fn parse_subscription_publication_list(input: &str) -> Result<(Vec<String>, &str), ParseError> {
    let with_idx = find_next_top_level_keyword(input, &["with"]).unwrap_or(input.len());
    let names_sql = input[..with_idx].trim();
    if names_sql.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "publication name",
            actual: subscription_syntax_error_token(&input[with_idx..]),
        });
    }
    let publications = split_top_level_items(names_sql, ',')?
        .into_iter()
        .map(|item| {
            let (name, trailing) = parse_unqualified_identifier(&item, "publication name")?;
            if !trailing.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "publication name",
                    actual: item,
                });
            }
            Ok(name)
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok((publications, &input[with_idx..]))
}

fn parse_optional_subscription_with_options(
    rest: &str,
) -> Result<(Vec<SubscriptionOption>, &str), ParseError> {
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "with") {
        return Ok((Vec::new(), rest));
    }
    parse_subscription_options_clause(consume_keyword(rest, "with").trim_start())
}

fn parse_subscription_options_clause(
    input: &str,
) -> Result<(Vec<SubscriptionOption>, &str), ParseError> {
    let (segment, rest) = take_parenthesized_segment(input)?;
    let mut options = Vec::new();
    let mut seen = BTreeSet::new();
    for item in split_top_level_items(&segment, ',')? {
        if item.trim().is_empty() {
            continue;
        }
        let (name, trailing) = parse_sql_identifier(&item)?;
        let normalized_name = name.to_ascii_lowercase();
        if !seen.insert(normalized_name.clone()) {
            return Err(ParseError::ConflictingOrRedundantOptions {
                option: normalized_name,
            });
        }
        let trailing = trailing.trim_start();
        let value = if let Some(value) = trailing.strip_prefix('=') {
            let (value, trailing) = parse_subscription_option_value(value)?;
            if !trailing.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "subscription option value",
                    actual: trailing.trim().into(),
                });
            }
            Some(value)
        } else {
            if !trailing.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "subscription option",
                    actual: item,
                });
            }
            None
        };
        options.push(SubscriptionOption {
            name: normalized_name,
            value,
        });
    }
    Ok((options, rest))
}

fn parse_subscription_option_value(
    input: &str,
) -> Result<(SubscriptionOptionValue, &str), ParseError> {
    let input = input.trim_start();
    if let Some(token_len) = scan_string_literal_token_len(input) {
        return Ok((
            SubscriptionOptionValue::String(decode_string_literal(&input[..token_len])?),
            &input[token_len..],
        ));
    }
    let (value, rest) = parse_sql_identifier(input)?;
    Ok((SubscriptionOptionValue::Identifier(value), rest))
}

fn subscription_syntax_error_token(rest: &str) -> String {
    let rest = rest.trim_start();
    if rest.is_empty() {
        return "syntax error at or near \";\"".into();
    }
    format!(
        "syntax error at or near \"{}\"",
        leading_identifier_token(rest)
    )
}

fn build_comment_on_constraint_statement(
    sql: &str,
) -> Result<CommentOnConstraintStatement, ParseError> {
    let rest = sql
        .get("comment on constraint".len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let (constraint_name, mut rest) = parse_unqualified_identifier(rest, "constraint name")?;
    rest = rest.trim_start();
    if !keyword_at_start(rest, "on") {
        return Err(ParseError::UnexpectedToken {
            expected: "ON table_name",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "on").trim_start();
    let (table_name, domain_name, mut rest) = if keyword_at_start(rest, "domain") {
        rest = consume_keyword(rest, "domain").trim_start();
        let (parts, parsed_rest) = parse_qualified_identifier_parts(rest)?;
        let domain_name = match parts.as_slice() {
            [name] => name.clone(),
            [schema, name] => format!("{schema}.{name}"),
            _ => return Err(ParseError::UnsupportedQualifiedName(parts.join("."))),
        };
        (String::new(), Some(domain_name), parsed_rest)
    } else {
        let (parts, parsed_rest) = parse_qualified_identifier_parts(rest)?;
        let table_name = match parts.as_slice() {
            [name] => name.clone(),
            [schema, name] => format!("{schema}.{name}"),
            _ => return Err(ParseError::UnsupportedQualifiedName(parts.join("."))),
        };
        (table_name, None, parsed_rest)
    };
    rest = rest.trim_start();
    if !keyword_at_start(rest, "is") {
        return Err(ParseError::UnexpectedToken {
            expected: "IS string literal or NULL",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "is").trim_start();
    let (comment, rest) = if keyword_at_start(rest, "null") {
        (None, consume_keyword(rest, "null"))
    } else {
        let token_len = scan_string_literal_token_len(rest).ok_or(ParseError::UnexpectedToken {
            expected: "comment string literal or NULL",
            actual: rest.into(),
        })?;
        (
            Some(decode_string_literal(&rest[..token_len])?),
            &rest[token_len..],
        )
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of COMMENT ON CONSTRAINT",
            actual: rest.trim().into(),
        });
    }
    Ok(CommentOnConstraintStatement {
        constraint_name,
        table_name,
        domain_name,
        comment,
    })
}

fn parse_create_publication_target(
    input: &str,
) -> Result<(PublicationTargetSpec, &str), ParseError> {
    if let Some(target) = parse_publication_all_target_spec(input)? {
        return Ok(target);
    }
    parse_publication_target_spec(input)
}

fn parse_alter_publication_set_target(
    input: &str,
) -> Result<(PublicationTargetSpec, &str), ParseError> {
    if let Some(target) = parse_publication_all_target_spec(input)? {
        return Ok(target);
    }
    parse_publication_target_spec(input)
}

fn parse_publication_all_target_spec(
    input: &str,
) -> Result<Option<(PublicationTargetSpec, &str)>, ParseError> {
    let mut rest = input.trim_start();
    let mut for_all_tables = false;
    let mut for_all_sequences = false;
    let mut except_tables = Vec::new();
    let mut parsed_any = false;

    loop {
        if let Some(next) = consume_keywords(rest, &["all", "tables"]) {
            if for_all_tables {
                return Err(duplicate_publication_all_target_error("ALL TABLES"));
            }
            for_all_tables = true;
            parsed_any = true;
            let (tables, next) = parse_publication_except_clause(next)?;
            except_tables = tables;
            rest = next.trim_start();
        } else if let Some(next) = consume_keywords(rest, &["all", "sequences"]) {
            if for_all_sequences {
                return Err(duplicate_publication_all_target_error("ALL SEQUENCES"));
            }
            for_all_sequences = true;
            parsed_any = true;
            rest = next.trim_start();
        } else if parsed_any {
            return Err(ParseError::UnexpectedToken {
                expected: "ALL TABLES or ALL SEQUENCES",
                actual: rest.into(),
            });
        } else {
            return Ok(None);
        }

        let Some(after_comma) = rest.strip_prefix(',') else {
            break;
        };
        rest = after_comma.trim_start();
    }

    Ok(Some((
        PublicationTargetSpec {
            for_all_tables,
            for_all_sequences,
            except_tables,
            objects: Vec::new(),
        },
        rest,
    )))
}

fn parse_publication_except_clause(
    input: &str,
) -> Result<(Vec<PublicationTableSpec>, &str), ParseError> {
    let rest = input.trim_start();
    if !keyword_at_start(rest, "except") {
        return Ok((Vec::new(), input));
    }

    let rest = consume_keyword(rest, "except").trim_start();
    let (segment, rest) = take_parenthesized_segment(rest)?;
    if !keyword_at_start(&segment, "table") {
        return Err(publication_missing_object_kind_error());
    }
    let (target, trailing) = parse_publication_target_spec(&segment)?;
    if !trailing.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of publication EXCEPT list",
            actual: trailing.trim().into(),
        });
    }
    if target.objects.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "TABLE ...",
            actual: segment,
        });
    }
    let except_tables = target
        .objects
        .into_iter()
        .map(|object| match object {
            PublicationObjectSpec::Table(table) => {
                if !table.column_names.is_empty() || table.where_clause.is_some() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "publication EXCEPT table name",
                        actual: table.relation_name,
                    });
                }
                Ok(table)
            }
            PublicationObjectSpec::Schema(_) => Err(ParseError::UnexpectedToken {
                expected: "TABLE ...",
                actual: segment.clone(),
            }),
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok((except_tables, rest))
}

fn duplicate_publication_all_target_error(target: &'static str) -> ParseError {
    ParseError::DetailedError {
        message: "invalid publication object list".into(),
        detail: Some(format!("{target} can be specified only once.")),
        hint: None,
        sqlstate: "42601",
    }
}

fn publication_missing_object_kind_error() -> ParseError {
    ParseError::DetailedError {
        message: "invalid publication object list".into(),
        detail: Some(
            "One of TABLE or TABLES IN SCHEMA must be specified before a standalone table or schema name."
                .into(),
        ),
        hint: None,
        sqlstate: "42601",
    }
}

fn parse_publication_target_spec(input: &str) -> Result<(PublicationTargetSpec, &str), ParseError> {
    #[derive(Clone, Copy)]
    enum PublicationObjectMode {
        Table { explicit: bool },
        Schema,
    }

    let mut rest = input.trim_start();
    let mut mode = if let Some(next) = consume_keywords(rest, &["table"]) {
        rest = next;
        PublicationObjectMode::Table { explicit: true }
    } else if let Some(next) = consume_keywords(rest, &["tables", "in", "schema"]) {
        rest = next;
        PublicationObjectMode::Schema
    } else {
        return Err(publication_missing_object_kind_error());
    };

    let mut objects = Vec::new();
    loop {
        let (object, next) = match mode {
            PublicationObjectMode::Table { explicit } => {
                let (table, next) = parse_publication_table_object(rest, explicit)?;
                (PublicationObjectSpec::Table(table), next)
            }
            PublicationObjectMode::Schema => {
                let (schema, next) = parse_publication_schema_object(rest, !objects.is_empty())?;
                (PublicationObjectSpec::Schema(schema), next)
            }
        };
        objects.push(object);
        rest = next.trim_start();
        let Some(after_comma) = rest.strip_prefix(',') else {
            break;
        };
        rest = after_comma.trim_start();
        if let Some(next) = consume_keywords(rest, &["table"]) {
            rest = next;
            mode = PublicationObjectMode::Table { explicit: true };
            continue;
        }
        if let Some(next) = consume_keywords(rest, &["tables", "in", "schema"]) {
            rest = next;
            mode = PublicationObjectMode::Schema;
            continue;
        }
        if matches!(mode, PublicationObjectMode::Table { .. }) {
            mode = PublicationObjectMode::Table { explicit: false };
        }
    }

    if objects.len() > 1
        && objects.iter().any(|object| {
            matches!(
                object,
                PublicationObjectSpec::Table(PublicationTableSpec { relation_name, .. })
                    if relation_name == "current_schema"
            )
        })
    {
        return Err(ParseError::InvalidPublicationTableName(
            "current_schema".into(),
        ));
    }

    Ok((
        PublicationTargetSpec {
            for_all_tables: false,
            for_all_sequences: false,
            except_tables: Vec::new(),
            objects,
        },
        rest,
    ))
}

fn parse_publication_table_object(
    input: &str,
    explicit_table_keyword: bool,
) -> Result<(PublicationTableSpec, &str), ParseError> {
    let mut rest = input.trim_start();
    let mut only = false;
    if keyword_at_start(rest, "only") {
        only = true;
        rest = consume_keyword(rest, "only").trim_start();
    }
    if explicit_table_keyword && keyword_at_start(rest, "current_schema") {
        return Err(ParseError::UnexpectedToken {
            expected: "publication table name",
            actual: format!(
                "syntax error at or near \"{}\"",
                leading_identifier_token(rest)
            ),
        });
    }
    let (parts, mut rest) = parse_qualified_identifier_parts(rest)?;
    let relation_name = match parts.as_slice() {
        [name] => name.clone(),
        [schema, name] => format!("{schema}.{name}"),
        _ => return Err(ParseError::UnsupportedQualifiedName(parts.join("."))),
    };

    let mut column_names = Vec::new();
    let mut where_clause = None;
    if rest.trim_start().starts_with('(') {
        let (segment, next) = take_parenthesized_segment(rest)?;
        column_names = parse_publication_identifier_list(&segment)?;
        rest = next;
    }
    if keyword_at_start(rest, "where") {
        let after_where = consume_keyword(rest.trim_start(), "where").trim_start();
        let (segment, next) = take_parenthesized_segment(after_where)?;
        where_clause = Some(segment.trim().to_string());
        rest = next;
    }

    Ok((
        PublicationTableSpec {
            relation_name,
            only,
            column_names,
            where_clause,
        },
        rest,
    ))
}

fn parse_publication_schema_object(
    input: &str,
    has_prior_schema: bool,
) -> Result<(PublicationSchemaSpec, &str), ParseError> {
    let rest = input.trim_start();
    let (schema_name, rest) = if keyword_at_start(rest, "current_schema") {
        (
            PublicationSchemaName::CurrentSchema,
            consume_keyword(rest, "current_schema"),
        )
    } else {
        let (parts, rest) = parse_qualified_identifier_parts(rest)?;
        match parts.as_slice() {
            [name] => (PublicationSchemaName::Name(name.clone()), rest),
            _ => {
                return Err(ParseError::InvalidPublicationSchemaName(parts.join(".")));
            }
        }
    };
    let trailing = rest.trim_start();
    if trailing.starts_with('(') {
        if has_prior_schema {
            return Err(ParseError::DetailedError {
                message: "column specification not allowed for schema".into(),
                detail: None,
                hint: None,
                sqlstate: "42601",
            });
        }
        return Err(ParseError::UnexpectedToken {
            expected: "schema name",
            actual: "syntax error at or near \"(\"".into(),
        });
    }
    if keyword_at_start(trailing, "where") {
        if !has_prior_schema {
            return Err(ParseError::UnexpectedToken {
                expected: "schema name",
                actual: "syntax error at or near \"WHERE\"".into(),
            });
        }
        return Err(ParseError::DetailedError {
            message: "WHERE clause not allowed for schema".into(),
            detail: None,
            hint: None,
            sqlstate: "42601",
        });
    }
    Ok((PublicationSchemaSpec { schema_name }, rest))
}

fn parse_publication_options_clause(input: &str) -> Result<(PublicationOptions, &str), ParseError> {
    let (segment, rest) = take_parenthesized_segment(input)?;
    let mut options = Vec::new();
    let mut seen = BTreeSet::new();
    for item in split_top_level_items(&segment, ',')? {
        if item.trim().is_empty() {
            continue;
        }
        let (name, trailing) = parse_sql_identifier(&item)?;
        let normalized_name = name.to_ascii_lowercase();
        if !seen.insert(normalized_name.clone()) {
            return Err(ParseError::ConflictingOrRedundantOptions {
                option: normalized_name,
            });
        }
        let trailing = trailing.trim_start();
        let value = trailing
            .strip_prefix('=')
            .map(str::trim_start)
            .unwrap_or_default();
        let option = match normalized_name.as_str() {
            "publish" => {
                let (actions, trailing) = parse_publication_publish_actions(value)?;
                if !trailing.trim().is_empty() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "publish action list",
                        actual: trailing.trim().into(),
                    });
                }
                PublicationOption::Publish(actions)
            }
            "publish_via_partition_root" => {
                let (value, trailing) = parse_publication_bool_value(value)?;
                if !trailing.trim().is_empty() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "boolean publication option value",
                        actual: trailing.trim().into(),
                    });
                }
                PublicationOption::PublishViaPartitionRoot(value)
            }
            "publish_generated_columns" => {
                let (value, trailing) = parse_publication_generated_columns_value(value)?;
                if !trailing.trim().is_empty() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "publish_generated_columns value",
                        actual: trailing.trim().into(),
                    });
                }
                PublicationOption::PublishGeneratedColumns(value)
            }
            _ => return Err(ParseError::UnrecognizedPublicationParameter(name)),
        };
        options.push(option);
    }
    Ok((PublicationOptions { options }, rest))
}

fn parse_publication_publish_actions(
    input: &str,
) -> Result<(PublicationPublishActions, &str), ParseError> {
    let (text, rest) = parse_publication_option_text_value(input)?;
    let mut actions = PublicationPublishActions {
        insert: false,
        update: false,
        delete: false,
        truncate: false,
    };
    for item in text
        .split(',')
        .map(str::trim)
        .filter(|item| !item.is_empty())
    {
        match item.to_ascii_lowercase().as_str() {
            "insert" => actions.insert = true,
            "update" => actions.update = true,
            "delete" => actions.delete = true,
            "truncate" => actions.truncate = true,
            other => {
                return Err(ParseError::UnrecognizedPublicationOptionValue {
                    option: "publish".into(),
                    value: other.into(),
                });
            }
        }
    }
    Ok((actions, rest))
}

fn parse_publication_generated_columns_value(
    input: &str,
) -> Result<(PublishGeneratedColumns, &str), ParseError> {
    let (value, rest) = parse_publication_option_text_value(input)?;
    let value = match value.to_ascii_lowercase().as_str() {
        "none" => PublishGeneratedColumns::None,
        "stored" => PublishGeneratedColumns::Stored,
        _ => {
            return Err(ParseError::InvalidPublicationParameterValue {
                parameter: "publish_generated_columns".into(),
                value,
            });
        }
    };
    Ok((value, rest))
}

fn parse_publication_option_text_value(input: &str) -> Result<(String, &str), ParseError> {
    let input = input.trim_start();
    if input.is_empty() {
        return Ok((String::new(), input));
    }
    if let Some(token_len) = scan_string_literal_token_len(input) {
        return Ok((
            decode_string_literal(&input[..token_len])?,
            &input[token_len..],
        ));
    }
    let (value, rest) = parse_sql_identifier(input)?;
    Ok((value, rest))
}

fn leading_identifier_token(input: &str) -> &str {
    let input = input.trim_start();
    let end = input
        .char_indices()
        .find_map(|(index, ch)| {
            (index > 0 && !(ch.is_ascii_alphanumeric() || ch == '_')).then_some(index)
        })
        .unwrap_or(input.len());
    &input[..end]
}

fn parse_publication_bool_value(input: &str) -> Result<(bool, &str), ParseError> {
    let input = input.trim_start();
    if let Some(token_len) = scan_string_literal_token_len(input) {
        let value = decode_string_literal(&input[..token_len])?;
        let parsed = match value.to_ascii_lowercase().as_str() {
            "true" | "on" | "yes" | "1" => true,
            "false" | "off" | "no" | "0" => false,
            _ => {
                return Err(ParseError::UnexpectedToken {
                    expected: "boolean option value",
                    actual: value,
                });
            }
        };
        return Ok((parsed, &input[token_len..]));
    }
    if let Some(rest) = input.strip_prefix('1') {
        if rest
            .chars()
            .next()
            .is_none_or(|ch| !(ch.is_ascii_alphanumeric() || ch == '_'))
        {
            return Ok((true, rest));
        }
    }
    if let Some(rest) = input.strip_prefix('0') {
        if rest
            .chars()
            .next()
            .is_none_or(|ch| !(ch.is_ascii_alphanumeric() || ch == '_'))
        {
            return Ok((false, rest));
        }
    }
    let (value, rest) = parse_sql_identifier(input)?;
    let parsed = match value.as_str() {
        "true" | "on" | "yes" => true,
        "false" | "off" | "no" => false,
        _ => {
            return Err(ParseError::UnexpectedToken {
                expected: "boolean option value",
                actual: value,
            });
        }
    };
    Ok((parsed, rest))
}

fn parse_publication_identifier_list(input: &str) -> Result<Vec<String>, ParseError> {
    split_top_level_items(input, ',')?
        .into_iter()
        .map(|item| {
            let (name, rest) = parse_unqualified_identifier(&item, "identifier")?;
            if !rest.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "identifier",
                    actual: item,
                });
            }
            Ok(name)
        })
        .collect()
}

fn build_create_tablespace_statement(sql: &str) -> Result<CreateTablespaceStatement, ParseError> {
    let prefix = "create tablespace";
    let rest = sql
        .get(prefix.len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let (tablespace_name, rest) = parse_sql_identifier(rest)?;
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "location") {
        return Err(ParseError::UnexpectedToken {
            expected: "LOCATION string literal",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "location").trim_start();
    let token_len = scan_string_literal_token_len(rest).ok_or(ParseError::UnexpectedToken {
        expected: "tablespace location string literal",
        actual: rest.into(),
    })?;
    let location = decode_string_literal(&rest[..token_len])?;
    let trailing = rest[token_len..].trim();
    if !trailing.is_empty() {
        return Err(ParseError::FeatureNotSupported(format!(
            "unsupported CREATE TABLESPACE clause: {}",
            trailing.split_whitespace().next().unwrap_or(trailing)
        )));
    }
    Ok(CreateTablespaceStatement {
        tablespace_name,
        location,
    })
}

pub fn parse_expr(sql: &str) -> Result<SqlExpr, ParseError> {
    run_with_parser_stack(effective_default_max_stack_depth_kb(), {
        let sql = sql.to_string();
        move || {
            let sql = strip_sql_comments_preserving_layout(&sql);
            validate_numeric_lexemes(&sql)?;
            pgrust_sql_grammar::parse_rule(Rule::expr, &sql)
                .map_err(|e| map_pest_error("expression", &sql, e))
                .and_then(|mut pairs| {
                    let pair = pairs.next().ok_or(ParseError::UnexpectedEof)?;
                    if pairs.next().is_some() {
                        return Err(ParseError::UnexpectedToken {
                            expected: "expression",
                            actual: sql.clone(),
                        });
                    }
                    build_expr(pair)
                })
        }
    })
}

pub fn parse_type_name(sql: &str) -> Result<RawTypeName, ParseError> {
    let sql = strip_sql_comments_preserving_layout(sql);
    let trimmed = sql.trim();
    let lowered = trimmed.to_ascii_lowercase();
    if lowered.ends_with("%type") || lowered.ends_with("%rowtype") {
        return Ok(RawTypeName::Named {
            name: trimmed.to_string(),
            array_bounds: 0,
        });
    }
    match lowered.as_str() {
        "int2vector" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Int2Vector))),
        "oidvector" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::OidVector))),
        "name" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Name))),
        "any" | "pg_catalog.any" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::AnyElement)
                    .with_identity(crate::include::catalog::ANYOID, 0),
            ));
        }
        "anyenum" | "pg_catalog.anyenum" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::AnyElement)
                    .with_identity(crate::include::catalog::ANYENUMOID, 0),
            ));
        }
        "anynonarray" | "pg_catalog.anynonarray" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::AnyElement)
                    .with_identity(crate::include::catalog::ANYNONARRAYOID, 0),
            ));
        }
        "anycompatiblenonarray" | "pg_catalog.anycompatiblenonarray" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::AnyCompatible)
                    .with_identity(crate::include::catalog::ANYCOMPATIBLENONARRAYOID, 0),
            ));
        }
        "refcursor" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::Text)
                    .with_identity(crate::include::catalog::REFCURSOR_TYPE_OID, 0),
            ));
        }
        "inet" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Inet))),
        "cidr" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Cidr))),
        "uuid" | "pg_catalog.uuid" => {
            return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Uuid)));
        }
        "macaddr" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::MacAddr))),
        "macaddr8" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::MacAddr8))),
        "xid8" | "pg_catalog.xid8" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::Int8)
                    .with_identity(crate::include::catalog::XID8_TYPE_OID, 0),
            ));
        }
        "_macaddr" => {
            return Ok(RawTypeName::Builtin(SqlType::array_of(SqlType::new(
                SqlTypeKind::MacAddr,
            ))));
        }
        "_macaddr8" => {
            return Ok(RawTypeName::Builtin(SqlType::array_of(SqlType::new(
                SqlTypeKind::MacAddr8,
            ))));
        }
        "bpchar" | "pg_catalog.bpchar" => {
            return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Char)));
        }
        "character" | "pg_catalog.character" => {
            return Ok(RawTypeName::Builtin(SqlType::with_char_len(
                SqlTypeKind::Char,
                1,
            )));
        }
        "pg_node_tree" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::PgNodeTree))),
        "unknown" | "pg_catalog.unknown" => {
            return Ok(RawTypeName::Named {
                name: "unknown".to_string(),
                array_bounds: 0,
            });
        }
        "trigger" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Trigger))),
        "event_trigger" => {
            return Ok(RawTypeName::Builtin(SqlType::new(
                SqlTypeKind::EventTrigger,
            )));
        }
        "void" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Void))),
        "cstring" | "pg_catalog.cstring" => {
            return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::Cstring)));
        }
        "fdw_handler" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::FdwHandler))),
        "index_am_handler" | "pg_catalog.index_am_handler" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::FdwHandler)
                    .with_identity(crate::include::catalog::INDEX_AM_HANDLER_TYPE_OID, 0),
            ));
        }
        "table_am_handler" | "pg_catalog.table_am_handler" => {
            return Ok(RawTypeName::Builtin(
                SqlType::new(SqlTypeKind::FdwHandler)
                    .with_identity(crate::include::catalog::TABLE_AM_HANDLER_TYPE_OID, 0),
            ));
        }
        "regrole" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::RegRole))),
        "regproc" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::RegProc))),
        "regprocedure" => {
            return Ok(RawTypeName::Builtin(SqlType::new(
                SqlTypeKind::RegProcedure,
            )));
        }
        "regoper" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::RegOper))),
        "regoperator" => {
            return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::RegOperator)));
        }
        "regcollation" => {
            return Ok(RawTypeName::Builtin(SqlType::new(
                SqlTypeKind::RegCollation,
            )));
        }
        "pg_lsn" => return Ok(RawTypeName::Builtin(SqlType::new(SqlTypeKind::PgLsn))),
        _ => {}
    }
    pgrust_sql_grammar::parse_rule(Rule::type_name, &sql)
        .map_err(|e| map_pest_error("type name", &sql, e))
        .and_then(|mut pairs| {
            let pair = pairs.next().ok_or(ParseError::UnexpectedEof)?;
            if pairs.next().is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "type name",
                    actual: sql.clone(),
                });
            }
            Ok(build_type_name(pair))
        })
}

#[cfg(not(target_arch = "wasm32"))]
fn run_with_parser_stack<F, T>(max_stack_depth_kb: u32, f: F) -> T
where
    F: FnOnce() -> T + Send + 'static,
    T: Send + 'static,
{
    // :HACK: The current pest AST builders can use more debug stack than
    // PostgreSQL's default max_stack_depth while lowering ordinary statements.
    // Keep executor/runtime checks tied to the GUC, but give parser-only work a
    // floor until those recursive builders are flattened.
    let max_stack_depth_kb = max_stack_depth_kb.max(PARSER_STACK_DEPTH_FLOOR_KB);
    let (result, notices) = std::thread::Builder::new()
        .name("pgrust-parser".into())
        .stack_size(PARSER_THREAD_STACK_BYTES)
        .spawn(move || {
            let result = StackDepthGuard::enter(max_stack_depth_kb).run(f);
            let notices = crate::backend::utils::misc::notices::take_notices();
            (result, notices)
        })
        .expect("spawn parser thread")
        .join()
        .expect("parser thread panicked");
    for notice in notices {
        crate::backend::utils::misc::notices::push_backend_notice(
            notice.severity,
            notice.sqlstate,
            notice.message,
            notice.detail,
            notice.position,
        );
    }
    result
}

#[cfg(target_arch = "wasm32")]
fn run_with_parser_stack<F, T>(max_stack_depth_kb: u32, f: F) -> T
where
    F: FnOnce() -> T,
{
    let max_stack_depth_kb = max_stack_depth_kb.max(PARSER_STACK_DEPTH_FLOOR_KB);
    // Browser wasm cannot spawn threads without a different runtime model.
    // Run inline there and keep the larger parser stack workaround only on
    // native targets.
    StackDepthGuard::enter(max_stack_depth_kb).run(f)
}

fn try_parse_copy_to_statement(
    sql: &str,
    parse_options: ParseOptions,
) -> Result<Option<Statement>, ParseError> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    if !keyword_at_start(trimmed, "copy") {
        return Ok(None);
    }

    let mut rest = consume_keyword(trimmed, "copy").trim_start();
    let mut options = CopyToOptions::default();
    let mut explicit_format = false;
    let mut explicit_delimiter = false;
    let mut explicit_null = false;
    let mut explicit_quote = false;
    let mut explicit_escape = false;
    if keyword_at_start(rest, "binary") {
        set_copy_format(
            &mut options,
            &mut explicit_format,
            CopyFormat::Binary,
            &CopyOptionExplicit {
                delimiter: explicit_delimiter,
                null: explicit_null,
                quote: explicit_quote,
                escape: explicit_escape,
            },
        )?;
        rest = consume_keyword(rest.trim_start(), "binary").trim_start();
    }

    if rest.starts_with('(') {
        let (query_sql, after_query) = take_parenthesized_segment(rest)?;
        rest = after_query.trim_start();
        if keyword_at_start(rest, "from") {
            return Err(ParseError::UnexpectedToken {
                expected: "TO",
                actual: "syntax error at or near \"from\"".into(),
            });
        }
        if rest.starts_with('(') {
            return Err(ParseError::UnexpectedToken {
                expected: "TO",
                actual: "syntax error at or near \"(\"".into(),
            });
        }
        rest = consume_keywords(rest, &["to"]).ok_or_else(|| ParseError::UnexpectedToken {
            expected: "TO",
            actual: rest.into(),
        })?;
        let (destination, option_rest) = parse_copy_to_destination(rest)?;
        parse_copy_to_options(
            option_rest,
            &mut options,
            &mut explicit_format,
            &mut explicit_delimiter,
            &mut explicit_null,
            &mut explicit_quote,
            &mut explicit_escape,
        )?;
        validate_copy_to_options(
            &options,
            &CopyOptionExplicit {
                delimiter: explicit_delimiter,
                null: explicit_null,
                quote: explicit_quote,
                escape: explicit_escape,
            },
        )?;
        let statement = parse_statement_with_options_inner(query_sql.clone(), parse_options)?;
        return Ok(Some(Statement::CopyTo(CopyToStatement {
            source: CopyToSource::Query {
                statement: Box::new(statement),
                sql: query_sql,
            },
            destination,
            options,
        })));
    }

    let (parts, mut rest) = parse_qualified_identifier_parts(rest)?;
    let table_name = parts.join(".");
    let mut columns = None;
    rest = rest.trim_start();
    if rest.starts_with('(') {
        let (columns_sql, after_columns) = take_parenthesized_segment(rest)?;
        let parsed_columns = split_top_level_items(&columns_sql, ',')?
            .into_iter()
            .map(|item| {
                let (name, rest) = parse_unqualified_identifier(&item, "column name")?;
                if !rest.trim().is_empty() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "column name",
                        actual: rest.trim().into(),
                    });
                }
                Ok(name)
            })
            .collect::<Result<Vec<_>, ParseError>>()?;
        if parsed_columns.is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "column name",
                actual: columns_sql,
            });
        }
        columns = Some(parsed_columns);
        rest = after_columns.trim_start();
    }

    if keyword_at_start(rest, "from") {
        return Ok(None);
    }

    rest = consume_keywords(rest, &["to"]).ok_or_else(|| ParseError::UnexpectedToken {
        expected: "TO",
        actual: rest.into(),
    })?;
    let (destination, option_rest) = parse_copy_to_destination(rest)?;
    parse_copy_to_options(
        option_rest,
        &mut options,
        &mut explicit_format,
        &mut explicit_delimiter,
        &mut explicit_null,
        &mut explicit_quote,
        &mut explicit_escape,
    )?;
    validate_copy_to_options(
        &options,
        &CopyOptionExplicit {
            delimiter: explicit_delimiter,
            null: explicit_null,
            quote: explicit_quote,
            escape: explicit_escape,
        },
    )?;
    Ok(Some(Statement::CopyTo(CopyToStatement {
        source: CopyToSource::Relation {
            table_name,
            columns,
        },
        destination,
        options,
    })))
}

#[derive(Clone, Copy)]
struct CopyOptionExplicit {
    delimiter: bool,
    null: bool,
    quote: bool,
    escape: bool,
}

fn parse_copy_to_destination(input: &str) -> Result<(CopyToDestination, &str), ParseError> {
    let input = input.trim_start();
    if keyword_at_start(input, "program") {
        let rest = consume_keyword(input, "program").trim_start();
        let (program, rest) = parse_copy_string_literal(rest)?;
        return Ok((CopyToDestination::Program(program), rest));
    }
    if keyword_at_start(input, "stdout") {
        return Ok((
            CopyToDestination::Stdout,
            consume_keyword(input, "stdout").trim_start(),
        ));
    }
    let (path, rest) = parse_copy_string_literal(input)?;
    Ok((CopyToDestination::File(path), rest))
}

fn parse_copy_string_literal(input: &str) -> Result<(String, &str), ParseError> {
    let input = input.trim_start();
    let token_len =
        scan_string_literal_token_len(input).ok_or_else(|| ParseError::UnexpectedToken {
            expected: "string literal",
            actual: input.into(),
        })?;
    Ok((
        decode_string_literal(&input[..token_len])?,
        &input[token_len..],
    ))
}

fn parse_copy_to_options(
    input: &str,
    options: &mut CopyToOptions,
    explicit_format: &mut bool,
    explicit_delimiter: &mut bool,
    explicit_null: &mut bool,
    explicit_quote: &mut bool,
    explicit_escape: &mut bool,
) -> Result<(), ParseError> {
    let mut rest = input.trim_start();
    if rest.is_empty() {
        return Ok(());
    }
    if keyword_at_start(rest, "with") {
        rest = consume_keyword(rest, "with").trim_start();
        if rest.starts_with('(') {
            let (body, after) = take_parenthesized_segment(rest)?;
            if !after.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "end of COPY options",
                    actual: after.trim().into(),
                });
            }
            return parse_copy_to_modern_options(
                &body,
                options,
                explicit_format,
                explicit_delimiter,
                explicit_null,
                explicit_quote,
                explicit_escape,
            );
        }
    }

    parse_copy_to_legacy_options(
        rest,
        options,
        explicit_format,
        explicit_delimiter,
        explicit_null,
        explicit_quote,
        explicit_escape,
    )
}

fn parse_copy_to_modern_options(
    body: &str,
    options: &mut CopyToOptions,
    explicit_format: &mut bool,
    explicit_delimiter: &mut bool,
    explicit_null: &mut bool,
    explicit_quote: &mut bool,
    explicit_escape: &mut bool,
) -> Result<(), ParseError> {
    let mut seen = BTreeSet::new();
    for item in split_top_level_items(body, ',')? {
        if item.is_empty() {
            continue;
        }
        let (name, value) = split_copy_option_assignment(&item)?;
        let key = name.to_ascii_lowercase();
        if !seen.insert(key.clone()) {
            return Err(ParseError::ConflictingOrRedundantOptions { option: key });
        }
        match key.as_str() {
            "format" => {
                let value = value.ok_or_else(|| ParseError::UnexpectedToken {
                    expected: "COPY FORMAT value",
                    actual: item.clone(),
                })?;
                let format = parse_copy_format_value(&value)?;
                set_copy_format(
                    options,
                    explicit_format,
                    format,
                    &CopyOptionExplicit {
                        delimiter: *explicit_delimiter,
                        null: *explicit_null,
                        quote: *explicit_quote,
                        escape: *explicit_escape,
                    },
                )?;
            }
            "encoding" => {
                options.encoding = Some(parse_copy_option_string_value(value.as_deref(), &item)?);
            }
            "delimiter" => {
                options.delimiter = parse_copy_option_string_value(value.as_deref(), &item)?;
                *explicit_delimiter = true;
            }
            "null" => {
                options.null = parse_copy_option_string_value(value.as_deref(), &item)?;
                *explicit_null = true;
            }
            "header" => {
                options.header = match value.as_deref() {
                    None => true,
                    Some(value) => parse_copy_option_bool(value)?,
                };
            }
            "quote" => {
                options.quote = parse_copy_option_string_value(value.as_deref(), &item)?;
                *explicit_quote = true;
            }
            "escape" => {
                options.escape = parse_copy_option_string_value(value.as_deref(), &item)?;
                *explicit_escape = true;
            }
            "force_quote" | "force quote" => {
                options.force_quote = parse_copy_force_quote_value(value.as_deref(), &item)?;
            }
            other => {
                return Err(ParseError::UnexpectedToken {
                    expected: "COPY option",
                    actual: other.into(),
                });
            }
        }
    }
    Ok(())
}

fn split_copy_option_assignment(item: &str) -> Result<(String, Option<String>), ParseError> {
    let trimmed = item.trim();
    if let Some((name, value)) = trimmed.split_once('=') {
        return Ok((name.trim().to_string(), Some(value.trim().to_string())));
    }
    if keyword_at_start(trimmed, "force") {
        let rest = consume_keyword(trimmed, "force").trim_start();
        if keyword_at_start(rest, "quote") {
            let rest = consume_keyword(rest, "quote").trim_start();
            return Ok((
                "force_quote".into(),
                (!rest.is_empty()).then(|| rest.to_string()),
            ));
        }
    }
    let (name, rest) = parse_sql_identifier(trimmed)?;
    let rest = rest.trim_start();
    Ok((name, (!rest.is_empty()).then(|| rest.to_string())))
}

fn parse_copy_to_legacy_options(
    input: &str,
    options: &mut CopyToOptions,
    explicit_format: &mut bool,
    explicit_delimiter: &mut bool,
    explicit_null: &mut bool,
    explicit_quote: &mut bool,
    explicit_escape: &mut bool,
) -> Result<(), ParseError> {
    let mut rest = input.trim_start();
    let mut seen = BTreeSet::new();
    while !rest.is_empty() {
        if keyword_at_start(rest, "binary") {
            set_legacy_copy_option_seen(&mut seen, "format")?;
            set_copy_format(
                options,
                explicit_format,
                CopyFormat::Binary,
                &CopyOptionExplicit {
                    delimiter: *explicit_delimiter,
                    null: *explicit_null,
                    quote: *explicit_quote,
                    escape: *explicit_escape,
                },
            )?;
            rest = consume_keyword(rest, "binary").trim_start();
        } else if keyword_at_start(rest, "csv") {
            set_legacy_copy_option_seen(&mut seen, "format")?;
            set_copy_format(
                options,
                explicit_format,
                CopyFormat::Csv,
                &CopyOptionExplicit {
                    delimiter: *explicit_delimiter,
                    null: *explicit_null,
                    quote: *explicit_quote,
                    escape: *explicit_escape,
                },
            )?;
            rest = consume_keyword(rest, "csv").trim_start();
        } else if keyword_at_start(rest, "header") {
            set_legacy_copy_option_seen(&mut seen, "header")?;
            options.header = true;
            rest = consume_keyword(rest, "header").trim_start();
        } else if keyword_at_start(rest, "delimiter") {
            set_legacy_copy_option_seen(&mut seen, "delimiter")?;
            rest = consume_keyword(rest, "delimiter").trim_start();
            if keyword_at_start(rest, "as") {
                rest = consume_keyword(rest, "as").trim_start();
            }
            let (value, after) = parse_copy_string_literal(rest)?;
            options.delimiter = value;
            *explicit_delimiter = true;
            rest = after.trim_start();
        } else if keyword_at_start(rest, "null") {
            set_legacy_copy_option_seen(&mut seen, "null")?;
            rest = consume_keyword(rest, "null").trim_start();
            if keyword_at_start(rest, "as") {
                rest = consume_keyword(rest, "as").trim_start();
            }
            let (value, after) = parse_copy_string_literal(rest)?;
            options.null = value;
            *explicit_null = true;
            rest = after.trim_start();
        } else if keyword_at_start(rest, "quote") {
            set_legacy_copy_option_seen(&mut seen, "quote")?;
            rest = consume_keyword(rest, "quote").trim_start();
            if keyword_at_start(rest, "as") {
                rest = consume_keyword(rest, "as").trim_start();
            }
            let (value, after) = parse_copy_string_literal(rest)?;
            options.quote = value;
            *explicit_quote = true;
            rest = after.trim_start();
        } else if keyword_at_start(rest, "escape") {
            set_legacy_copy_option_seen(&mut seen, "escape")?;
            rest = consume_keyword(rest, "escape").trim_start();
            if keyword_at_start(rest, "as") {
                rest = consume_keyword(rest, "as").trim_start();
            }
            let (value, after) = parse_copy_string_literal(rest)?;
            options.escape = value;
            *explicit_escape = true;
            rest = after.trim_start();
        } else if keyword_at_start(rest, "force") {
            set_legacy_copy_option_seen(&mut seen, "force_quote")?;
            rest = consume_keyword(rest, "force").trim_start();
            rest =
                consume_keywords(rest, &["quote"]).ok_or_else(|| ParseError::UnexpectedToken {
                    expected: "QUOTE",
                    actual: rest.into(),
                })?;
            let (force_quote, after) = parse_legacy_force_quote(rest)?;
            options.force_quote = force_quote;
            rest = after.trim_start();
        } else {
            return Err(ParseError::UnexpectedToken {
                expected: "COPY option",
                actual: rest.into(),
            });
        }
    }
    Ok(())
}

fn set_legacy_copy_option_seen(
    seen: &mut BTreeSet<&'static str>,
    option: &'static str,
) -> Result<(), ParseError> {
    if !seen.insert(option) {
        return Err(ParseError::ConflictingOrRedundantOptions {
            option: option.into(),
        });
    }
    Ok(())
}

fn parse_copy_format_value(value: &str) -> Result<CopyFormat, ParseError> {
    let value = parse_copy_bare_or_string_value(value)?;
    match value.to_ascii_lowercase().as_str() {
        "text" => Ok(CopyFormat::Text),
        "csv" => Ok(CopyFormat::Csv),
        "binary" => Ok(CopyFormat::Binary),
        _ => Err(ParseError::UnexpectedToken {
            expected: "text, csv, or binary",
            actual: value,
        }),
    }
}

fn parse_copy_option_bool(value: &str) -> Result<bool, ParseError> {
    match parse_copy_bare_or_string_value(value)?
        .to_ascii_lowercase()
        .as_str()
    {
        "true" | "on" | "1" => Ok(true),
        "false" | "off" | "0" => Ok(false),
        _ => Err(ParseError::UnexpectedToken {
            expected: "boolean COPY option",
            actual: value.into(),
        }),
    }
}

fn parse_copy_option_string_value(value: Option<&str>, item: &str) -> Result<String, ParseError> {
    let value = value.ok_or_else(|| ParseError::UnexpectedToken {
        expected: "COPY option value",
        actual: item.into(),
    })?;
    parse_copy_bare_or_string_value(value)
}

fn parse_copy_bare_or_string_value(value: &str) -> Result<String, ParseError> {
    let value = value.trim();
    if let Some(token_len) = scan_string_literal_token_len(value) {
        if !value[token_len..].trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "COPY option value",
                actual: value.into(),
            });
        }
        return decode_string_literal(&value[..token_len]);
    }
    Ok(value.to_string())
}

fn parse_copy_force_quote_value(
    value: Option<&str>,
    item: &str,
) -> Result<CopyForceQuote, ParseError> {
    let value = value.ok_or_else(|| ParseError::UnexpectedToken {
        expected: "FORCE_QUOTE value",
        actual: item.into(),
    })?;
    let (force_quote, rest) = parse_legacy_force_quote(value)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "FORCE_QUOTE value",
            actual: rest.trim().into(),
        });
    }
    Ok(force_quote)
}

fn parse_legacy_force_quote(input: &str) -> Result<(CopyForceQuote, &str), ParseError> {
    let rest = input.trim_start();
    if let Some(after_star) = rest.strip_prefix('*') {
        return Ok((CopyForceQuote::All, after_star));
    }
    if rest.starts_with('(') {
        let (columns_sql, after) = take_parenthesized_segment(rest)?;
        let columns = parse_copy_force_quote_columns(&columns_sql)?;
        return Ok((CopyForceQuote::Columns(columns), after));
    }
    let mut columns = Vec::new();
    let mut remaining = rest;
    loop {
        let (name, after) = parse_unqualified_identifier(remaining, "FORCE QUOTE column")?;
        columns.push(name);
        let after = after.trim_start();
        if let Some(next) = after.strip_prefix(',') {
            remaining = next.trim_start();
            continue;
        }
        return Ok((CopyForceQuote::Columns(columns), after));
    }
}

fn parse_copy_force_quote_columns(input: &str) -> Result<Vec<String>, ParseError> {
    let columns = split_top_level_items(input, ',')?
        .into_iter()
        .map(|item| {
            let (name, rest) = parse_unqualified_identifier(&item, "FORCE QUOTE column")?;
            if !rest.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "FORCE QUOTE column",
                    actual: rest.trim().into(),
                });
            }
            Ok(name)
        })
        .collect::<Result<Vec<_>, ParseError>>()?;
    if columns.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "FORCE QUOTE column",
            actual: input.into(),
        });
    }
    Ok(columns)
}

fn set_copy_format(
    options: &mut CopyToOptions,
    explicit_format: &mut bool,
    format: CopyFormat,
    explicit: &CopyOptionExplicit,
) -> Result<(), ParseError> {
    if *explicit_format {
        return Err(ParseError::ConflictingOrRedundantOptions {
            option: "format".into(),
        });
    }
    *explicit_format = true;
    options.format = format;
    if matches!(format, CopyFormat::Csv) {
        if !explicit.delimiter {
            options.delimiter = ",".into();
        }
        if !explicit.null {
            options.null.clear();
        }
        if !explicit.quote {
            options.quote = "\"".into();
        }
        if !explicit.escape {
            options.escape = "\"".into();
        }
    }
    Ok(())
}

fn validate_copy_to_options(
    options: &CopyToOptions,
    explicit: &CopyOptionExplicit,
) -> Result<(), ParseError> {
    validate_copy_single_char_option("DELIMITER", &options.delimiter)?;
    validate_copy_single_char_option("QUOTE", &options.quote)?;
    validate_copy_single_char_option("ESCAPE", &options.escape)?;
    if options.delimiter == "\n" || options.delimiter == "\r" {
        return Err(ParseError::UnexpectedToken {
            expected: "valid COPY delimiter",
            actual: "COPY delimiter cannot be newline or carriage return".into(),
        });
    }
    if matches!(options.format, CopyFormat::Binary) {
        if explicit.delimiter
            || explicit.null
            || explicit.quote
            || explicit.escape
            || options.header
            || !matches!(options.force_quote, CopyForceQuote::None)
        {
            return Err(ParseError::UnexpectedToken {
                expected: "binary COPY options",
                actual: "COPY text or CSV options cannot be used with BINARY".into(),
            });
        }
    }
    if !matches!(options.format, CopyFormat::Csv) {
        if options.header || !matches!(options.force_quote, CopyForceQuote::None) {
            return Err(ParseError::UnexpectedToken {
                expected: "CSV COPY options",
                actual: "COPY HEADER/FORCE_QUOTE only available using CSV mode".into(),
            });
        }
    }
    Ok(())
}

fn validate_copy_single_char_option(name: &'static str, value: &str) -> Result<(), ParseError> {
    if value.len() == 1 {
        Ok(())
    } else {
        Err(ParseError::UnexpectedToken {
            expected: name,
            actual: format!("{name} must be a single one-byte character"),
        })
    }
}

fn try_parse_unsupported_statement(sql: &str) -> Option<Statement> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    let lowered = trimmed.to_ascii_lowercase();

    let feature = if lowered.starts_with("alter table ") {
        Some("ALTER TABLE form")
    } else if lowered.starts_with("alter index ") {
        Some("ALTER INDEX")
    } else if lowered.starts_with("alter view ") {
        Some("ALTER VIEW")
    } else if lowered.starts_with("drop index ") {
        Some("DROP INDEX")
    } else if lowered.starts_with("drop table ") {
        Some("DROP TABLE form")
    } else if lowered.starts_with("drop domain ") {
        Some("DROP DOMAIN")
    } else if lowered.starts_with("comment on column ") {
        Some("COMMENT ON COLUMN")
    } else if lowered.starts_with("comment on constraint ") {
        Some("COMMENT ON CONSTRAINT")
    } else if lowered.starts_with("comment on index ") {
        Some("COMMENT ON INDEX")
    } else if lowered.starts_with("create domain ") {
        Some("CREATE DOMAIN")
    } else if lowered.starts_with("create unique index ") {
        Some("CREATE UNIQUE INDEX")
    } else if lowered.starts_with("create index ") {
        Some("CREATE INDEX form")
    } else if lowered.starts_with("create view ") {
        Some("CREATE VIEW form")
    } else if lowered.starts_with("create temp table ") {
        Some("CREATE TEMP TABLE form")
    } else if lowered.starts_with("select ") || lowered.starts_with("with ") {
        Some("SELECT form")
    } else if lowered.starts_with("delete from ") {
        Some("DELETE form")
    } else if lowered.starts_with("alter default privileges ") {
        Some("ALTER DEFAULT PRIVILEGES")
    } else if lowered.starts_with("create transform ") {
        Some("CREATE TRANSFORM")
    } else if lowered.starts_with("create subscription ") {
        Some("CREATE SUBSCRIPTION")
    } else if lowered.starts_with("drop subscription ") {
        Some("DROP SUBSCRIPTION")
    } else if lowered.starts_with("prepare ") {
        Some("PREPARE")
    } else if lowered.starts_with("execute ") {
        Some("EXECUTE")
    } else {
        None
    }?;

    Some(Statement::Unsupported(UnsupportedStatement {
        sql: trimmed.into(),
        feature,
    }))
}

fn try_parse_index_statement(sql: &str) -> Result<Option<Statement>, ParseError> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    let lowered = trimmed.to_ascii_lowercase();
    if !lowered.starts_with("alter index ") {
        return Ok(None);
    }
    if lowered.contains(" rename to ") {
        return build_alter_index_rename_statement(trimmed)
            .map(|stmt| Some(Statement::AlterIndexRename(stmt)));
    }
    if lowered.contains(" attach partition ") {
        return build_alter_index_attach_partition_statement(trimmed)
            .map(|stmt| Some(Statement::AlterIndexAttachPartition(stmt)));
    }
    if lowered.contains(" alter column ")
        && (lowered.contains(" set (") || lowered.contains(" reset ("))
    {
        return build_alter_index_alter_column_options_statement(trimmed)
            .map(|stmt| Some(Statement::AlterIndexAlterColumnOptions(stmt)));
    }
    if lowered.contains(" set statistics ") {
        return build_alter_index_alter_column_statistics_statement(trimmed)
            .map(|stmt| Some(Statement::AlterIndexAlterColumnStatistics(stmt)));
    }
    if lowered.contains(" set ") {
        return build_alter_index_set_statement(trimmed)
            .map(|stmt| Some(Statement::AlterIndexSet(stmt)));
    }
    Ok(None)
}

fn try_parse_reindex_statement(sql: &str) -> Result<Option<Statement>, ParseError> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    let lowered = trimmed.to_ascii_lowercase();
    if !lowered.starts_with("reindex ") {
        return Ok(None);
    }

    let mut rest = consume_keyword(trimmed, "reindex").trim_start();
    let mut verbose = false;
    let mut concurrently = false;
    if rest.starts_with('(') {
        let close = rest.find(')').ok_or_else(|| ParseError::UnexpectedToken {
            expected: "REINDEX option list",
            actual: rest.to_string(),
        })?;
        let options = &rest[1..close];
        for option in options.split(',') {
            let option = option.trim();
            if option.eq_ignore_ascii_case("verbose") {
                verbose = true;
            } else if option.eq_ignore_ascii_case("concurrently") {
                concurrently = true;
            } else {
                return Err(ParseError::UnexpectedToken {
                    expected: "REINDEX option",
                    actual: option.to_string(),
                });
            }
        }
        rest = rest[close + 1..].trim_start();
    }
    if keyword_at_start(rest, "concurrently") {
        rest = consume_keyword(rest, "concurrently").trim_start();
        concurrently = true;
    }
    let kind = if keyword_at_start(rest, "index") {
        rest = consume_keyword(rest, "index").trim_start();
        ReindexTargetKind::Index
    } else if keyword_at_start(rest, "table") {
        rest = consume_keyword(rest, "table").trim_start();
        ReindexTargetKind::Table
    } else if keyword_at_start(rest, "schema") {
        rest = consume_keyword(rest, "schema").trim_start();
        ReindexTargetKind::Schema
    } else if keyword_at_start(rest, "database") {
        rest = consume_keyword(rest, "database").trim_start();
        ReindexTargetKind::Database
    } else if keyword_at_start(rest, "system") {
        rest = consume_keyword(rest, "system").trim_start();
        ReindexTargetKind::System
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "REINDEX target",
            actual: rest.to_string(),
        });
    };
    if keyword_at_start(rest, "concurrently") {
        rest = consume_keyword(rest, "concurrently").trim_start();
        concurrently = true;
    }
    let (index_name, tail) = if rest.trim().is_empty()
        && matches!(
            kind,
            ReindexTargetKind::Database | ReindexTargetKind::System
        ) {
        (String::new(), "")
    } else {
        let (parts, tail) = parse_qualified_identifier_parts(rest)?;
        (parts.join("."), tail)
    };
    let tail = tail.trim();
    if !tail.is_empty() && !tail.eq_ignore_ascii_case("force") {
        return Err(ParseError::UnexpectedToken {
            expected: "end of REINDEX statement",
            actual: tail.to_string(),
        });
    }
    Ok(Some(Statement::ReindexIndex(ReindexIndexStatement {
        concurrently,
        verbose,
        kind,
        index_name,
    })))
}

