fn find_matching_create_foreign_table_columns_end(input: &str) -> Option<usize> {
    let bytes = input.as_bytes();
    if bytes.first().copied()? != b'(' {
        return None;
    }
    let mut depth = 0usize;
    let mut i = 0usize;
    while i < bytes.len() {
        match bytes[i] {
            b'\'' => {
                i = parse_delimited_token_end(bytes, i, b'\'');
                continue;
            }
            b'"' => {
                i = parse_delimited_token_end(bytes, i, b'"');
                continue;
            }
            b'$' => {
                if let Some(end) = scan_dollar_string_token_end(input, i) {
                    i = end;
                    continue;
                }
            }
            b'(' => depth = depth.saturating_add(1),
            b')' => {
                depth = depth.saturating_sub(1);
                if depth == 0 {
                    return Some(i);
                }
            }
            _ => {}
        }
        i += 1;
    }
    None
}

fn strip_create_foreign_table_column_options(
    columns_sql: &str,
) -> Result<(String, Vec<(String, Vec<RelOption>)>), ParseError> {
    let Some(inner) = columns_sql
        .trim()
        .strip_prefix('(')
        .and_then(|value| value.strip_suffix(')'))
    else {
        return Ok((columns_sql.to_string(), Vec::new()));
    };
    let mut cleaned_items = Vec::new();
    let mut column_options = Vec::new();
    for item in split_top_level_items(inner, ',')? {
        let trimmed = item.trim();
        let Some(options_idx) = find_top_level_keyword(trimmed, "options") else {
            cleaned_items.push(item);
            continue;
        };
        let (column_name, _) = parse_sql_identifier(trimmed)?;
        let options_tail = trimmed[options_idx + "options".len()..].trim_start();
        let options_end = find_matching_create_foreign_table_columns_end(options_tail).ok_or(
            ParseError::UnexpectedToken {
                expected: "OPTIONS (name 'value' [, ...])",
                actual: options_tail.into(),
            },
        )?;
        let options_sql = format!("options {}", &options_tail[..=options_end]);
        let options = parse_create_generic_options(&options_sql)?;
        column_options.push((column_name, options));

        let before = trimmed[..options_idx].trim_end();
        let after = options_tail[options_end + 1..].trim_start();
        cleaned_items.push(if after.is_empty() {
            before.to_string()
        } else {
            format!("{before} {after}")
        });
    }
    Ok((format!("({})", cleaned_items.join(", ")), column_options))
}

fn build_create_foreign_table_statement(
    sql: &str,
) -> Result<CreateForeignTableStatement, ParseError> {
    let mut rest = sql["create foreign table ".len()..].trim_start();
    let if_not_exists = if keyword_at_start(rest, "if not exists") {
        rest = consume_keyword(rest, "if not exists").trim_start();
        true
    } else {
        false
    };
    let ((schema_name, table_name), next) = parse_qualified_sql_name(rest)?;
    rest = next.trim_start();
    let columns_end = find_matching_create_foreign_table_columns_end(rest).ok_or(
        ParseError::UnexpectedToken {
            expected: "foreign table column definitions",
            actual: rest.into(),
        },
    )?;
    let columns_sql = &rest[..=columns_end];
    let (columns_sql, column_options) = strip_create_foreign_table_column_options(columns_sql)?;
    rest = rest[columns_end + 1..].trim_start();
    if !keyword_at_start(rest, "server") {
        return Err(ParseError::UnexpectedToken {
            expected: "SERVER",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "server").trim_start();
    let (server_name, tail) = parse_sql_identifier(rest)?;
    let tail = tail.trim_start();
    let options = if tail.is_empty() {
        Vec::new()
    } else if keyword_at_start(tail, "options") {
        parse_create_generic_options(tail)?
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "OPTIONS or end of statement",
            actual: tail.into(),
        });
    };

    let qualified_name = schema_name
        .as_ref()
        .map(|schema| format!("{schema}.{table_name}"))
        .unwrap_or_else(|| table_name.clone());
    let create_table_sql = if if_not_exists {
        format!("create table if not exists {qualified_name} {columns_sql}")
    } else {
        format!("create table {qualified_name} {columns_sql}")
    };
    let mut create_table = match parse_statement(&create_table_sql)? {
        Statement::CreateTable(stmt) => stmt,
        _ => unreachable!("CREATE TABLE parser must produce CreateTable"),
    };
    create_table.schema_name = schema_name;
    create_table.table_name = table_name;
    Ok(CreateForeignTableStatement {
        create_table,
        server_name,
        options,
        column_options,
    })
}

fn build_import_foreign_schema_statement(
    sql: &str,
) -> Result<ImportForeignSchemaStatement, ParseError> {
    let prefix = "import foreign schema ";
    let rest = sql
        .get(prefix.len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let (schema_and_restriction, after_from) = split_once_keyword(rest, "from server")?;
    let (server_name, after_into) = split_once_keyword(after_from, "into")?;
    let (local_schema, options_tail) =
        split_optional_keyword(after_into, "options").unwrap_or((after_into.trim(), None));
    let options = options_tail
        .map(|tail| parse_create_generic_options(&format!("options {tail}")))
        .transpose()?
        .unwrap_or_default();
    let (remote_schema, restriction) =
        parse_import_foreign_schema_restriction(schema_and_restriction)?;
    Ok(ImportForeignSchemaStatement {
        remote_schema,
        restriction,
        server_name: normalize_simple_identifier(server_name)?,
        local_schema: normalize_simple_identifier(local_schema)?,
        options,
    })
}

fn parse_import_foreign_schema_restriction(
    input: &str,
) -> Result<(String, ImportForeignSchemaRestriction), ParseError> {
    let (remote_schema, tail) = parse_sql_identifier(input.trim())?;
    let tail = tail.trim();
    if tail.is_empty() {
        return Ok((remote_schema, ImportForeignSchemaRestriction::All));
    }
    if keyword_at_start(tail, "limit") {
        let rest = consume_keyword(tail, "limit").trim_start();
        if !keyword_at_start(rest, "to") {
            return Err(ParseError::UnexpectedToken {
                expected: "TO",
                actual: rest.into(),
            });
        }
        let list = parse_parenthesized_identifier_list(consume_keyword(rest, "to").trim_start())?;
        return Ok((remote_schema, ImportForeignSchemaRestriction::LimitTo(list)));
    }
    if keyword_at_start(tail, "except") {
        let list =
            parse_parenthesized_identifier_list(consume_keyword(tail, "except").trim_start())?;
        return Ok((remote_schema, ImportForeignSchemaRestriction::Except(list)));
    }
    Err(ParseError::UnexpectedToken {
        expected: "IMPORT FOREIGN SCHEMA restriction",
        actual: tail.into(),
    })
}

fn parse_parenthesized_identifier_list(input: &str) -> Result<Vec<String>, ParseError> {
    let trimmed = input.trim();
    let Some(inner) = trimmed
        .strip_prefix('(')
        .and_then(|value| value.strip_suffix(')'))
    else {
        return Err(ParseError::UnexpectedToken {
            expected: "parenthesized identifier list",
            actual: input.into(),
        });
    };
    parse_identifier_list(inner)
}

fn build_create_foreign_data_wrapper_statement(
    sql: &str,
) -> Result<CreateForeignDataWrapperStatement, ParseError> {
    let mut rest = sql["create foreign data wrapper ".len()..].trim_start();
    let (fdw_name, next) = parse_sql_identifier(rest)?;
    rest = next.trim_start();
    let mut handler_name = None;
    let mut validator_name = None;
    let mut saw_handler = false;
    let mut saw_validator = false;
    while !rest.is_empty() && !keyword_at_start(rest, "options") {
        if keyword_at_start(rest, "handler") {
            if saw_handler {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            let next = consume_keyword(rest, "handler").trim_start();
            let (name, tail) = parse_sql_identifier(next)?;
            handler_name = Some(name);
            saw_handler = true;
            rest = tail.trim_start();
            continue;
        }
        if keyword_at_start(rest, "no handler") {
            if saw_handler {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            handler_name = None;
            saw_handler = true;
            rest = consume_keyword(rest, "no handler").trim_start();
            continue;
        }
        if keyword_at_start(rest, "validator") {
            if saw_validator {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            let next = consume_keyword(rest, "validator").trim_start();
            let (name, tail) = parse_sql_identifier(next)?;
            validator_name = Some(name);
            saw_validator = true;
            rest = tail.trim_start();
            continue;
        }
        if keyword_at_start(rest, "no validator") {
            if saw_validator {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            validator_name = None;
            saw_validator = true;
            rest = consume_keyword(rest, "no validator").trim_start();
            continue;
        }
        return Err(ParseError::UnexpectedToken {
            expected: "HANDLER, NO HANDLER, VALIDATOR, NO VALIDATOR, OPTIONS, or end of statement",
            actual: rest.into(),
        });
    }
    let options = if rest.is_empty() {
        Vec::new()
    } else {
        parse_create_generic_options(rest)?
    };
    Ok(CreateForeignDataWrapperStatement {
        fdw_name,
        handler_name,
        validator_name,
        options,
    })
}

fn build_alter_foreign_data_wrapper_statement(sql: &str) -> Result<Option<Statement>, ParseError> {
    let mut rest = sql["alter foreign data wrapper ".len()..].trim_start();
    let (fdw_name, next) = parse_sql_identifier(rest)?;
    rest = next.trim_start();
    if keyword_at_start(rest, "owner to") {
        let next = consume_keyword(rest, "owner to").trim_start();
        let (new_owner, tail) = parse_sql_identifier(next)?;
        if !tail.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: tail.trim().into(),
            });
        }
        return Ok(Some(Statement::AlterForeignDataWrapperOwner(
            AlterForeignDataWrapperOwnerStatement {
                fdw_name,
                new_owner,
            },
        )));
    }
    if keyword_at_start(rest, "rename to") {
        let next = consume_keyword(rest, "rename to").trim_start();
        let (new_name, tail) = parse_sql_identifier(next)?;
        if !tail.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: tail.trim().into(),
            });
        }
        return Ok(Some(Statement::AlterForeignDataWrapperRename(
            AlterForeignDataWrapperRenameStatement { fdw_name, new_name },
        )));
    }

    let mut handler_name = None;
    let mut validator_name = None;
    let mut saw_handler = false;
    let mut saw_validator = false;
    while !rest.is_empty() && !keyword_at_start(rest, "options") {
        if keyword_at_start(rest, "handler") {
            if saw_handler {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            let next = consume_keyword(rest, "handler").trim_start();
            let (name, tail) = parse_sql_identifier(next)?;
            handler_name = Some(Some(name));
            saw_handler = true;
            rest = tail.trim_start();
            continue;
        }
        if keyword_at_start(rest, "no handler") {
            if saw_handler {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            handler_name = Some(None);
            saw_handler = true;
            rest = consume_keyword(rest, "no handler").trim_start();
            continue;
        }
        if keyword_at_start(rest, "validator") {
            if saw_validator {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            let next = consume_keyword(rest, "validator").trim_start();
            let (name, tail) = parse_sql_identifier(next)?;
            validator_name = Some(Some(name));
            saw_validator = true;
            rest = tail.trim_start();
            continue;
        }
        if keyword_at_start(rest, "no validator") {
            if saw_validator {
                return Err(ParseError::FeatureNotSupportedMessage(
                    "conflicting or redundant options".into(),
                ));
            }
            validator_name = Some(None);
            saw_validator = true;
            rest = consume_keyword(rest, "no validator").trim_start();
            continue;
        }
        break;
    }
    let options = if rest.is_empty() {
        if handler_name.is_none() && validator_name.is_none() {
            return Err(syntax_error_at_statement_end(sql));
        }
        Vec::new()
    } else {
        parse_alter_generic_options(rest)?
    };
    Ok(Some(Statement::AlterForeignDataWrapper(
        AlterForeignDataWrapperStatement {
            fdw_name,
            handler_name,
            validator_name,
            options,
        },
    )))
}

fn build_drop_foreign_data_wrapper_statement(
    sql: &str,
) -> Result<DropForeignDataWrapperStatement, ParseError> {
    let tokens = sql.split_whitespace().collect::<Vec<_>>();
    let mut index = 4usize;
    let mut if_exists = false;
    if tokens
        .get(index)
        .is_some_and(|token| token.eq_ignore_ascii_case("if"))
    {
        if !tokens
            .get(index + 1)
            .is_some_and(|token| token.eq_ignore_ascii_case("exists"))
        {
            return Err(ParseError::UnexpectedToken {
                expected: "EXISTS",
                actual: tokens.get(index + 1).unwrap_or(&"").to_string(),
            });
        }
        if_exists = true;
        index += 2;
    }
    let Some(fdw_name) = tokens.get(index) else {
        return Err(ParseError::UnexpectedToken {
            expected: "foreign-data wrapper name",
            actual: sql.into(),
        });
    };
    let cascade = tokens
        .get(index + 1)
        .is_some_and(|token| token.eq_ignore_ascii_case("cascade"));
    if tokens.len() > index + 1 && !cascade && !tokens[index + 1].eq_ignore_ascii_case("restrict") {
        return Err(ParseError::UnexpectedToken {
            expected: "CASCADE, RESTRICT, or end of statement",
            actual: tokens[index + 1].into(),
        });
    }
    if tokens.len() > index + 2 {
        return Err(ParseError::UnexpectedToken {
            expected: "end of statement",
            actual: sql.into(),
        });
    }
    Ok(DropForeignDataWrapperStatement {
        if_exists,
        fdw_name: (*fdw_name).to_string(),
        cascade,
    })
}

fn build_comment_on_foreign_data_wrapper_statement(
    sql: &str,
) -> Result<CommentOnForeignDataWrapperStatement, ParseError> {
    let lower = sql.to_ascii_lowercase();
    let Some(is_offset) = lower.find(" is ") else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON FOREIGN DATA WRAPPER name IS ...",
            actual: sql.into(),
        });
    };
    let object = sql["comment on foreign data wrapper ".len()..is_offset].trim();
    let value = sql[is_offset + 4..].trim();
    let comment = if value.eq_ignore_ascii_case("null") {
        None
    } else if value.starts_with('\'') && value.ends_with('\'') && value.len() >= 2 {
        Some(value[1..value.len() - 1].replace("''", "'"))
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "quoted string or NULL",
            actual: value.into(),
        });
    };
    Ok(CommentOnForeignDataWrapperStatement {
        fdw_name: object.to_string(),
        comment,
    })
}

