fn language_usage_prefix<'a>(
    sql: &'a str,
    command: &'static str,
) -> Result<(&'a str, GrantObjectPrivilege), ParseError> {
    let lower = sql.to_ascii_lowercase();
    for (prefix, privilege) in [
        (
            format!("{command} usage on language "),
            GrantObjectPrivilege::UsageOnLanguage,
        ),
        (
            format!("{command} all on language "),
            GrantObjectPrivilege::AllPrivilegesOnLanguage,
        ),
        (
            format!("{command} all privileges on language "),
            GrantObjectPrivilege::AllPrivilegesOnLanguage,
        ),
    ] {
        if lower.starts_with(&prefix) {
            return Ok((
                sql.get(prefix.len()..)
                    .ok_or(ParseError::UnexpectedEof)?
                    .trim_start(),
                privilege,
            ));
        }
    }
    Err(ParseError::UnexpectedToken {
        expected: "language privilege",
        actual: sql.into(),
    })
}

fn revoke_foreign_usage_prefix<'a>(
    sql: &'a str,
    object: &'static str,
) -> Result<(&'a str, GrantObjectPrivilege), ParseError> {
    let lower = sql.to_ascii_lowercase();
    for (prefix, privilege) in [
        (
            format!("revoke usage on {object} "),
            if object == "foreign data wrapper" {
                GrantObjectPrivilege::UsageOnForeignDataWrapper
            } else {
                GrantObjectPrivilege::UsageOnForeignServer
            },
        ),
        (
            format!("revoke all on {object} "),
            if object == "foreign data wrapper" {
                GrantObjectPrivilege::AllPrivilegesOnForeignDataWrapper
            } else {
                GrantObjectPrivilege::AllPrivilegesOnForeignServer
            },
        ),
        (
            format!("revoke all privileges on {object} "),
            if object == "foreign data wrapper" {
                GrantObjectPrivilege::AllPrivilegesOnForeignDataWrapper
            } else {
                GrantObjectPrivilege::AllPrivilegesOnForeignServer
            },
        ),
    ] {
        if lower.starts_with(&prefix) {
            return Ok((
                sql.get(prefix.len()..)
                    .ok_or(ParseError::UnexpectedEof)?
                    .trim_start(),
                privilege,
            ));
        }
    }
    Err(ParseError::UnexpectedToken {
        expected: "REVOKE USAGE ON foreign object",
        actual: sql.into(),
    })
}

fn build_revoke_foreign_data_wrapper_usage(sql: &str) -> Result<RevokeObjectStatement, ParseError> {
    let (rest, privilege) = revoke_foreign_usage_prefix(sql, "foreign data wrapper")?;
    let (object_names, rest) = split_once_keyword(rest, "from")?;
    let (grantee_names, cascade) = parse_revokee_list_with_optional_cascade(rest)?;
    Ok(RevokeObjectStatement {
        privilege,
        columns: Vec::new(),
        object_names: parse_identifier_list(object_names)?,
        grantee_names,
        cascade,
    })
}

fn build_revoke_foreign_server_usage(sql: &str) -> Result<RevokeObjectStatement, ParseError> {
    let (rest, privilege) = revoke_foreign_usage_prefix(sql, "foreign server")?;
    let (object_names, rest) = split_once_keyword(rest, "from")?;
    let (grantee_names, cascade) = parse_revokee_list_with_optional_cascade(rest)?;
    Ok(RevokeObjectStatement {
        privilege,
        columns: Vec::new(),
        object_names: parse_identifier_list(object_names)?,
        grantee_names,
        cascade,
    })
}

fn build_revoke_function_execute(sql: &str) -> Result<RevokeObjectStatement, ParseError> {
    let rest = function_execute_prefix(sql, "revoke", "function")?;
    let (object_name, rest) = split_once_keyword(rest, "from")?;
    let (grantee_names, cascade) = parse_revokee_list_with_optional_cascade(rest)?;
    Ok(RevokeObjectStatement {
        privilege: GrantObjectPrivilege::ExecuteOnFunction,
        columns: Vec::new(),
        object_names: vec![object_name.trim().to_ascii_lowercase()],
        grantee_names,
        cascade,
    })
}

fn build_revoke_procedure_execute(sql: &str) -> Result<RevokeObjectStatement, ParseError> {
    build_revoke_routine_execute_with_object(
        sql,
        "procedure",
        GrantObjectPrivilege::ExecuteOnProcedure,
    )
}

fn build_revoke_routine_execute(sql: &str) -> Result<RevokeObjectStatement, ParseError> {
    build_revoke_routine_execute_with_object(sql, "routine", GrantObjectPrivilege::ExecuteOnRoutine)
}

fn build_revoke_routine_execute_with_object(
    sql: &str,
    object: &'static str,
    privilege: GrantObjectPrivilege,
) -> Result<RevokeObjectStatement, ParseError> {
    let rest = function_execute_prefix(sql, "revoke", object)?;
    let (object_name, rest) = split_once_keyword(rest.trim_start(), "from")?;
    let (grantee_names, cascade) = parse_revokee_list_with_optional_cascade(rest)?;
    Ok(RevokeObjectStatement {
        privilege,
        columns: Vec::new(),
        object_names: vec![object_name.trim().to_ascii_lowercase()],
        grantee_names,
        cascade,
    })
}

fn build_grant_role_membership(sql: &str) -> Result<GrantRoleMembershipStatement, ParseError> {
    let prefix = "grant ";
    let rest = sql
        .get(prefix.len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let (role_names, rest) = split_once_keyword(rest, "to")?;
    let (grant_body, granted_by_clause) =
        split_optional_keyword(rest, "granted by").unwrap_or((rest.trim(), None));
    let (grantee_names_text, with_clause) =
        split_optional_keyword(grant_body, "with").unwrap_or((grant_body.trim(), None));
    let mut stmt = GrantRoleMembershipStatement {
        role_names: parse_identifier_list(role_names)?,
        grantee_names: parse_identifier_list(grantee_names_text)?,
        admin_option: false,
        admin_option_specified: false,
        inherit_option: None,
        set_option: None,
        granted_by: granted_by_clause.map(parse_role_grantor_spec).transpose()?,
        legacy_group_syntax: false,
    };
    if let Some(with_clause) = with_clause {
        let lowered = with_clause.to_ascii_lowercase();
        if lowered == "admin option" {
            stmt.admin_option = true;
            stmt.admin_option_specified = true;
        } else {
            for option in with_clause.split(',') {
                let option = option.trim();
                let mut parts = option.split_whitespace();
                let name = parts.next().ok_or(ParseError::UnexpectedEof)?;
                let value = parts.next().ok_or(ParseError::UnexpectedEof)?;
                if parts.next().is_some() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "GRANT role option",
                        actual: option.into(),
                    });
                }
                match name.to_ascii_lowercase().as_str() {
                    "admin" => {
                        stmt.admin_option = parse_grant_bool(value)?;
                        stmt.admin_option_specified = true;
                    }
                    "inherit" => stmt.inherit_option = Some(parse_grant_bool(value)?),
                    "set" => stmt.set_option = Some(parse_grant_bool(value)?),
                    _ => {
                        return Err(ParseError::UnexpectedToken {
                            expected: "GRANT role option",
                            actual: option.into(),
                        });
                    }
                }
            }
        }
    }
    Ok(stmt)
}

fn build_revoke_role_membership(sql: &str) -> Result<RevokeRoleMembershipStatement, ParseError> {
    let prefix = "revoke ";
    let rest = sql
        .get(prefix.len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let (revoke_body, cascade) = split_optional_cascade_restrict_clause(rest)?;
    let (revoke_body, granted_by_clause) =
        split_optional_keyword(revoke_body, "granted by").unwrap_or((revoke_body.trim(), None));
    let (role_names, rest, revoke_membership, flags) =
        if let Some(stripped) = strip_keyword_prefix(revoke_body, "admin option for") {
            let (role_names, rest) = split_once_keyword(stripped, "from")?;
            (role_names, rest, false, (true, false, false))
        } else if let Some(stripped) = strip_keyword_prefix(revoke_body, "inherit option for") {
            let (role_names, rest) = split_once_keyword(stripped, "from")?;
            (role_names, rest, false, (false, true, false))
        } else if let Some(stripped) = strip_keyword_prefix(revoke_body, "set option for") {
            let (role_names, rest) = split_once_keyword(stripped, "from")?;
            (role_names, rest, false, (false, false, true))
        } else {
            let (role_names, rest) = split_once_keyword(revoke_body, "from")?;
            (role_names, rest, true, (false, false, false))
        };
    Ok(RevokeRoleMembershipStatement {
        role_names: parse_identifier_list(role_names)?,
        grantee_names: parse_identifier_list(rest)?,
        revoke_membership,
        admin_option: flags.0,
        inherit_option: flags.1,
        set_option: flags.2,
        cascade,
        granted_by: granted_by_clause.map(parse_role_grantor_spec).transpose()?,
        legacy_group_syntax: false,
    })
}

fn parse_role_grantor_spec(input: &str) -> Result<RoleGrantorSpec, ParseError> {
    let trimmed = input.trim();
    match trimmed.to_ascii_lowercase().as_str() {
        "current_user" => Ok(RoleGrantorSpec::CurrentUser),
        "current_role" => Ok(RoleGrantorSpec::CurrentRole),
        _ => Ok(RoleGrantorSpec::RoleName(normalize_simple_identifier(
            trimmed,
        )?)),
    }
}

fn split_optional_cascade_restrict_clause(input: &str) -> Result<(&str, bool), ParseError> {
    let boundary =
        find_next_top_level_keyword(input, &["cascade", "restrict"]).unwrap_or(input.len());
    let head = input[..boundary].trim_end();
    let tail = input[boundary..].trim();
    if tail.is_empty() {
        return Ok((head, false));
    }
    if tail.eq_ignore_ascii_case("cascade") {
        return Ok((head, true));
    }
    if tail.eq_ignore_ascii_case("restrict") {
        return Ok((head, false));
    }
    Err(ParseError::UnexpectedToken {
        expected: "CASCADE, RESTRICT, or end of statement",
        actual: tail.into(),
    })
}

fn split_once_keyword<'a>(input: &'a str, keyword: &str) -> Result<(&'a str, &'a str), ParseError> {
    let (left, right) =
        split_optional_keyword(input, keyword).ok_or_else(|| ParseError::UnexpectedToken {
            expected: "keyword-delimited clause",
            actual: input.into(),
        })?;
    right
        .map(|right| (left, right))
        .ok_or_else(|| ParseError::UnexpectedEof)
}

fn split_optional_keyword<'a>(input: &'a str, keyword: &str) -> Option<(&'a str, Option<&'a str>)> {
    let lowered = input.to_ascii_lowercase();
    let needle = format!(" {keyword} ");
    let index = lowered.find(&needle)?;
    let left = input[..index].trim();
    let right = input[index + needle.len()..].trim();
    Some((left, (!right.is_empty()).then_some(right)))
}

fn strip_keyword_prefix<'a>(input: &'a str, keyword: &str) -> Option<&'a str> {
    let lowered = input.to_ascii_lowercase();
    lowered
        .starts_with(keyword)
        .then(|| input[keyword.len()..].trim_start())
}

fn parse_grantees_with_optional_grant(input: &str) -> Result<(Vec<String>, bool), ParseError> {
    // :HACK: pgrust does not yet model object-GRANT grantor selection, but
    // PostgreSQL accepts GRANTED BY after the grantee list. Strip it so the
    // clause does not get mistaken for part of the grantee role name.
    let (input, _granted_by_clause) =
        split_optional_keyword(input, "granted by").unwrap_or((input.trim(), None));
    let (grantees, suffix) = split_optional_keyword(input, "with")
        .map(|(grantees, suffix)| (grantees, suffix.unwrap_or_default()))
        .unwrap_or((input.trim(), ""));
    let with_grant_option = if suffix.is_empty() {
        false
    } else if suffix.eq_ignore_ascii_case("grant option") {
        true
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "WITH GRANT OPTION",
            actual: suffix.into(),
        });
    };
    Ok((parse_grantee_identifier_list(grantees)?, with_grant_option))
}

fn parse_revokee_list_with_optional_cascade(
    input: &str,
) -> Result<(Vec<String>, bool), ParseError> {
    let (input, cascade) = split_optional_cascade_restrict_clause(input)?;
    // :HACK: see parse_grantees_with_optional_grant; object REVOKE grantor
    // selection is not represented yet, so only keep the revokee list.
    let (input, _granted_by_clause) =
        split_optional_keyword(input, "granted by").unwrap_or((input.trim(), None));
    Ok((parse_grantee_identifier_list(input)?, cascade))
}

fn parse_identifier_list(input: &str) -> Result<Vec<String>, ParseError> {
    input
        .split(',')
        .map(normalize_simple_identifier)
        .collect::<Result<Vec<_>, _>>()
}

fn parse_grantee_identifier_list(input: &str) -> Result<Vec<String>, ParseError> {
    input
        .split(',')
        .map(normalize_grantee_identifier)
        .collect::<Result<Vec<_>, _>>()
}

fn normalize_grantee_identifier(input: &str) -> Result<String, ParseError> {
    let trimmed = input.trim();
    if keyword_at_start(trimmed, "group") {
        normalize_simple_identifier(consume_keyword(trimmed, "group"))
    } else {
        normalize_simple_identifier(trimmed)
    }
}

fn normalize_simple_identifier(input: &str) -> Result<String, ParseError> {
    let trimmed = input.trim();
    if trimmed.is_empty() {
        return Err(ParseError::UnexpectedEof);
    }
    Ok(trimmed.trim_matches('"').to_ascii_lowercase())
}

fn parse_grant_bool(input: &str) -> Result<bool, ParseError> {
    match input.trim().to_ascii_lowercase().as_str() {
        "true" => Ok(true),
        "false" => Ok(false),
        other => Err(ParseError::UnexpectedToken {
            expected: "TRUE or FALSE",
            actual: other.into(),
        }),
    }
}
fn try_parse_sequence_statement(sql: &str) -> Result<Option<Statement>, ParseError> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    let lowered = trimmed.to_ascii_lowercase();
    if lowered.starts_with("create sequence ")
        || lowered.starts_with("create temp sequence ")
        || lowered.starts_with("create temporary sequence ")
        || lowered.starts_with("create unlogged sequence ")
    {
        return build_create_sequence_statement(trimmed)
            .map(|stmt| Some(Statement::CreateSequence(stmt)));
    }
    if !lowered.starts_with("alter sequence ") && !lowered.starts_with("drop sequence ") {
        return Ok(None);
    }
    if lowered.starts_with("drop sequence ") {
        return build_drop_sequence_statement(trimmed)
            .map(|stmt| Some(Statement::DropSequence(stmt)));
    }
    if lowered.contains(" owner to ") {
        return build_alter_sequence_owner_statement(trimmed)
            .map(|stmt| Some(Statement::AlterSequenceOwner(stmt)));
    }
    if lowered.contains(" rename to ") {
        return build_alter_sequence_rename_statement(trimmed)
            .map(|stmt| Some(Statement::AlterSequenceRename(stmt)));
    }
    build_alter_sequence_statement(trimmed).map(|stmt| Some(Statement::AlterSequence(stmt)))
}

fn try_parse_comment_on_sequence_statement(sql: &str) -> Result<Option<Statement>, ParseError> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    if !trimmed
        .to_ascii_lowercase()
        .starts_with("comment on sequence ")
    {
        return Ok(None);
    }
    let Some(rest) = trimmed.get("comment on sequence".len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON SEQUENCE name IS ...",
            actual: sql.into(),
        });
    };
    let Some(is_index) = find_top_level_keyword(rest, "is") else {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.trim().into(),
        });
    };
    let sequence_name = rest[..is_index].trim();
    if sequence_name.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "sequence name",
            actual: sql.into(),
        });
    }
    Ok(Some(Statement::CommentOnSequence(
        CommentOnSequenceStatement {
            sequence_name: sequence_name.to_string(),
            comment: parse_comment_value(&rest[is_index..], "end of COMMENT ON SEQUENCE")?,
        },
    )))
}

fn try_parse_alter_table_identity_statement(sql: &str) -> Result<Option<Statement>, ParseError> {
    let trimmed = sql.trim().trim_end_matches(';').trim();
    let lowered = trimmed.to_ascii_lowercase();
    if !lowered.starts_with("alter table ") {
        return Ok(None);
    }
    if ![
        " identity",
        " generated",
        " restart",
        " increment",
        " minvalue",
        " maxvalue",
        " cache",
        " cycle",
    ]
    .iter()
    .any(|marker| lowered.contains(marker))
    {
        return Ok(None);
    }

    let mut rest = consume_keyword(trimmed, "alter").trim_start();
    rest = consume_keyword(rest, "table").trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        let after_if = consume_keyword(rest, "if").trim_start();
        let after_not = consume_keyword(after_if, "not").trim_start();
        rest = consume_keyword(after_not, "exists").trim_start();
        if_exists = true;
    }
    let mut only = false;
    if keyword_at_start(rest, "only") {
        rest = consume_keyword(rest, "only").trim_start();
        only = true;
    }
    let (table_parts, mut rest) = parse_qualified_identifier_parts(rest)?;
    let table_name = table_parts.join(".");
    rest = rest.trim_start();
    if let Some(after_star) = rest.strip_prefix('*') {
        rest = after_star.trim_start();
    }
    if !keyword_at_start(rest, "alter") {
        return Ok(None);
    }
    rest = consume_keyword(rest, "alter").trim_start();
    if keyword_at_start(rest, "column") {
        rest = consume_keyword(rest, "column").trim_start();
    }
    let (column_name, rest) = parse_unqualified_identifier(rest, "ALTER TABLE column name")?;
    let rest = rest.trim_start();
    let Some(action) = parse_alter_column_identity_action(rest)? else {
        return Ok(None);
    };
    Ok(Some(Statement::AlterTableAlterColumnIdentity(
        AlterTableAlterColumnIdentityStatement {
            if_exists,
            only,
            table_name,
            column_name,
            action,
        },
    )))
}

fn parse_alter_column_identity_action(
    input: &str,
) -> Result<Option<AlterColumnIdentityAction>, ParseError> {
    let rest = input.trim_start();
    if keyword_at_start(rest, "add") {
        let mut rest = consume_keyword(rest, "add").trim_start();
        rest = consume_keyword(rest, "generated").trim_start();
        let (kind, next) = parse_identity_generation_kind(rest)?;
        rest = consume_keyword(next.trim_start(), "as").trim_start();
        rest = consume_keyword(rest, "identity").trim_start();
        let (options, rest) = parse_optional_parenthesized_sequence_options(rest)?;
        ensure_identity_action_consumed(rest)?;
        return Ok(Some(AlterColumnIdentityAction::Add(ColumnIdentityDef {
            kind,
            options,
        })));
    }
    if keyword_at_start(rest, "drop") {
        let mut rest = consume_keyword(rest, "drop").trim_start();
        rest = consume_keyword(rest, "identity").trim_start();
        let mut missing_ok = false;
        if keyword_at_start(rest, "if") {
            let after_if = consume_keyword(rest, "if").trim_start();
            rest = consume_keyword(after_if, "exists").trim_start();
            missing_ok = true;
        }
        ensure_identity_action_consumed(rest)?;
        return Ok(Some(AlterColumnIdentityAction::Drop { missing_ok }));
    }
    if keyword_at_start(rest, "set") {
        let after_set = consume_keyword(rest, "set").trim_start();
        if keyword_at_start(after_set, "generated") {
            let after_generated = consume_keyword(after_set, "generated").trim_start();
            let (kind, rest) = parse_identity_generation_kind(after_generated)?;
            let (options, rest) = parse_identity_sequence_option_patch(rest)?;
            ensure_identity_action_consumed(rest)?;
            return Ok(Some(AlterColumnIdentityAction::Set {
                generation: Some(kind),
                options,
            }));
        }
    }
    if starts_identity_sequence_option_patch(rest) {
        let (options, rest) = parse_identity_sequence_option_patch(rest)?;
        ensure_identity_action_consumed(rest)?;
        return Ok(Some(AlterColumnIdentityAction::Set {
            generation: None,
            options,
        }));
    }
    Ok(None)
}

fn starts_identity_sequence_option_patch(input: &str) -> bool {
    let trimmed = input.trim_start();
    if keyword_at_start(trimmed, "restart") {
        return true;
    }
    if !keyword_at_start(trimmed, "set") {
        return false;
    }
    let after_set = consume_keyword(trimmed, "set").trim_start();
    keyword_at_start(after_set, "increment")
        || keyword_at_start(after_set, "minvalue")
        || keyword_at_start(after_set, "no minvalue")
        || keyword_at_start(after_set, "maxvalue")
        || keyword_at_start(after_set, "no maxvalue")
        || keyword_at_start(after_set, "start")
        || keyword_at_start(after_set, "restart")
        || keyword_at_start(after_set, "cache")
        || keyword_at_start(after_set, "cycle")
        || keyword_at_start(after_set, "no cycle")
}

fn parse_identity_generation_kind(input: &str) -> Result<(ColumnIdentityKind, &str), ParseError> {
    let input = input.trim_start();
    if keyword_at_start(input, "always") {
        return Ok((
            ColumnIdentityKind::Always,
            consume_keyword(input, "always").trim_start(),
        ));
    }
    if keyword_at_start(input, "by") {
        let after_by = consume_keyword(input, "by").trim_start();
        if keyword_at_start(after_by, "default") {
            return Ok((
                ColumnIdentityKind::ByDefault,
                consume_keyword(after_by, "default").trim_start(),
            ));
        }
    }
    Err(ParseError::UnexpectedToken {
        expected: "ALWAYS or BY DEFAULT",
        actual: input.into(),
    })
}

fn parse_optional_parenthesized_sequence_options(
    input: &str,
) -> Result<(SequenceOptionsSpec, &str), ParseError> {
    let input = input.trim_start();
    let Some(after_open) = input.strip_prefix('(') else {
        return Ok((SequenceOptionsSpec::default(), input));
    };
    let Some(close_index) = after_open.find(')') else {
        return Err(ParseError::UnexpectedToken {
            expected: "closing ')' for identity sequence options",
            actual: input.into(),
        });
    };
    let inner = &after_open[..close_index];
    let rest = &after_open[close_index + 1..];
    let (options, option_rest) = parse_sequence_option_spec(inner)?;
    if !option_rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "identity sequence options",
            actual: option_rest.trim().into(),
        });
    }
    if options.owned_by.is_some() {
        return Err(ParseError::UnexpectedToken {
            expected: "identity sequence options without OWNED BY",
            actual: inner.into(),
        });
    }
    Ok((options, rest))
}

fn parse_identity_sequence_option_patch(
    input: &str,
) -> Result<(SequenceOptionsPatchSpec, &str), ParseError> {
    let mut rest = input;
    let mut options = SequenceOptionsPatchSpec::default();
    loop {
        let trimmed = rest.trim_start();
        if trimmed.is_empty() {
            return Ok((options, trimmed));
        }
        let option_input = if keyword_at_start(trimmed, "set") {
            consume_keyword(trimmed, "set").trim_start()
        } else {
            trimmed
        };
        let (patch, remainder) = parse_sequence_option_patch(option_input)?;
        if remainder == option_input {
            return Ok((options, trimmed));
        }
        merge_sequence_option_patch(&mut options, patch)?;
        rest = remainder;
    }
}

fn merge_sequence_option_patch(
    target: &mut SequenceOptionsPatchSpec,
    patch: SequenceOptionsPatchSpec,
) -> Result<(), ParseError> {
    if patch.increment.is_some() {
        target.increment = patch.increment;
    }
    if patch.as_type.is_some() {
        target.as_type = patch.as_type;
    }
    if patch.persistence.is_some() {
        target.persistence = patch.persistence;
    }
    if patch.minvalue.is_some() {
        target.minvalue = patch.minvalue;
    }
    if patch.maxvalue.is_some() {
        target.maxvalue = patch.maxvalue;
    }
    if patch.start.is_some() {
        target.start = patch.start;
    }
    if patch.restart.is_some() {
        target.restart = patch.restart;
    }
    if patch.cache.is_some() {
        target.cache = patch.cache;
    }
    if patch.cycle.is_some() {
        target.cycle = patch.cycle;
    }
    if patch.owned_by.is_some() {
        return Err(ParseError::UnexpectedToken {
            expected: "identity sequence options without OWNED BY",
            actual: "OWNED BY".into(),
        });
    }
    Ok(())
}

fn ensure_identity_action_consumed(rest: &str) -> Result<(), ParseError> {
    if rest.trim().is_empty() {
        Ok(())
    } else {
        Err(ParseError::UnexpectedToken {
            expected: "end of ALTER TABLE identity action",
            actual: rest.trim().into(),
        })
    }
}

fn parse_schema_qualified_name(
    input: &str,
) -> Result<((Option<String>, String), &str), ParseError> {
    let (parts, rest) = parse_qualified_identifier_parts(input)?;
    match parts.as_slice() {
        [name] => Ok(((None, name.clone()), rest)),
        [schema, name] => Ok(((Some(schema.clone()), name.clone()), rest)),
        _ => Err(ParseError::UnsupportedQualifiedName(parts.join("."))),
    }
}

fn parse_unqualified_identifier<'a>(
    input: &'a str,
    expected: &'static str,
) -> Result<(String, &'a str), ParseError> {
    let (parts, rest) = parse_qualified_identifier_parts(input)?;
    match parts.as_slice() {
        [name] => Ok((name.clone(), rest)),
        _ => Err(ParseError::UnexpectedToken {
            expected,
            actual: parts.join("."),
        }),
    }
}

fn parse_qualified_identifier_parts(input: &str) -> Result<(Vec<String>, &str), ParseError> {
    let (first, mut rest) = parse_sql_identifier(input)?;
    let mut parts = vec![first];
    loop {
        let trimmed = rest.trim_start();
        let Some(after_dot) = trimmed.strip_prefix('.') else {
            return Ok((parts, rest));
        };
        let (next, remaining) = parse_sql_identifier(after_dot.trim_start())?;
        parts.push(next);
        rest = remaining;
    }
}

fn parse_sequence_owned_by(input: &str) -> Result<(SequenceOwnedByClause, &str), ParseError> {
    let mut rest = consume_keyword(input.trim_start(), "owned").trim_start();
    rest = consume_keyword(rest, "by").trim_start();
    if keyword_at_start(rest, "none") {
        return Ok((SequenceOwnedByClause::None, consume_keyword(rest, "none")));
    }
    let (parts, rest) = parse_qualified_identifier_parts(rest)?;
    match parts.as_slice() {
        [table_name, column_name] => Ok((
            SequenceOwnedByClause::Column {
                table_name: table_name.clone(),
                column_name: column_name.clone(),
            },
            rest,
        )),
        [schema_name, table_name, column_name] => Ok((
            SequenceOwnedByClause::Column {
                table_name: format!("{schema_name}.{table_name}"),
                column_name: column_name.clone(),
            },
            rest,
        )),
        _ => Err(ParseError::DetailedError {
            message: "invalid OWNED BY option".into(),
            detail: None,
            hint: Some("Specify OWNED BY table.column or OWNED BY NONE.".into()),
            sqlstate: "42601",
        }),
    }
}

fn parse_signed_i64_token(input: &str) -> Result<(i64, &str), ParseError> {
    let input = input.trim_start();
    let mut end = 0usize;
    let mut previous_was_digit = false;
    for (idx, ch) in input.char_indices() {
        if idx == 0 && matches!(ch, '+' | '-') {
            end = ch.len_utf8();
            continue;
        }
        if ch.is_ascii_digit() {
            end = idx + ch.len_utf8();
            previous_was_digit = true;
            continue;
        }
        if ch == '_' && previous_was_digit {
            let next = input[idx + ch.len_utf8()..].chars().next();
            if next.is_some_and(|next| next.is_ascii_digit()) {
                end = idx + ch.len_utf8();
                previous_was_digit = false;
                continue;
            }
        }
        if ch == '_' {
            end = idx + ch.len_utf8();
            continue;
        }
        break;
    }
    if end == 0 || (end == 1 && matches!(input.as_bytes()[0], b'+' | b'-')) {
        return Err(ParseError::UnexpectedToken {
            expected: "signed integer",
            actual: input.into(),
        });
    }
    let token = &input[..end];
    let normalized = normalize_numeric_token(token);
    let value = normalized
        .parse::<i64>()
        .map_err(|_| ParseError::UnexpectedToken {
            expected: "signed integer in i64 range",
            actual: token.into(),
        })?;
    Ok((value, &input[end..]))
}

fn parse_positive_i64_token<'a>(
    input: &'a str,
    context: &'static str,
) -> Result<(i64, &'a str), ParseError> {
    let (value, rest) = parse_signed_i64_token(input)?;
    if value <= 0 {
        return Err(ParseError::UnexpectedToken {
            expected: context,
            actual: value.to_string(),
        });
    }
    Ok((value, rest))
}

fn parse_sequence_option_spec(input: &str) -> Result<(SequenceOptionsSpec, &str), ParseError> {
    let mut rest = input;
    let mut options = SequenceOptionsSpec::default();
    loop {
        let trimmed = rest.trim_start();
        if trimmed.is_empty() {
            return Ok((options, trimmed));
        }
        if keyword_at_start(trimmed, "as") {
            let (type_name, remainder) = parse_sequence_as_type(consume_keyword(trimmed, "as"))?;
            options.as_type = Some(type_name);
            rest = remainder;
            continue;
        }
        if keyword_at_start(trimmed, "logged") {
            options.persistence = Some(TablePersistence::Permanent);
            rest = consume_keyword(trimmed, "logged");
            continue;
        }
        if keyword_at_start(trimmed, "unlogged") {
            options.persistence = Some(TablePersistence::Unlogged);
            rest = consume_keyword(trimmed, "unlogged");
            continue;
        }
        if keyword_at_start(trimmed, "increment") {
            let mut next = consume_keyword(trimmed, "increment").trim_start();
            if keyword_at_start(next, "by") {
                next = consume_keyword(next, "by").trim_start();
            }
            let (value, remainder) = parse_signed_i64_token(next)?;
            options.increment = Some(value);
            rest = remainder;
            continue;
        }
        if keyword_at_start(trimmed, "minvalue") {
            let (value, remainder) = parse_signed_i64_token(consume_keyword(trimmed, "minvalue"))?;
            options.minvalue = Some(Some(value));
            rest = remainder;
            continue;
        }
        if keyword_at_start(trimmed, "no minvalue") {
            options.minvalue = Some(None);
            rest = consume_keyword(consume_keyword(trimmed, "no").trim_start(), "minvalue");
            continue;
        }
        if keyword_at_start(trimmed, "maxvalue") {
            let (value, remainder) = parse_signed_i64_token(consume_keyword(trimmed, "maxvalue"))?;
            options.maxvalue = Some(Some(value));
            rest = remainder;
            continue;
        }
        if keyword_at_start(trimmed, "no maxvalue") {
            options.maxvalue = Some(None);
            rest = consume_keyword(consume_keyword(trimmed, "no").trim_start(), "maxvalue");
            continue;
        }
        if keyword_at_start(trimmed, "start") {
            let mut next = consume_keyword(trimmed, "start").trim_start();
            if keyword_at_start(next, "with") {
                next = consume_keyword(next, "with").trim_start();
            }
            let (value, remainder) = parse_signed_i64_token(next)?;
            options.start = Some(value);
            rest = remainder;
            continue;
        }
        if keyword_at_start(trimmed, "cache") {
            let (value, remainder) = parse_signed_i64_token(consume_keyword(trimmed, "cache"))?;
            options.cache = Some(value);
            rest = remainder;
            continue;
        }
        if keyword_at_start(trimmed, "cycle") {
            options.cycle = Some(true);
            rest = consume_keyword(trimmed, "cycle");
            continue;
        }
        if keyword_at_start(trimmed, "no cycle") {
            options.cycle = Some(false);
            rest = consume_keyword(consume_keyword(trimmed, "no").trim_start(), "cycle");
            continue;
        }
        if keyword_at_start(trimmed, "owned") {
            let (owned_by, remainder) = parse_sequence_owned_by(trimmed)?;
            options.owned_by = Some(owned_by);
            rest = remainder;
            continue;
        }
        return Ok((options, trimmed));
    }
}

fn parse_sequence_as_type(input: &str) -> Result<(RawTypeName, &str), ParseError> {
    let (parts, rest) = parse_qualified_identifier_parts(input)?;
    let type_sql = parts.join(".");
    let type_name = parse_type_name(&type_sql)?;
    Ok((type_name, rest))
}

fn parse_sequence_option_patch(
    input: &str,
) -> Result<(SequenceOptionsPatchSpec, &str), ParseError> {
    let mut rest = input;
    let mut options = SequenceOptionsPatchSpec::default();
    loop {
        let trimmed = rest.trim_start();
        if trimmed.is_empty() {
            return Ok((options, trimmed));
        }
        if keyword_at_start(trimmed, "set") {
            let after_set = consume_keyword(trimmed, "set").trim_start();
            if keyword_at_start(after_set, "logged") {
                options.persistence = Some(TablePersistence::Permanent);
                rest = consume_keyword(after_set, "logged");
                continue;
            }
            if keyword_at_start(after_set, "unlogged") {
                options.persistence = Some(TablePersistence::Unlogged);
                rest = consume_keyword(after_set, "unlogged");
                continue;
            }
        }
        if keyword_at_start(trimmed, "restart") {
            let mut next = consume_keyword(trimmed, "restart").trim_start();
            if keyword_at_start(next, "with") {
                next = consume_keyword(next, "with").trim_start();
                let (value, remainder) = parse_signed_i64_token(next)?;
                options.restart = Some(Some(value));
                rest = remainder;
            } else {
                options.restart = Some(None);
                rest = next;
            }
            continue;
        }
        let (base, remainder) = parse_sequence_option_spec(trimmed)?;
        if remainder == trimmed {
            return Ok((options, trimmed));
        }
        if base.increment.is_some() {
            options.increment = base.increment;
        }
        if base.as_type.is_some() {
            options.as_type = base.as_type;
        }
        if base.persistence.is_some() {
            options.persistence = base.persistence;
        }
        if base.minvalue.is_some() {
            options.minvalue = base.minvalue;
        }
        if base.maxvalue.is_some() {
            options.maxvalue = base.maxvalue;
        }
        if base.start.is_some() {
            options.start = base.start;
        }
        if base.cache.is_some() {
            options.cache = base.cache;
        }
        if base.cycle.is_some() {
            options.cycle = base.cycle;
        }
        if base.owned_by.is_some() {
            options.owned_by = base.owned_by;
        }
        rest = remainder;
    }
}

fn build_create_sequence_statement(sql: &str) -> Result<CreateSequenceStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "create").trim_start();
    let persistence = if keyword_at_start(rest, "temporary") {
        rest = consume_keyword(rest, "temporary");
        TablePersistence::Temporary
    } else if keyword_at_start(rest, "temp") {
        rest = consume_keyword(rest, "temp");
        TablePersistence::Temporary
    } else if keyword_at_start(rest, "unlogged") {
        rest = consume_keyword(rest, "unlogged");
        TablePersistence::Unlogged
    } else {
        TablePersistence::Permanent
    };
    rest = rest.trim_start();
    rest = consume_keyword(rest, "sequence").trim_start();
    let mut if_not_exists = false;
    if keyword_at_start(rest, "if") {
        let after_if = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(after_if, "not") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF NOT EXISTS",
                actual: sql.into(),
            });
        }
        let after_not = consume_keyword(after_if, "not").trim_start();
        if !keyword_at_start(after_not, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF NOT EXISTS",
                actual: sql.into(),
            });
        }
        rest = consume_keyword(after_not, "exists").trim_start();
        if_not_exists = true;
    }
    let ((schema_name, sequence_name), rest) = parse_schema_qualified_name(rest)?;
    let (options, rest) = parse_sequence_option_spec(rest)?;
    let persistence = options.persistence.unwrap_or(persistence);
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of CREATE SEQUENCE statement",
            actual: rest.trim().into(),
        });
    }
    Ok(CreateSequenceStatement {
        schema_name,
        sequence_name,
        persistence,
        if_not_exists,
        options,
    })
}

fn build_alter_sequence_statement(sql: &str) -> Result<AlterSequenceStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "alter").trim_start();
    rest = consume_keyword(rest, "sequence").trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        let after_if = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(after_if, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF EXISTS",
                actual: sql.into(),
            });
        }
        if_exists = true;
        rest = consume_keyword(after_if, "exists").trim_start();
    }
    let (parts, rest) = parse_qualified_identifier_parts(rest)?;
    let sequence_name = parts.join(".");
    let (options, rest) = parse_sequence_option_patch(rest)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of ALTER SEQUENCE statement",
            actual: rest.trim().into(),
        });
    }
    Ok(AlterSequenceStatement {
        if_exists,
        sequence_name,
        options,
    })
}

