fn build_alter_index_alter_column_statistics_statement(
    sql: &str,
) -> Result<AlterIndexAlterColumnStatisticsStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "alter").trim_start();
    rest = consume_keyword(rest, "index").trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        let after_if = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(after_if, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF EXISTS",
                actual: sql.into(),
            });
        }
        if_exists = true;
        rest = consume_keyword(after_if, "exists").trim_start();
    }
    let (parts, rest_after_name) = parse_qualified_identifier_parts(rest)?;
    let index_name = parts.join(".");
    let mut rest = rest_after_name.trim_start();
    rest = consume_keyword(rest, "alter").trim_start();
    if keyword_at_start(rest, "column") {
        rest = consume_keyword(rest, "column").trim_start();
    }
    let (column_number_sql, rest_after_column_number) = split_sql_identifier_token(rest)?;
    let column_number_i32 = column_number_sql
        .parse::<i32>()
        .map_err(|_| ParseError::InvalidInteger(column_number_sql.to_string()))?;
    if column_number_i32 <= 0 || column_number_i32 > i32::from(i16::MAX) {
        return Err(ParseError::DetailedError {
            message: format!("column number must be in range from 1 to {}", i16::MAX),
            detail: None,
            hint: None,
            sqlstate: "22023",
        });
    }
    let column_number = i16::try_from(column_number_i32)
        .map_err(|_| ParseError::InvalidInteger(column_number_i32.to_string()))?;
    let mut rest = rest_after_column_number.trim_start();
    rest = consume_keyword(rest, "set").trim_start();
    rest = consume_keyword(rest, "statistics").trim_start();
    let (statistics_target_sql, rest) = split_sql_identifier_token(rest)?;
    let statistics_target = statistics_target_sql
        .parse::<i32>()
        .map_err(|_| ParseError::InvalidInteger(statistics_target_sql.to_string()))?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of ALTER INDEX ALTER COLUMN SET STATISTICS statement",
            actual: rest.trim().into(),
        });
    }
    Ok(AlterIndexAlterColumnStatisticsStatement {
        if_exists,
        index_name,
        column_number,
        statistics_target,
    })
}

fn build_alter_index_alter_column_options_statement(
    sql: &str,
) -> Result<AlterIndexAlterColumnOptionsStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "alter").trim_start();
    rest = consume_keyword(rest, "index").trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        let after_if = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(after_if, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF EXISTS",
                actual: sql.into(),
            });
        }
        if_exists = true;
        rest = consume_keyword(after_if, "exists").trim_start();
    }
    let (parts, rest_after_name) = parse_qualified_identifier_parts(rest)?;
    let index_name = parts.join(".");
    let mut rest = rest_after_name.trim_start();
    rest = consume_keyword(rest, "alter").trim_start();
    if keyword_at_start(rest, "column") {
        rest = consume_keyword(rest, "column").trim_start();
    }
    let (column_name, rest_after_column_name) = parse_sql_identifier(rest)?;
    let rest = rest_after_column_name.trim_start();
    let action = if keyword_at_start(rest, "set") {
        let rest = consume_keyword(rest, "set").trim_start();
        AlterColumnOptionsAction::Set(parse_assignment_reloption_list(rest)?)
    } else if keyword_at_start(rest, "reset") {
        let rest = consume_keyword(rest, "reset").trim_start();
        AlterColumnOptionsAction::Reset(parse_identifier_parenthesized_list(rest)?)
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "SET or RESET",
            actual: rest.into(),
        });
    };
    Ok(AlterIndexAlterColumnOptionsStatement {
        if_exists,
        index_name,
        column_name,
        action,
    })
}

fn parse_assignment_reloption_list(input: &str) -> Result<Vec<RelOption>, ParseError> {
    let Some(inner) = input
        .trim()
        .strip_prefix('(')
        .and_then(|value| value.strip_suffix(')'))
    else {
        return Err(ParseError::UnexpectedToken {
            expected: "parenthesized option list",
            actual: input.into(),
        });
    };
    split_comma_separated_sql(inner)?
        .into_iter()
        .map(|part| {
            let Some((name_sql, value_sql)) = part.split_once('=') else {
                return Err(ParseError::UnexpectedToken {
                    expected: "name=value option",
                    actual: part.trim().into(),
                });
            };
            let (name, tail) = parse_sql_identifier(name_sql.trim())?;
            if !tail.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "option name",
                    actual: tail.trim().into(),
                });
            }
            Ok(RelOption {
                name,
                value: value_sql.trim().trim_matches('\'').to_string(),
            })
        })
        .collect()
}

fn parse_identifier_parenthesized_list(input: &str) -> Result<Vec<String>, ParseError> {
    let Some(inner) = input
        .trim()
        .strip_prefix('(')
        .and_then(|value| value.strip_suffix(')'))
    else {
        return Err(ParseError::UnexpectedToken {
            expected: "parenthesized identifier list",
            actual: input.into(),
        });
    };
    split_comma_separated_sql(inner)?
        .into_iter()
        .map(|part| {
            let (name, tail) = parse_sql_identifier(part.trim())?;
            if !tail.trim().is_empty() {
                return Err(ParseError::UnexpectedToken {
                    expected: "option name",
                    actual: tail.trim().into(),
                });
            }
            Ok(name)
        })
        .collect()
}
fn build_drop_sequence_statement(sql: &str) -> Result<DropSequenceStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "drop").trim_start();
    rest = consume_keyword(rest, "sequence").trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        let after_if = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(after_if, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF EXISTS",
                actual: sql.into(),
            });
        }
        rest = consume_keyword(after_if, "exists").trim_start();
        if_exists = true;
    }
    let mut cascade = false;
    let mut sequence_names = Vec::new();
    for item in split_top_level_items(rest, ',')? {
        let trimmed = item.trim();
        if trimmed.is_empty() {
            continue;
        }
        let boundary =
            find_next_top_level_keyword(trimmed, &["cascade", "restrict"]).unwrap_or(trimmed.len());
        let name_sql = trimmed[..boundary].trim();
        if name_sql.is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "sequence name",
                actual: sql.into(),
            });
        }
        let (parts, suffix) = parse_qualified_identifier_parts(name_sql)?;
        if !suffix.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "sequence name",
                actual: name_sql.into(),
            });
        }
        sequence_names.push(parts.join("."));
        let tail = trimmed[boundary..].trim();
        if !tail.is_empty() {
            if tail.eq_ignore_ascii_case("cascade") {
                cascade = true;
            } else if !tail.eq_ignore_ascii_case("restrict") {
                return Err(ParseError::UnexpectedToken {
                    expected: "CASCADE or RESTRICT",
                    actual: tail.into(),
                });
            }
        }
    }
    Ok(DropSequenceStatement {
        if_exists,
        sequence_names,
        cascade,
    })
}

fn build_create_function_statement(sql: &str) -> Result<CreateFunctionStatement, ParseError> {
    let (prefix, replace_existing) = if sql
        .to_ascii_lowercase()
        .starts_with("create or replace function")
    {
        ("create or replace function", true)
    } else {
        ("create function", false)
    };
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE FUNCTION name(args) ...",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, function_name), rest) = parse_qualified_sql_name(rest)?;
    let arg_list_position = parenthesized_inner_position(sql, rest);
    let (arg_list, mut rest) = take_parenthesized_segment(rest)?;
    let args = parse_create_function_args_with_base(&arg_list, arg_list_position)?;

    let mut return_spec = None;
    let mut language = None;
    let mut body = None;
    let mut link_symbol = None;
    let mut cost = None;
    let mut support = None;
    let mut strict = false;
    let mut leakproof = false;
    let mut security_definer = false;
    let mut volatility = crate::backend::parser::FunctionVolatility::Volatile;
    let mut parallel = crate::backend::parser::FunctionParallel::Unsafe;
    let mut window = false;
    let mut config = Vec::new();

    while !rest.trim_start().is_empty() {
        rest = rest.trim_start();
        if keyword_at_start(rest, "returns") {
            let maybe_null = consume_keyword(rest, "returns").trim_start();
            if keyword_at_start(maybe_null, "null") {
                let next = consume_keyword(maybe_null, "null").trim_start();
                let next = consume_keyword(next, "on").trim_start();
                let next = consume_keyword(next, "null").trim_start();
                rest = consume_keyword(next, "input");
                strict = true;
                continue;
            }
            if return_spec.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single RETURNS clause",
                    actual: rest.into(),
                });
            }
            let (parsed, next_rest) = parse_create_function_returns(rest)?;
            return_spec = Some(parsed);
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "language") {
            if language.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single LANGUAGE clause",
                    actual: rest.into(),
                });
            }
            let (parsed, next_rest) = parse_create_function_language(rest)?;
            language = Some(parsed);
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "cost") {
            if cost.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single COST clause",
                    actual: rest.into(),
                });
            }
            let (parsed, next_rest) = parse_create_function_cost(rest)?;
            cost = Some(parsed);
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "support") {
            if support.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single SUPPORT clause",
                    actual: rest.into(),
                });
            }
            let (parsed, next_rest) = parse_create_function_support(rest)?;
            support = Some(parsed);
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "as") {
            if body.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single AS clause",
                    actual: rest.into(),
                });
            }
            let (parsed, parsed_link_symbol, next_rest) = parse_create_function_body(rest)?;
            body = Some(parsed);
            link_symbol = parsed_link_symbol;
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "return") {
            if body.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single function body",
                    actual: rest.into(),
                });
            }
            let (parsed, next_rest) = parse_create_function_return_body(rest)?;
            body = Some(parsed);
            language.get_or_insert_with(|| "sql".into());
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "begin") {
            if body.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single function body",
                    actual: rest.into(),
                });
            }
            if !consume_keyword(rest, "begin")
                .trim_start()
                .to_ascii_lowercase()
                .starts_with("atomic")
            {
                return Err(ParseError::FeatureNotSupported(
                    "CREATE FUNCTION SQL-standard bodies must use BEGIN ATOMIC".into(),
                ));
            }
            body = Some(rest.trim().to_string());
            language.get_or_insert_with(|| "sql".into());
            rest = "";
            continue;
        }
        if keyword_at_start(rest, "strict") {
            strict = true;
            rest = consume_keyword(rest, "strict");
            continue;
        }
        if keyword_at_start(rest, "called") {
            let next = consume_keyword(rest, "called").trim_start();
            let next = consume_keyword(next, "on").trim_start();
            let next = consume_keyword(next, "null").trim_start();
            rest = consume_keyword(next, "input");
            strict = false;
            continue;
        }
        if keyword_at_start(rest, "leakproof") {
            leakproof = true;
            rest = consume_keyword(rest, "leakproof");
            continue;
        }
        if keyword_at_start(rest, "security") {
            let next_rest = consume_keyword(rest, "security").trim_start();
            if keyword_at_start(next_rest, "definer") {
                security_definer = true;
                rest = consume_keyword(next_rest, "definer");
                continue;
            }
            if keyword_at_start(next_rest, "invoker") {
                security_definer = false;
                rest = consume_keyword(next_rest, "invoker");
                continue;
            }
            return Err(ParseError::UnexpectedToken {
                expected: "DEFINER or INVOKER",
                actual: next_rest.into(),
            });
        }
        if keyword_at_start(rest, "immutable") {
            volatility = crate::backend::parser::FunctionVolatility::Immutable;
            rest = consume_keyword(rest, "immutable");
            continue;
        }
        if keyword_at_start(rest, "stable") {
            volatility = crate::backend::parser::FunctionVolatility::Stable;
            rest = consume_keyword(rest, "stable");
            continue;
        }
        if keyword_at_start(rest, "volatile") {
            volatility = crate::backend::parser::FunctionVolatility::Volatile;
            rest = consume_keyword(rest, "volatile");
            continue;
        }
        if keyword_at_start(rest, "parallel") {
            let (parsed, next_rest) = parse_create_function_parallel(rest)?;
            parallel = parsed;
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "window") {
            window = true;
            rest = consume_keyword(rest, "window");
            continue;
        }
        if keyword_at_start(rest, "set") {
            let (parsed, next_rest) = parse_create_function_set_config(rest)?;
            config.push(parsed);
            rest = next_rest;
            continue;
        }
        return Err(ParseError::FeatureNotSupported(format!(
            "unsupported CREATE FUNCTION clause: {}",
            rest.split_whitespace().next().unwrap_or(rest)
        )));
    }

    let has_out_args = args
        .iter()
        .any(|arg| matches!(arg.mode, FunctionArgMode::Out | FunctionArgMode::InOut));
    let return_spec = match return_spec {
        Some(CreateFunctionReturnSpec::Type {
            ty: RawTypeName::Record,
            setof,
        }) if has_out_args => CreateFunctionReturnSpec::DerivedFromOutArgs {
            setof_record: setof,
        },
        Some(spec) => spec,
        None if has_out_args => CreateFunctionReturnSpec::DerivedFromOutArgs {
            setof_record: false,
        },
        None => {
            return Err(ParseError::UnexpectedToken {
                expected: "RETURNS clause or OUT/INOUT arguments",
                actual: sql.into(),
            });
        }
    };

    Ok(CreateFunctionStatement {
        schema_name,
        function_name,
        replace_existing,
        cost,
        support,
        args,
        return_spec,
        strict,
        leakproof,
        security_definer,
        volatility,
        parallel,
        window,
        language: language.ok_or(ParseError::UnexpectedEof)?,
        body: body.ok_or(ParseError::UnexpectedEof)?,
        link_symbol,
        config,
    })
}

fn parse_support_routine_signature(input: &str) -> Result<RoutineSignature, ParseError> {
    let ((schema_name, routine_name), rest) = parse_qualified_sql_name(input.trim())?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "support function name",
            actual: rest.trim().into(),
        });
    }
    Ok(RoutineSignature {
        schema_name,
        routine_name,
        arg_types: Vec::new(),
    })
}

fn parse_create_function_support(input: &str) -> Result<(RoutineSignature, &str), ParseError> {
    let rest = consume_keyword(input, "support").trim_start();
    let (value, rest) = take_next_word(rest)?;
    Ok((parse_support_routine_signature(&value)?, rest))
}

fn parse_create_function_set_config(input: &str) -> Result<(AlterRoutineOption, &str), ParseError> {
    let rest = consume_keyword(input, "set").trim_start();
    let (name, rest) = take_next_word(rest)?;
    let rest = rest.trim_start();
    let rest = if keyword_at_start(rest, "to") {
        consume_keyword(rest, "to").trim_start()
    } else if rest.starts_with('=') {
        rest[1..].trim_start()
    } else {
        rest
    };
    let (value, rest) = take_next_word(rest)?;
    Ok((AlterRoutineOption::SetConfig { name, value }, rest))
}

fn build_drop_function_statement(sql: &str) -> Result<DropFunctionStatement, ParseError> {
    let prefix = "drop function";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP FUNCTION name(args)",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if let Some(next) = consume_keywords(rest, &["if", "exists"]) {
        if_exists = true;
        rest = next.trim_start();
    }
    if rest.starts_with('(') {
        return Err(syntax_error_at(sql, slice_byte_offset(sql, rest), "("));
    }
    if rest.chars().next().is_some_and(|ch| ch.is_ascii_digit()) {
        return Err(syntax_error_at(
            sql,
            slice_byte_offset(sql, rest),
            syntax_error_token_at(rest, 0).as_str(),
        ));
    }
    let (routine_list, cascade) = split_drop_routine_suffix(rest)?;
    let items = split_top_level_items(routine_list, ',')?
        .into_iter()
        .filter(|item| !item.trim().is_empty())
        .collect::<Vec<_>>();
    let Some(first_item) = items.first() else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP FUNCTION name(args)",
            actual: rest.into(),
        });
    };
    let mut routines = items
        .iter()
        .map(|item| parse_drop_routine_item(item))
        .collect::<Result<Vec<_>, _>>()?;
    let first = routines.remove(0);
    let arg_list_specified = drop_routine_item_has_arg_list(first_item)?;
    Ok(DropFunctionStatement {
        if_exists,
        schema_name: first.schema_name,
        function_name: first.routine_name,
        arg_list_specified,
        arg_types: first.arg_types,
        additional_functions: routines,
        cascade,
    })
}

fn build_call_statement(sql: &str) -> Result<CallStatement, ParseError> {
    let rest = sql
        .get("call".len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let ((schema_name, procedure_name), rest) = parse_qualified_sql_name(rest)?;
    let (arg_sql, rest) = take_parenthesized_segment(rest.trim_start())?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of CALL statement",
            actual: rest.trim().into(),
        });
    }
    Ok(CallStatement {
        schema_name,
        procedure_name,
        args: parse_sql_call_args(&arg_sql)?,
        raw_arg_sql: parse_call_arg_sql_items(&arg_sql)?,
    })
}

fn build_create_procedure_statement(sql: &str) -> Result<CreateProcedureStatement, ParseError> {
    let (prefix, replace_existing) = if sql
        .to_ascii_lowercase()
        .starts_with("create or replace procedure")
    {
        ("create or replace procedure", true)
    } else {
        ("create procedure", false)
    };
    let rest = sql
        .get(prefix.len()..)
        .ok_or(ParseError::UnexpectedToken {
            expected: "CREATE PROCEDURE name(args) ...",
            actual: sql.into(),
        })?
        .trim_start();
    let ((schema_name, procedure_name), rest) = parse_qualified_sql_name(rest)?;
    let (arg_list, mut rest) = take_parenthesized_segment(rest)?;
    let args = parse_create_procedure_args(&arg_list)?;

    let mut language = None;
    let mut body = None;
    let mut sql_standard_body = false;
    let strict = false;
    let mut volatility = crate::backend::parser::FunctionVolatility::Volatile;

    while !rest.trim_start().is_empty() {
        rest = rest.trim_start();
        if keyword_at_start(rest, "language") {
            if language.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single LANGUAGE clause",
                    actual: rest.into(),
                });
            }
            let (parsed, next_rest) = parse_create_function_language(rest)?;
            language = Some(parsed);
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "as") {
            if body.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single procedure body",
                    actual: rest.into(),
                });
            }
            let (parsed, _link_symbol, next_rest) = parse_create_function_body(rest)?;
            body = Some(parsed);
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "begin") {
            if body.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "single procedure body",
                    actual: rest.into(),
                });
            }
            body = Some(rest.trim().to_string());
            sql_standard_body = true;
            language.get_or_insert_with(|| "sql".into());
            rest = "";
            continue;
        }
        if keyword_at_start(rest, "strict") {
            return Err(ParseError::DetailedError {
                message: "invalid attribute in procedure definition".into(),
                detail: None,
                hint: None,
                sqlstate: "42P13",
            });
        }
        if keyword_at_start(rest, "immutable") {
            volatility = crate::backend::parser::FunctionVolatility::Immutable;
            rest = consume_keyword(rest, "immutable");
            continue;
        }
        if keyword_at_start(rest, "stable") {
            volatility = crate::backend::parser::FunctionVolatility::Stable;
            rest = consume_keyword(rest, "stable");
            continue;
        }
        if keyword_at_start(rest, "volatile") {
            volatility = crate::backend::parser::FunctionVolatility::Volatile;
            rest = consume_keyword(rest, "volatile");
            continue;
        }
        if keyword_at_start(rest, "window")
            || keyword_at_start(rest, "parallel")
            || keyword_at_start(rest, "leakproof")
            || keyword_at_start(rest, "returns")
        {
            return Err(ParseError::DetailedError {
                message: "invalid attribute in procedure definition".into(),
                detail: None,
                hint: None,
                sqlstate: "42P13",
            });
        }
        return Err(ParseError::FeatureNotSupported(format!(
            "unsupported CREATE PROCEDURE clause: {}",
            rest.split_whitespace().next().unwrap_or(rest)
        )));
    }

    Ok(CreateProcedureStatement {
        schema_name,
        procedure_name,
        replace_existing,
        args,
        strict,
        volatility,
        language: language.ok_or(ParseError::UnexpectedEof)?,
        body: body.ok_or(ParseError::UnexpectedEof)?,
        sql_standard_body,
    })
}

fn build_drop_procedure_statement(sql: &str) -> Result<DropProcedureStatement, ParseError> {
    let prefix = "drop procedure";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP PROCEDURE name(args)",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if let Some(next) = consume_keywords(rest, &["if", "exists"]) {
        if_exists = true;
        rest = next.trim_start();
    }
    let (routine_list, cascade) = split_drop_routine_suffix(rest)?;
    let procedures = split_top_level_items(routine_list, ',')?
        .into_iter()
        .filter(|item| !item.trim().is_empty())
        .map(|item| parse_drop_routine_item(&item))
        .collect::<Result<Vec<_>, _>>()?;
    Ok(DropProcedureStatement {
        if_exists,
        procedures,
        cascade,
    })
}

fn build_drop_routine_statement(sql: &str) -> Result<DropProcedureStatement, ParseError> {
    let prefix = "drop routine";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP ROUTINE name(args)",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if let Some(next) = consume_keywords(rest, &["if", "exists"]) {
        if_exists = true;
        rest = next.trim_start();
    }
    let (routine_list, cascade) = split_drop_routine_suffix(rest)?;
    let procedures = split_top_level_items(routine_list, ',')?
        .into_iter()
        .filter(|item| !item.trim().is_empty())
        .map(|item| parse_drop_routine_item(&item))
        .collect::<Result<Vec<_>, _>>()?;
    Ok(DropProcedureStatement {
        if_exists,
        procedures,
        cascade,
    })
}

fn split_drop_routine_suffix(input: &str) -> Result<(&str, bool), ParseError> {
    let trimmed = input.trim_end();
    if let Some(prefix) = trim_keyword_suffix(trimmed, "cascade") {
        return Ok((prefix.trim_end(), true));
    }
    if let Some(prefix) = trim_keyword_suffix(trimmed, "restrict") {
        return Ok((prefix.trim_end(), false));
    }
    Ok((trimmed, false))
}

fn trim_keyword_suffix<'a>(input: &'a str, keyword: &str) -> Option<&'a str> {
    let index = input.len().checked_sub(keyword.len())?;
    input[index..].eq_ignore_ascii_case(keyword).then(|| {
        let prefix = &input[..index];
        prefix
            .chars()
            .last()
            .is_none_or(|ch| ch.is_whitespace())
            .then_some(prefix)
    })?
}

fn parse_drop_routine_item(input: &str) -> Result<DropRoutineItem, ParseError> {
    let ((schema_name, routine_name), rest) = parse_qualified_sql_name(input.trim())?;
    let rest = rest.trim_start();
    let (arg_types, rest) = if rest.starts_with('(') {
        let (arg_sql, rest) = take_parenthesized_segment(rest)?;
        let arg_types = split_comma_separated_sql(&arg_sql)?
            .into_iter()
            .filter(|item| !item.trim().is_empty())
            .map(|item| item.trim().to_string())
            .collect();
        (arg_types, rest)
    } else {
        (Vec::new(), rest)
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "comma or end of DROP PROCEDURE list",
            actual: rest.into(),
        });
    }
    Ok(DropRoutineItem {
        schema_name,
        routine_name,
        arg_types,
    })
}

fn drop_routine_item_has_arg_list(input: &str) -> Result<bool, ParseError> {
    let (_, rest) = parse_qualified_sql_name(input.trim())?;
    Ok(rest.trim_start().starts_with('('))
}

fn build_alter_procedure_statement(sql: &str) -> Result<AlterProcedureStatement, ParseError> {
    let rest = sql
        .get("alter procedure".len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let ((schema_name, procedure_name), rest_after_name) = parse_qualified_sql_name(rest)?;
    let (arg_sql, suffix) = take_parenthesized_segment(rest_after_name.trim_start())?;
    let suffix = suffix.trim();
    let action = if keyword_at_start(suffix, "strict") {
        if !consume_keyword(suffix, "strict").trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of ALTER PROCEDURE statement",
                actual: suffix.into(),
            });
        }
        AlterProcedureAction::Strict
    } else if keyword_at_start(suffix, "volatile") {
        if !consume_keyword(suffix, "volatile").trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of ALTER PROCEDURE statement",
                actual: suffix.into(),
            });
        }
        AlterProcedureAction::Volatility(crate::backend::parser::FunctionVolatility::Volatile)
    } else if keyword_at_start(suffix, "stable") {
        if !consume_keyword(suffix, "stable").trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of ALTER PROCEDURE statement",
                actual: suffix.into(),
            });
        }
        AlterProcedureAction::Volatility(crate::backend::parser::FunctionVolatility::Stable)
    } else if keyword_at_start(suffix, "immutable") {
        if !consume_keyword(suffix, "immutable").trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of ALTER PROCEDURE statement",
                actual: suffix.into(),
            });
        }
        AlterProcedureAction::Volatility(crate::backend::parser::FunctionVolatility::Immutable)
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "procedure attribute",
            actual: suffix.into(),
        });
    };
    Ok(AlterProcedureStatement {
        schema_name,
        procedure_name,
        arg_types: split_comma_separated_sql(&arg_sql)?
            .into_iter()
            .filter(|item| !item.is_empty())
            .map(str::to_string)
            .collect(),
        action,
    })
}

fn build_alter_routine_statement(sql: &str) -> Result<AlterRoutineStatement, ParseError> {
    let lowered = sql.to_ascii_lowercase();
    let (kind, prefix) = if lowered.starts_with("alter function ") {
        (RoutineKind::Function, "alter function")
    } else if lowered.starts_with("alter procedure ") {
        (RoutineKind::Procedure, "alter procedure")
    } else if lowered.starts_with("alter aggregate ") {
        (RoutineKind::Aggregate, "alter aggregate")
    } else if lowered.starts_with("alter routine ") {
        (RoutineKind::Routine, "alter routine")
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "ALTER FUNCTION, ALTER PROCEDURE, ALTER AGGREGATE, or ALTER ROUTINE",
            actual: sql.into(),
        });
    };
    let rest = sql
        .get(prefix.len()..)
        .ok_or(ParseError::UnexpectedEof)?
        .trim_start();
    let ((schema_name, routine_name), rest_after_name) = parse_qualified_sql_name(rest)?;
    let (arg_sql, suffix) = if rest_after_name.trim_start().starts_with('(') {
        take_parenthesized_segment(rest_after_name.trim_start())?
    } else {
        ("".to_string(), rest_after_name.trim_start())
    };
    let signature = RoutineSignature {
        schema_name,
        routine_name,
        arg_types: split_comma_separated_sql(&arg_sql)?
            .into_iter()
            .filter(|item| !item.is_empty())
            .map(str::to_string)
            .collect(),
    };
    let suffix = suffix.trim();
    let suffix_lower = suffix.to_ascii_lowercase();
    if keyword_at_start(suffix, "rename") {
        let rest = consume_keyword(suffix, "rename").trim_start();
        let rest = consume_keyword(rest, "to").trim_start();
        return Ok(AlterRoutineStatement {
            kind,
            signature,
            action: AlterRoutineAction::Rename {
                new_name: normalize_simple_identifier(rest)?,
            },
        });
    }
    if suffix_lower.starts_with("set schema ") {
        return Ok(AlterRoutineStatement {
            kind,
            signature,
            action: AlterRoutineAction::SetSchema {
                new_schema: normalize_simple_identifier(suffix["set schema ".len()..].trim())?,
            },
        });
    }
    if suffix_lower.starts_with("owner to ") {
        return Ok(AlterRoutineStatement {
            kind,
            signature,
            action: AlterRoutineAction::OwnerTo {
                new_owner: normalize_simple_identifier(suffix["owner to ".len()..].trim())?,
            },
        });
    }
    if suffix_lower.starts_with("depends on extension ")
        || suffix_lower.starts_with("no depends on extension ")
    {
        let remove = suffix_lower.starts_with("no ");
        let prefix = if remove {
            "no depends on extension "
        } else {
            "depends on extension "
        };
        return Ok(AlterRoutineStatement {
            kind,
            signature,
            action: AlterRoutineAction::DependsOnExtension {
                extension_name: normalize_simple_identifier(suffix[prefix.len()..].trim())?,
                remove,
            },
        });
    }
    Ok(AlterRoutineStatement {
        kind,
        signature,
        action: AlterRoutineAction::Options(parse_alter_routine_options(suffix)?),
    })
}

fn parse_alter_routine_options(mut input: &str) -> Result<Vec<AlterRoutineOption>, ParseError> {
    let mut options = Vec::new();
    while !input.trim().is_empty() {
        input = input.trim_start();
        if keyword_at_start(input, "strict") {
            options.push(AlterRoutineOption::Strict(true));
            input = consume_keyword(input, "strict");
        } else if keyword_at_start(input, "returns") {
            let rest = consume_keyword(input, "returns").trim_start();
            let rest = consume_keyword(rest, "null").trim_start();
            let rest = consume_keyword(rest, "on").trim_start();
            input = consume_keyword(rest, "null").trim_start();
            options.push(AlterRoutineOption::Strict(false));
        } else if keyword_at_start(input, "called") {
            let rest = consume_keyword(input, "called").trim_start();
            let rest = consume_keyword(rest, "on").trim_start();
            input = consume_keyword(rest, "null").trim_start();
            options.push(AlterRoutineOption::Strict(false));
        } else if keyword_at_start(input, "immutable") {
            options.push(AlterRoutineOption::Volatility(
                FunctionVolatility::Immutable,
            ));
            input = consume_keyword(input, "immutable");
        } else if keyword_at_start(input, "stable") {
            options.push(AlterRoutineOption::Volatility(FunctionVolatility::Stable));
            input = consume_keyword(input, "stable");
        } else if keyword_at_start(input, "volatile") {
            options.push(AlterRoutineOption::Volatility(FunctionVolatility::Volatile));
            input = consume_keyword(input, "volatile");
        } else if keyword_at_start(input, "security") {
            let rest = consume_keyword(input, "security").trim_start();
            if keyword_at_start(rest, "definer") {
                options.push(AlterRoutineOption::SecurityDefiner(true));
                input = consume_keyword(rest, "definer");
            } else {
                options.push(AlterRoutineOption::SecurityDefiner(false));
                input = consume_keyword(rest, "invoker");
            }
        } else if keyword_at_start(input, "leakproof") {
            options.push(AlterRoutineOption::Leakproof(true));
            input = consume_keyword(input, "leakproof");
        } else if keyword_at_start(input, "not") {
            let rest = consume_keyword(input, "not").trim_start();
            options.push(AlterRoutineOption::Leakproof(false));
            input = consume_keyword(rest, "leakproof");
        } else if keyword_at_start(input, "parallel") {
            let rest = consume_keyword(input, "parallel").trim_start();
            let (value, rest) = take_next_word(rest)?;
            let parallel = match value.to_ascii_lowercase().as_str() {
                "safe" => FunctionParallel::Safe,
                "restricted" => FunctionParallel::Restricted,
                "unsafe" => FunctionParallel::Unsafe,
                _ => {
                    return Err(ParseError::UnexpectedToken {
                        expected: "SAFE, RESTRICTED, or UNSAFE",
                        actual: value,
                    });
                }
            };
            options.push(AlterRoutineOption::Parallel(parallel));
            input = rest;
        } else if keyword_at_start(input, "cost") {
            let rest = consume_keyword(input, "cost").trim_start();
            let (value, rest) = take_next_word(rest)?;
            options.push(AlterRoutineOption::Cost(value));
            input = rest;
        } else if keyword_at_start(input, "rows") {
            let rest = consume_keyword(input, "rows").trim_start();
            let (value, rest) = take_next_word(rest)?;
            options.push(AlterRoutineOption::Rows(value));
            input = rest;
        } else if keyword_at_start(input, "support") {
            let rest = consume_keyword(input, "support").trim_start();
            let (value, rest) = take_next_word(rest)?;
            options.push(AlterRoutineOption::Support(
                parse_support_routine_signature(&value)?,
            ));
            input = rest;
        } else if keyword_at_start(input, "set") {
            let rest = consume_keyword(input, "set").trim_start();
            let (name, rest) = take_next_word(rest)?;
            let rest = rest.trim_start();
            let rest = if keyword_at_start(rest, "to") {
                consume_keyword(rest, "to").trim_start()
            } else if rest.starts_with('=') {
                rest[1..].trim_start()
            } else {
                rest
            };
            let (value, rest) = take_next_word(rest)?;
            options.push(AlterRoutineOption::SetConfig { name, value });
            input = rest;
        } else if keyword_at_start(input, "reset") {
            let rest = consume_keyword(input, "reset").trim_start();
            if keyword_at_start(rest, "all") {
                options.push(AlterRoutineOption::ResetAll);
                input = consume_keyword(rest, "all");
            } else {
                let (name, rest) = take_next_word(rest)?;
                options.push(AlterRoutineOption::ResetConfig(name));
                input = rest;
            }
        } else {
            return Err(ParseError::UnexpectedToken {
                expected: "routine option",
                actual: input.into(),
            });
        }
    }
    Ok(options)
}

fn take_next_word(input: &str) -> Result<(String, &str), ParseError> {
    let trimmed = input.trim_start();
    if trimmed.is_empty() {
        return Err(ParseError::UnexpectedEof);
    }
    let end = trimmed.find(char::is_whitespace).unwrap_or(trimmed.len());
    Ok((
        trimmed[..end].trim_matches('\'').to_string(),
        &trimmed[end..],
    ))
}

fn build_drop_routine_like_statement(
    sql: &str,
    prefix: &str,
    expected: &'static str,
) -> Result<DropFunctionStatement, ParseError> {
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected,
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if let Some(next) = consume_keywords(rest, &["if", "exists"]) {
        if_exists = true;
        rest = next.trim_start();
    }
    let ((schema_name, function_name), rest_after_name) = parse_qualified_sql_name(rest)?;
    let rest_after_name = rest_after_name.trim_start();
    let arg_list_specified = rest_after_name.starts_with('(');
    let (arg_sql, suffix) = if rest_after_name.starts_with('(') {
        take_parenthesized_segment(rest_after_name)?
    } else {
        ("".to_string(), rest_after_name)
    };
    let suffix = suffix.trim();
    let cascade = if suffix.is_empty() || keyword_at_start(suffix, "restrict") {
        false
    } else if keyword_at_start(suffix, "cascade") {
        true
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "CASCADE, RESTRICT, or end of statement",
            actual: suffix.into(),
        });
    };
    let arg_types = split_comma_separated_sql(&arg_sql)?
        .into_iter()
        .filter(|item| !item.is_empty())
        .map(str::to_string)
        .collect();
    Ok(DropFunctionStatement {
        if_exists,
        schema_name,
        function_name,
        arg_list_specified,
        arg_types,
        additional_functions: Vec::new(),
        cascade,
    })
}

fn parse_sql_call_args(input: &str) -> Result<SqlCallArgs, ParseError> {
    if input.trim().is_empty() {
        return Ok(SqlCallArgs::Args(Vec::new()));
    }
    let pair = pgrust_sql_grammar::parse_rule(Rule::function_arg_list, input)
        .map_err(|err| map_pest_error("function argument list", input, err))?
        .next()
        .ok_or(ParseError::UnexpectedEof)?;
    let parsed = build_function_arg_list(pair)?;
    Ok(SqlCallArgs::Args(parsed.args))
}

fn parse_call_arg_sql_items(input: &str) -> Result<Vec<String>, ParseError> {
    if input.trim().is_empty() {
        return Ok(Vec::new());
    }
    split_top_level_items(input, ',')?
        .into_iter()
        .map(|item| strip_call_arg_name(&item).map(str::to_string))
        .collect()
}

fn strip_call_arg_name(input: &str) -> Result<&str, ParseError> {
    let trimmed = input.trim();
    if let Some(index) = find_top_level_named_arg_operator(trimmed, "=>") {
        return Ok(trimmed[index + 2..].trim());
    }
    if let Some(index) = find_top_level_named_arg_operator(trimmed, ":=") {
        return Ok(trimmed[index + 2..].trim());
    }
    Ok(trimmed)
}

fn find_top_level_named_arg_operator(input: &str, operator: &str) -> Option<usize> {
    let bytes = input.as_bytes();
    let op = operator.as_bytes();
    let mut depth = 0usize;
    let mut i = 0usize;
    while i + op.len() <= bytes.len() {
        match bytes[i] {
            b'\'' => {
                i = parse_delimited_token_end(bytes, i, b'\'');
                continue;
            }
            b'"' => {
                i = parse_delimited_token_end(bytes, i, b'"');
                continue;
            }
            b'$' => {
                if let Some(end) = scan_dollar_string_token_end(input, i) {
                    i = end;
                    continue;
                }
            }
            b'(' | b'[' => depth += 1,
            b')' | b']' => depth = depth.saturating_sub(1),
            _ => {}
        }
        if depth == 0 && &bytes[i..i + op.len()] == op {
            return Some(i);
        }
        i += 1;
    }
    None
}

fn parse_create_procedure_args(input: &str) -> Result<Vec<CreateFunctionArg>, ParseError> {
    let items = split_top_level_items(input, ',')?;
    if items.len() == 1 && items[0].trim().is_empty() {
        return Ok(Vec::new());
    }
    items
        .into_iter()
        .filter(|item| !item.trim().is_empty())
        .map(|item| parse_create_procedure_arg(&item))
        .collect()
}

fn parse_create_procedure_arg(input: &str) -> Result<CreateFunctionArg, ParseError> {
    let (trimmed, default_expr) = split_create_proc_arg_default(input.trim(), true)?;
    let prefix_variadic = keyword_at_start(trimmed, "variadic");
    let trimmed = if prefix_variadic {
        consume_keyword(trimmed, "variadic").trim_start()
    } else {
        trimmed
    };
    if !prefix_variadic && let Ok((name, rest)) = parse_sql_identifier(trimmed) {
        let rest = rest.trim_start();
        let (mode, variadic, type_sql) = if keyword_at_start(rest, "inout") {
            (
                FunctionArgMode::InOut,
                false,
                consume_keyword(rest, "inout"),
            )
        } else if keyword_at_start(rest, "out") {
            (FunctionArgMode::Out, false, consume_keyword(rest, "out"))
        } else if keyword_at_start(rest, "in") {
            (FunctionArgMode::In, false, consume_keyword(rest, "in"))
        } else if keyword_at_start(rest, "variadic") {
            (FunctionArgMode::In, true, consume_keyword(rest, "variadic"))
        } else {
            (FunctionArgMode::In, false, "")
        };
        if !type_sql.trim().is_empty() {
            return Ok(CreateFunctionArg {
                mode,
                name: Some(name),
                ty: parse_type_name(type_sql.trim())?,
                type_position: None,
                default_expr: default_expr.map(str::to_string),
                variadic,
            });
        }
    }
    let mut arg = parse_create_function_arg(trimmed)?;
    arg.default_expr = default_expr.map(str::to_string);
    arg.variadic = prefix_variadic;
    Ok(arg)
}

#[derive(Debug, Default)]
struct ParsedCreateAggregateOptions {
    sfunc_name: Option<String>,
    stype: Option<RawTypeName>,
    finalfunc_name: Option<String>,
    initcond: Option<String>,
    parallel: Option<FunctionParallel>,
    basetype: Option<AggregateSignatureKind>,
    transspace: i32,
    combinefunc_name: Option<String>,
    serialfunc_name: Option<String>,
    deserialfunc_name: Option<String>,
    finalfunc_extra: bool,
    finalfunc_modify: char,
    mstype: Option<RawTypeName>,
    msfunc_name: Option<String>,
    minvfunc_name: Option<String>,
    mfinalfunc_name: Option<String>,
    minitcond: Option<String>,
    mtransspace: i32,
    mfinalfunc_extra: bool,
    mfinalfunc_modify: char,
    hypothetical: bool,
}

fn build_create_aggregate_statement(sql: &str) -> Result<CreateAggregateStatement, ParseError> {
    let (prefix, replace_existing) = if sql
        .to_ascii_lowercase()
        .starts_with("create or replace aggregate")
    {
        ("create or replace aggregate", true)
    } else {
        ("create aggregate", false)
    };
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE AGGREGATE name(signature) (...)",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, aggregate_name), rest) = parse_schema_qualified_name(rest)?;
    let (first_segment, rest) = take_parenthesized_segment(rest)?;
    let (signature, options_sql, rest) = if rest.trim_start().starts_with('(') {
        let signature = parse_aggregate_signature_kind(&first_segment)?;
        let (options_sql, rest) = take_parenthesized_segment(rest)?;
        (Some(signature), options_sql, rest)
    } else {
        (None, first_segment, rest)
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of CREATE AGGREGATE",
            actual: rest.trim().into(),
        });
    }

    let parsed_options = parse_create_aggregate_options(&options_sql)?;
    if signature.is_none() && parsed_options.basetype.is_none() && parsed_options.stype.is_some() {
        return Err(ParseError::DetailedError {
            message: "aggregate input type must be specified".into(),
            detail: None,
            hint: None,
            sqlstate: "42601",
        });
    }
    let signature = match signature {
        Some(signature) => {
            if parsed_options.basetype.is_some() {
                return Err(ParseError::UnexpectedToken {
                    expected: "either an aggregate signature or BASETYPE, not both",
                    actual: aggregate_name.clone(),
                });
            }
            signature
        }
        None => parsed_options
            .basetype
            .clone()
            .unwrap_or(AggregateSignatureKind::Star),
    };

    let missing_actual = aggregate_name.clone();
    let stype = parsed_options
        .stype
        .ok_or_else(|| ParseError::UnexpectedToken {
            expected: "STYPE or STYPE1 option",
            actual: "aggregate stype must be specified".into(),
        })?;
    let sfunc_name = parsed_options
        .sfunc_name
        .ok_or_else(|| ParseError::UnexpectedToken {
            expected: "SFUNC or SFUNC1 option",
            actual: missing_actual.clone(),
        })?;
    Ok(CreateAggregateStatement {
        schema_name,
        aggregate_name,
        replace_existing,
        signature,
        sfunc_name,
        stype,
        finalfunc_name: parsed_options.finalfunc_name,
        initcond: parsed_options.initcond,
        parallel: parsed_options.parallel,
        transspace: parsed_options.transspace,
        combinefunc_name: parsed_options.combinefunc_name,
        serialfunc_name: parsed_options.serialfunc_name,
        deserialfunc_name: parsed_options.deserialfunc_name,
        finalfunc_extra: parsed_options.finalfunc_extra,
        finalfunc_modify: parsed_options.finalfunc_modify,
        mstype: parsed_options.mstype,
        msfunc_name: parsed_options.msfunc_name,
        minvfunc_name: parsed_options.minvfunc_name,
        mfinalfunc_name: parsed_options.mfinalfunc_name,
        minitcond: parsed_options.minitcond,
        mtransspace: parsed_options.mtransspace,
        mfinalfunc_extra: parsed_options.mfinalfunc_extra,
        mfinalfunc_modify: parsed_options.mfinalfunc_modify,
        hypothetical: parsed_options.hypothetical,
    })
}

fn build_drop_aggregate_statement(sql: &str) -> Result<DropAggregateStatement, ParseError> {
    let prefix = "drop aggregate";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP AGGREGATE name(signature)",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if let Some(next) = consume_keywords(rest, &["if", "exists"]) {
        if_exists = true;
        rest = next.trim_start();
    }
    if rest.chars().next().is_some_and(|ch| ch.is_ascii_digit()) {
        return Err(syntax_error_at(
            sql,
            slice_byte_offset(sql, rest),
            syntax_error_token_at(rest, 0).as_str(),
        ));
    }
    let ((schema_name, aggregate_name), rest_after_name) = parse_schema_qualified_name(rest)?;
    if !rest_after_name.trim_start().starts_with('(') {
        return Err(syntax_error_at_statement_end(sql));
    }
    let (signature_sql, suffix) = take_parenthesized_segment(rest_after_name.trim_start())?;
    let suffix = suffix.trim();
    let cascade = if suffix.is_empty() || keyword_at_start(suffix, "restrict") {
        false
    } else if keyword_at_start(suffix, "cascade") {
        true
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "CASCADE, RESTRICT, or end of statement",
            actual: suffix.into(),
        });
    };
    Ok(DropAggregateStatement {
        if_exists,
        schema_name,
        aggregate_name,
        signature: parse_aggregate_signature_kind(&signature_sql)?,
        cascade,
    })
}

fn build_alter_aggregate_rename_statement(
    sql: &str,
) -> Result<AlterAggregateRenameStatement, ParseError> {
    let prefix = "alter aggregate";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "ALTER AGGREGATE name(signature) RENAME TO new_name",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, aggregate_name), rest_after_name) = parse_schema_qualified_name(rest)?;
    let (signature_sql, rest) = take_parenthesized_segment(rest_after_name.trim_start())?;
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "rename") {
        return Err(ParseError::UnexpectedToken {
            expected: "RENAME TO",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "rename").trim_start();
    if !keyword_at_start(rest, "to") {
        return Err(ParseError::UnexpectedToken {
            expected: "TO",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "to").trim_start();
    let (new_name, rest) = parse_sql_identifier(rest)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of ALTER AGGREGATE RENAME statement",
            actual: rest.trim().into(),
        });
    }
    Ok(AlterAggregateRenameStatement {
        schema_name,
        aggregate_name,
        signature: parse_aggregate_signature_kind(&signature_sql)?,
        new_name,
    })
}

fn build_comment_on_aggregate_statement(
    sql: &str,
) -> Result<CommentOnAggregateStatement, ParseError> {
    let Some(rest) = sql.get("comment on aggregate".len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON AGGREGATE name(signature) IS ...",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, aggregate_name), rest) = parse_schema_qualified_name(rest)?;
    let (signature_sql, rest) = take_parenthesized_segment(rest.trim_start())?;
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "is") {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "is").trim_start();
    let (comment, rest) = if keyword_at_start(rest, "null") {
        (None, consume_keyword(rest, "null"))
    } else {
        let len = scan_string_literal_token_len(rest).ok_or(ParseError::UnexpectedToken {
            expected: "quoted string or NULL",
            actual: rest.into(),
        })?;
        (Some(decode_string_literal(&rest[..len])?), &rest[len..])
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of COMMENT ON AGGREGATE",
            actual: rest.trim().into(),
        });
    }
    Ok(CommentOnAggregateStatement {
        schema_name,
        aggregate_name,
        signature: parse_aggregate_signature_kind(&signature_sql)?,
        comment,
    })
}

fn build_comment_on_function_statement(
    sql: &str,
) -> Result<CommentOnFunctionStatement, ParseError> {
    let Some(rest) = sql.get("comment on function".len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON FUNCTION name(signature) IS ...",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, function_name), rest) = parse_schema_qualified_name(rest)?;
    let (signature_sql, rest) = take_parenthesized_segment(rest.trim_start())?;
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "is") {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "is").trim_start();
    let (comment, rest) = if keyword_at_start(rest, "null") {
        (None, consume_keyword(rest, "null"))
    } else {
        let len = scan_string_literal_token_len(rest).ok_or(ParseError::UnexpectedToken {
            expected: "quoted string or NULL",
            actual: rest.into(),
        })?;
        (Some(decode_string_literal(&rest[..len])?), &rest[len..])
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of COMMENT ON FUNCTION",
            actual: rest.trim().into(),
        });
    }
    let arg_types = if signature_sql.trim().is_empty() {
        Vec::new()
    } else {
        split_top_level_items(&signature_sql, ',')?
            .into_iter()
            .map(|arg| arg.trim().to_string())
            .collect::<Vec<_>>()
    };
    Ok(CommentOnFunctionStatement {
        schema_name,
        function_name,
        arg_types,
        comment,
    })
}

fn build_comment_on_operator_statement(
    sql: &str,
) -> Result<CommentOnOperatorStatement, ParseError> {
    let Some(rest) = sql.get("comment on operator".len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON OPERATOR name(leftarg, rightarg) IS ...",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, operator_name), rest_after_name) = parse_operator_name(rest)?;
    let ((left_arg, right_arg), rest) = parse_operator_argtypes(rest_after_name.trim_start())?;
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "is") {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "is").trim_start();
    let (comment, rest) = if keyword_at_start(rest, "null") {
        (None, consume_keyword(rest, "null"))
    } else {
        let len = scan_string_literal_token_len(rest).ok_or(ParseError::UnexpectedToken {
            expected: "quoted string or NULL",
            actual: rest.into(),
        })?;
        (Some(decode_string_literal(&rest[..len])?), &rest[len..])
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of COMMENT ON OPERATOR",
            actual: rest.trim().into(),
        });
    }
    Ok(CommentOnOperatorStatement {
        schema_name,
        operator_name,
        left_arg,
        right_arg,
        comment,
    })
}

fn parse_comment_value(
    rest: &str,
    expected_end: &'static str,
) -> Result<Option<String>, ParseError> {
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "is") {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "is").trim_start();
    let (comment, rest) = if keyword_at_start(rest, "null") {
        (None, consume_keyword(rest, "null"))
    } else {
        let len = scan_string_literal_token_len(rest).ok_or(ParseError::UnexpectedToken {
            expected: "quoted string or NULL",
            actual: rest.into(),
        })?;
        (Some(decode_string_literal(&rest[..len])?), &rest[len..])
    };
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: expected_end,
            actual: rest.trim().into(),
        });
    }
    Ok(comment)
}

fn build_comment_on_type_statement(sql: &str) -> Result<CommentOnTypeStatement, ParseError> {
    let Some(rest) = sql.get("comment on type".len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON TYPE name IS ...",
            actual: sql.into(),
        });
    };
    let Some(is_index) = find_top_level_keyword(rest, "is") else {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.trim().into(),
        });
    };
    let type_name = rest[..is_index].trim();
    if type_name.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "type name",
            actual: sql.into(),
        });
    }
    Ok(CommentOnTypeStatement {
        type_name: type_name.to_string(),
        comment: parse_comment_value(&rest[is_index..], "end of COMMENT ON TYPE")?,
    })
}

fn build_comment_on_column_statement(sql: &str) -> Result<CommentOnColumnStatement, ParseError> {
    let Some(rest) = sql.get("comment on column".len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "COMMENT ON COLUMN relation.column IS ...",
            actual: sql.into(),
        });
    };
    let Some(is_index) = find_top_level_keyword(rest, "is") else {
        return Err(ParseError::UnexpectedToken {
            expected: "IS",
            actual: rest.trim().into(),
        });
    };
    let target = rest[..is_index].trim();
    let Some((table_name, column_name)) = target.rsplit_once('.') else {
        return Err(ParseError::UnexpectedToken {
            expected: "relation.column",
            actual: target.into(),
        });
    };
    Ok(CommentOnColumnStatement {
        table_name: table_name.trim().to_string(),
        column_name: column_name.trim().to_string(),
        comment: parse_comment_value(&rest[is_index..], "end of COMMENT ON COLUMN")?,
    })
}

fn parse_create_aggregate_options(input: &str) -> Result<ParsedCreateAggregateOptions, ParseError> {
    let mut parsed = ParsedCreateAggregateOptions {
        finalfunc_modify: 'r',
        mfinalfunc_modify: 'r',
        ..Default::default()
    };
    for item in split_top_level_items(input, ',')? {
        let Some(eq_idx) = item.find('=') else {
            if item.trim().eq_ignore_ascii_case("hypothetical") {
                parsed.hypothetical = true;
                continue;
            }
            return Err(ParseError::UnexpectedToken {
                expected: "aggregate option assignment",
                actual: item,
            });
        };
        let raw_key = item[..eq_idx].trim();
        if raw_key.starts_with('"') {
            let attr = parse_sql_identifier(raw_key)
                .map(|(ident, _)| ident)
                .unwrap_or_else(|_| raw_key.trim_matches('"').to_string());
            crate::backend::utils::misc::notices::push_warning(format!(
                "aggregate attribute \"{attr}\" not recognized"
            ));
            continue;
        }
        let key = raw_key.to_ascii_lowercase();
        let value = item[eq_idx + 1..].trim();
        match key.as_str() {
            "sfunc" | "sfunc1" => parsed.sfunc_name = Some(parse_aggregate_proc_name(value)?),
            "stype" | "stype1" => parsed.stype = Some(parse_type_name(value)?),
            "finalfunc" => parsed.finalfunc_name = Some(parse_aggregate_proc_name(value)?),
            "initcond" | "initcond1" => parsed.initcond = Some(parse_aggregate_option_text(value)?),
            "parallel" => parsed.parallel = Some(parse_aggregate_parallel(value)?),
            "basetype" => parsed.basetype = Some(parse_legacy_aggregate_basetype(value)?),
            "sspace" => parsed.transspace = parse_aggregate_i32(value)?,
            "combinefunc" => parsed.combinefunc_name = Some(parse_aggregate_proc_name(value)?),
            "serialfunc" => parsed.serialfunc_name = Some(parse_aggregate_proc_name(value)?),
            "deserialfunc" => parsed.deserialfunc_name = Some(parse_aggregate_proc_name(value)?),
            "finalfunc_extra" => parsed.finalfunc_extra = parse_aggregate_bool(value)?,
            "finalfunc_modify" => parsed.finalfunc_modify = parse_aggregate_final_modify(value)?,
            "mstype" => parsed.mstype = Some(parse_type_name(value)?),
            "msfunc" => parsed.msfunc_name = Some(parse_aggregate_proc_name(value)?),
            "minvfunc" => parsed.minvfunc_name = Some(parse_aggregate_proc_name(value)?),
            "mfinalfunc" => parsed.mfinalfunc_name = Some(parse_aggregate_proc_name(value)?),
            "minitcond" => parsed.minitcond = Some(parse_aggregate_option_text(value)?),
            "msspace" => parsed.mtransspace = parse_aggregate_i32(value)?,
            "mfinalfunc_extra" => parsed.mfinalfunc_extra = parse_aggregate_bool(value)?,
            "mfinalfunc_modify" => parsed.mfinalfunc_modify = parse_aggregate_final_modify(value)?,
            "sortop" => {
                return Err(ParseError::FeatureNotSupported(format!(
                    "{key} aggregate option is not supported"
                )));
            }
            _ => {
                return Err(ParseError::FeatureNotSupported(format!(
                    "unsupported CREATE AGGREGATE option: {key}"
                )));
            }
        }
    }
    Ok(parsed)
}

fn parse_aggregate_signature_kind(input: &str) -> Result<AggregateSignatureKind, ParseError> {
    let trimmed = input.trim();
    if trimmed == "*" {
        return Ok(AggregateSignatureKind::Star);
    }
    if trimmed.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "aggregate signature",
            actual: "()".into(),
        });
    }
    let (arg_sql, order_by_sql) =
        if let Some(order_by_idx) = find_next_top_level_keyword(trimmed, &["order by"]) {
            (
                trimmed[..order_by_idx].trim(),
                Some(consume_keyword(&trimmed[order_by_idx..], "order by").trim()),
            )
        } else {
            (trimmed, None)
        };
    let args = if arg_sql.is_empty() {
        Vec::new()
    } else {
        split_top_level_items(arg_sql, ',')?
            .into_iter()
            .map(|item| parse_aggregate_signature_arg(&item))
            .collect::<Result<Vec<_>, _>>()?
    };
    let order_by = if let Some(order_by_sql) = order_by_sql {
        split_top_level_items(order_by_sql, ',')?
            .into_iter()
            .map(|item| parse_aggregate_signature_arg(&item))
            .collect::<Result<Vec<_>, _>>()?
    } else {
        Vec::new()
    };
    Ok(AggregateSignatureKind::Args(AggregateSignature {
        args,
        order_by,
    }))
}

fn parse_aggregate_signature_arg(input: &str) -> Result<AggregateSignatureArg, ParseError> {
    let trimmed = input.trim();
    if trimmed.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "aggregate argument type",
            actual: input.into(),
        });
    }
    let variadic = keyword_at_start(trimmed, "variadic");
    let type_or_named = if variadic {
        consume_keyword(trimmed, "variadic").trim_start()
    } else {
        trimmed
    };
    let named_candidate = parse_sql_identifier(type_or_named)
        .ok()
        .and_then(|(name, rest)| {
            let rest = rest.trim();
            (!rest.is_empty()
                && !aggregate_type_phrase_starts_with_identifier(type_or_named)
                && parse_aggregate_arg_type(rest).is_ok())
            .then_some((name, rest))
        });
    let (name, type_sql) = if let Some((name, rest)) = named_candidate {
        (Some(name), rest)
    } else if let Ok(arg_type) = parse_aggregate_arg_type(type_or_named)
        && aggregate_arg_type_consumes_all(type_or_named, &arg_type)
    {
        (None, type_or_named)
    } else if let Ok((name, rest)) = parse_sql_identifier(type_or_named)
        && !rest.trim().is_empty()
    {
        (Some(name), rest.trim())
    } else {
        (None, type_or_named)
    };
    Ok(AggregateSignatureArg {
        name,
        arg_type: parse_aggregate_arg_type(type_sql)?,
        variadic,
    })
}

fn aggregate_type_phrase_starts_with_identifier(input: &str) -> bool {
    let lower = input.trim_start().to_ascii_lowercase();
    matches!(
        lower.as_str(),
        "double precision"
            | "character varying"
            | "bit varying"
            | "time with time zone"
            | "time without time zone"
            | "timestamp with time zone"
            | "timestamp without time zone"
    ) || lower.starts_with("time(")
        || lower.starts_with("time ")
        || lower.starts_with("timestamp(")
        || lower.starts_with("timestamp ")
        || lower.starts_with("character(")
        || lower.starts_with("character ")
        || lower.starts_with("interval ")
        || lower.starts_with("interval(")
}

fn aggregate_arg_type_consumes_all(input: &str, arg_type: &AggregateArgType) -> bool {
    match arg_type {
        AggregateArgType::AnyPseudo => parse_sql_identifier(input)
            .is_ok_and(|(ident, rest)| ident.eq_ignore_ascii_case("any") && rest.trim().is_empty()),
        AggregateArgType::Type(_) => parse_type_name(input).is_ok(),
    }
}

fn parse_aggregate_arg_type(input: &str) -> Result<AggregateArgType, ParseError> {
    let trimmed = input.trim();
    if let Ok((ident, rest)) = parse_sql_identifier(trimmed)
        && rest.trim().is_empty()
        && ident.eq_ignore_ascii_case("any")
    {
        return Ok(AggregateArgType::AnyPseudo);
    }
    parse_type_name(trimmed).map(AggregateArgType::Type)
}

fn parse_aggregate_signature_type_only_arg(
    input: &str,
) -> Result<AggregateSignatureArg, ParseError> {
    let arg = parse_aggregate_signature_arg(input)?;
    if arg.name.is_some() {
        return Err(ParseError::FeatureNotSupported(
            "named aggregate parameters are not supported in BASETYPE".into(),
        ));
    }
    Ok(arg)
}

fn parse_aggregate_signature_type_only(input: &str) -> Result<AggregateSignatureKind, ParseError> {
    let args = split_top_level_items(input, ',')?
        .into_iter()
        .map(|item| parse_aggregate_signature_type_only_arg(&item))
        .collect::<Result<Vec<_>, _>>()?;
    Ok(AggregateSignatureKind::Args(AggregateSignature {
        args,
        order_by: Vec::new(),
    }))
}

fn parse_legacy_aggregate_basetype(input: &str) -> Result<AggregateSignatureKind, ParseError> {
    let trimmed = input.trim();
    if let Some(len) = scan_string_literal_token_len(trimmed)
        && trimmed[len..].trim().is_empty()
    {
        let literal = decode_string_literal(&trimmed[..len])?;
        if literal.eq_ignore_ascii_case("any") {
            return Ok(AggregateSignatureKind::Star);
        }
    }
    if let Ok((ident, rest)) = parse_sql_identifier(trimmed)
        && rest.trim().is_empty()
        && ident.eq_ignore_ascii_case("any")
    {
        return Ok(AggregateSignatureKind::Star);
    }
    parse_aggregate_signature_type_only(trimmed)
}

fn parse_aggregate_proc_name(input: &str) -> Result<String, ParseError> {
    let (parts, rest) = parse_qualified_identifier_parts(input)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "function name",
            actual: input.into(),
        });
    }
    Ok(parts.join("."))
}

fn parse_aggregate_option_text(input: &str) -> Result<String, ParseError> {
    let trimmed = input.trim();
    if let Some(len) = scan_string_literal_token_len(trimmed)
        && trimmed[len..].trim().is_empty()
    {
        return decode_string_literal(&trimmed[..len]);
    }
    Ok(trimmed.to_string())
}

fn parse_aggregate_i32(input: &str) -> Result<i32, ParseError> {
    input
        .trim()
        .parse::<i32>()
        .map_err(|_| ParseError::InvalidNumeric(input.trim().into()))
}

fn parse_aggregate_bool(input: &str) -> Result<bool, ParseError> {
    let (value, rest) = parse_sql_identifier(input)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "boolean aggregate option",
            actual: input.into(),
        });
    }
    match value.as_str() {
        "true" | "on" | "yes" | "1" => Ok(true),
        "false" | "off" | "no" | "0" => Ok(false),
        _ => Err(ParseError::UnexpectedToken {
            expected: "boolean aggregate option",
            actual: value,
        }),
    }
}

fn parse_aggregate_final_modify(input: &str) -> Result<char, ParseError> {
    let (value, rest) = parse_sql_identifier(input)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "READ_ONLY, SHAREABLE, or READ_WRITE",
            actual: input.into(),
        });
    }
    match value.as_str() {
        "read_only" => Ok('r'),
        "shareable" => Ok('s'),
        "read_write" => Ok('w'),
        _ => Err(ParseError::UnexpectedToken {
            expected: "READ_ONLY, SHAREABLE, or READ_WRITE",
            actual: value,
        }),
    }
}

fn parse_aggregate_parallel(input: &str) -> Result<FunctionParallel, ParseError> {
    let (value, rest) = parse_sql_identifier(input)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "PARALLEL SAFE, RESTRICTED, or UNSAFE",
            actual: input.into(),
        });
    }
    match value.as_str() {
        "safe" => Ok(FunctionParallel::Safe),
        "restricted" => Ok(FunctionParallel::Restricted),
        "unsafe" => Ok(FunctionParallel::Unsafe),
        _ => Err(ParseError::UnexpectedToken {
            expected: "SAFE, RESTRICTED, or UNSAFE",
            actual: "parameter \"parallel\" must be SAFE, RESTRICTED, or UNSAFE".into(),
        }),
    }
}

fn build_create_trigger_statement(sql: &str) -> Result<CreateTriggerStatement, ParseError> {
    let lowered = sql.to_ascii_lowercase();
    if lowered.starts_with("create constraint trigger") {
        return Err(ParseError::FeatureNotSupported(
            "CONSTRAINT TRIGGER is not supported".into(),
        ));
    }
    let (prefix, replace_existing) = if lowered.starts_with("create or replace trigger") {
        ("create or replace trigger", true)
    } else {
        ("create trigger", false)
    };
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE TRIGGER name ...",
            actual: sql.into(),
        });
    };
    let (trigger_name, rest) = parse_sql_identifier(rest.trim_start())?;
    let rest = rest.trim_start();
    let (timing, rest) = if keyword_at_start(rest, "before") {
        (TriggerTiming::Before, consume_keyword(rest, "before"))
    } else if keyword_at_start(rest, "after") {
        (TriggerTiming::After, consume_keyword(rest, "after"))
    } else if keyword_at_start(rest, "instead") {
        let next = consume_keyword(rest, "instead").trim_start();
        if !keyword_at_start(next, "of") {
            return Err(ParseError::UnexpectedToken {
                expected: "OF",
                actual: next.into(),
            });
        }
        (TriggerTiming::Instead, consume_keyword(next, "of"))
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "BEFORE, AFTER, or INSTEAD OF",
            actual: rest.into(),
        });
    };
    let rest = rest.trim_start();
    let on_boundary =
        find_next_top_level_keyword(rest, &["on"]).ok_or_else(|| ParseError::UnexpectedToken {
            expected: "trigger event list followed by ON",
            actual: sql.into(),
        })?;
    let events = parse_trigger_events(rest[..on_boundary].trim())?;
    let mut rest = rest[on_boundary..].trim_start();
    rest = consume_keyword(rest, "on").trim_start();
    let ((schema_name, table_name), mut rest) = parse_schema_qualified_name(rest)?;

    let mut level = TriggerLevel::Statement;
    let mut referencing = Vec::new();
    let mut when_clause_sql = None;
    loop {
        rest = rest.trim_start();
        if rest.is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "EXECUTE FUNCTION",
                actual: sql.into(),
            });
        }
        if keyword_at_start(rest, "execute") {
            break;
        }
        if keyword_at_start(rest, "for") {
            let mut next = consume_keyword(rest, "for").trim_start();
            if keyword_at_start(next, "each") {
                next = consume_keyword(next, "each").trim_start();
            }
            if keyword_at_start(next, "row") {
                level = TriggerLevel::Row;
                rest = consume_keyword(next, "row");
                continue;
            }
            if keyword_at_start(next, "statement") {
                level = TriggerLevel::Statement;
                rest = consume_keyword(next, "statement");
                continue;
            }
            return Err(ParseError::UnexpectedToken {
                expected: "ROW or STATEMENT",
                actual: next.into(),
            });
        }
        if keyword_at_start(rest, "when") {
            let rest_after_when = consume_keyword(rest, "when");
            let (when_sql, next_rest) = take_parenthesized_segment(rest_after_when)?;
            when_clause_sql = Some(when_sql.trim().to_string());
            rest = next_rest;
            continue;
        }
        if keyword_at_start(rest, "referencing") {
            let (parsed, next_rest) = parse_trigger_referencing_clause(rest)?;
            referencing = parsed;
            rest = next_rest;
            continue;
        }
        return Err(ParseError::FeatureNotSupported(format!(
            "unsupported CREATE TRIGGER clause: {}",
            rest.split_whitespace().next().unwrap_or(rest)
        )));
    }

    rest = consume_keyword(rest.trim_start(), "execute").trim_start();
    if keyword_at_start(rest, "function") {
        rest = consume_keyword(rest, "function").trim_start();
    } else if keyword_at_start(rest, "procedure") {
        rest = consume_keyword(rest, "procedure").trim_start();
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "FUNCTION or PROCEDURE",
            actual: rest.into(),
        });
    }
    let ((function_schema_name, function_name), rest) = parse_qualified_sql_name(rest)?;
    let (args_sql, rest) = take_parenthesized_segment(rest)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of CREATE TRIGGER statement",
            actual: rest.trim().into(),
        });
    }

    Ok(CreateTriggerStatement {
        replace_existing,
        trigger_name,
        schema_name,
        table_name,
        timing,
        level,
        events,
        referencing,
        when_clause_sql,
        function_schema_name,
        function_name,
        func_args: parse_trigger_function_args(&args_sql)?,
    })
}

fn build_alter_table_trigger_state_statement(
    sql: &str,
) -> Result<AlterTableTriggerStateStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "alter").trim_start();
    rest = consume_keyword(rest, "table").trim_start();

    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        rest = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(rest, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "EXISTS",
                actual: rest.into(),
            });
        }
        rest = consume_keyword(rest, "exists").trim_start();
        if_exists = true;
    }

    let mut only = false;
    if keyword_at_start(rest, "only") {
        rest = consume_keyword(rest, "only").trim_start();
        only = true;
    }

    let ((schema_name, table_name), mut rest) = parse_schema_qualified_name(rest)?;
    let table_name = match schema_name {
        Some(schema_name) => format!("{schema_name}.{table_name}"),
        None => table_name,
    };

    let mode = if keyword_at_start(rest.trim_start(), "enable") {
        rest = consume_keyword(rest.trim_start(), "enable").trim_start();
        if keyword_at_start(rest, "always") {
            rest = consume_keyword(rest, "always").trim_start();
            AlterTableTriggerMode::EnableAlways
        } else if keyword_at_start(rest, "replica") {
            rest = consume_keyword(rest, "replica").trim_start();
            AlterTableTriggerMode::EnableReplica
        } else {
            AlterTableTriggerMode::EnableOrigin
        }
    } else if keyword_at_start(rest.trim_start(), "disable") {
        rest = consume_keyword(rest.trim_start(), "disable").trim_start();
        AlterTableTriggerMode::Disable
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "ENABLE or DISABLE",
            actual: rest.trim_start().into(),
        });
    };

    if !keyword_at_start(rest, "trigger") {
        return Err(ParseError::UnexpectedToken {
            expected: "TRIGGER",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "trigger").trim_start();

    let (target, rest) = if keyword_at_start(rest, "all") {
        if matches!(
            mode,
            AlterTableTriggerMode::EnableAlways | AlterTableTriggerMode::EnableReplica
        ) {
            return Err(ParseError::UnexpectedToken {
                expected: "trigger name",
                actual: "all".into(),
            });
        }
        (AlterTableTriggerTarget::All, consume_keyword(rest, "all"))
    } else if keyword_at_start(rest, "user") {
        if matches!(
            mode,
            AlterTableTriggerMode::EnableAlways | AlterTableTriggerMode::EnableReplica
        ) {
            return Err(ParseError::UnexpectedToken {
                expected: "trigger name",
                actual: "user".into(),
            });
        }
        (AlterTableTriggerTarget::User, consume_keyword(rest, "user"))
    } else {
        let (name, rest) = parse_sql_identifier(rest)?;
        (AlterTableTriggerTarget::Named(name), rest)
    };

    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of ALTER TABLE trigger statement",
            actual: rest.trim().into(),
        });
    }

    Ok(AlterTableTriggerStateStatement {
        if_exists,
        only,
        table_name,
        target,
        mode,
    })
}

fn build_alter_trigger_rename_statement(
    sql: &str,
) -> Result<AlterTriggerRenameStatement, ParseError> {
    let mut rest = consume_keyword(sql.trim_start(), "alter").trim_start();
    rest = consume_keyword(rest, "trigger").trim_start();
    let (trigger_name, next) = parse_sql_identifier(rest)?;
    rest = next.trim_start();
    if !keyword_at_start(rest, "on") {
        return Err(ParseError::UnexpectedToken {
            expected: "ON",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "on").trim_start();
    let ((schema_name, table_name), next) = parse_schema_qualified_name(rest)?;
    rest = next.trim_start();
    if !keyword_at_start(rest, "rename") {
        return Err(ParseError::UnexpectedToken {
            expected: "RENAME",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "rename").trim_start();
    if !keyword_at_start(rest, "to") {
        return Err(ParseError::UnexpectedToken {
            expected: "TO",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "to").trim_start();
    let (new_trigger_name, rest) = parse_sql_identifier(rest)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of ALTER TRIGGER statement",
            actual: rest.trim().into(),
        });
    }
    Ok(AlterTriggerRenameStatement {
        trigger_name,
        schema_name,
        table_name,
        new_trigger_name,
    })
}

fn parse_trigger_events(input: &str) -> Result<Vec<TriggerEventSpec>, ParseError> {
    let mut rest = input.trim();
    let mut events = Vec::new();
    let mut seen = BTreeSet::new();
    while !rest.is_empty() {
        let (event, update_columns, next_rest) = if keyword_at_start(rest, "insert") {
            let next_rest = consume_keyword(rest, "insert");
            if keyword_at_start(next_rest.trim_start(), "of") {
                return Err(ParseError::UnexpectedToken {
                    expected: "trigger event list",
                    actual: "syntax error at or near \"OF\"".into(),
                });
            }
            (TriggerEvent::Insert, Vec::new(), next_rest)
        } else if keyword_at_start(rest, "update") {
            let mut next_rest = consume_keyword(rest, "update").trim_start();
            let update_columns = if keyword_at_start(next_rest, "of") {
                let rest_after_of = consume_keyword(next_rest, "of").trim_start();
                let boundary = find_next_top_level_keyword(rest_after_of, &["or"])
                    .unwrap_or(rest_after_of.len());
                let columns_sql = rest_after_of[..boundary].trim();
                if columns_sql.is_empty() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "column list after UPDATE OF",
                        actual: input.into(),
                    });
                }
                next_rest = &rest_after_of[boundary..];
                parse_identifier_list(columns_sql)?
            } else {
                Vec::new()
            };
            (TriggerEvent::Update, update_columns, next_rest)
        } else if keyword_at_start(rest, "delete") {
            (
                TriggerEvent::Delete,
                Vec::new(),
                consume_keyword(rest, "delete"),
            )
        } else if keyword_at_start(rest, "truncate") {
            (
                TriggerEvent::Truncate,
                Vec::new(),
                consume_keyword(rest, "truncate"),
            )
        } else {
            return Err(ParseError::UnexpectedToken {
                expected: "INSERT, UPDATE, DELETE, or TRUNCATE",
                actual: rest.into(),
            });
        };

        if !seen.insert(event) {
            return Err(ParseError::DetailedError {
                message: "duplicate trigger events specified at or near \"ON\"".into(),
                detail: None,
                hint: None,
                sqlstate: "42601",
            });
        }

        events.push(TriggerEventSpec {
            event,
            update_columns,
        });
        rest = next_rest.trim_start();
        if keyword_at_start(rest, "or") {
            rest = consume_keyword(rest, "or").trim_start();
            continue;
        }
        if !rest.is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "OR or end of trigger event list",
                actual: rest.into(),
            });
        }
    }
    if events.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "trigger event",
            actual: input.into(),
        });
    }
    Ok(events)
}

fn parse_trigger_referencing_clause(
    input: &str,
) -> Result<(Vec<TriggerReferencingSpec>, &str), ParseError> {
    let mut rest = consume_keyword(input.trim_start(), "referencing");
    let mut specs = Vec::new();
    loop {
        rest = rest.trim_start();
        let (is_new, next) = if keyword_at_start(rest, "new") {
            (true, consume_keyword(rest, "new"))
        } else if keyword_at_start(rest, "old") {
            (false, consume_keyword(rest, "old"))
        } else {
            break;
        };
        let next = next.trim_start();
        let (is_table, next) = if keyword_at_start(next, "table") {
            (true, consume_keyword(next, "table"))
        } else if keyword_at_start(next, "row") {
            (false, consume_keyword(next, "row"))
        } else {
            return Err(ParseError::UnexpectedToken {
                expected: "TABLE or ROW",
                actual: next.into(),
            });
        };
        let next = next.trim_start();
        if !keyword_at_start(next, "as") {
            return Err(ParseError::UnexpectedToken {
                expected: "AS",
                actual: next.into(),
            });
        }
        let (name, next) = parse_sql_identifier(consume_keyword(next, "as").trim_start())?;
        specs.push(TriggerReferencingSpec {
            is_new,
            is_table,
            name,
        });
        rest = next;
    }
    if specs.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "OLD/NEW TABLE or ROW",
            actual: rest.trim_start().into(),
        });
    }
    Ok((specs, rest))
}

fn parse_trigger_function_args(input: &str) -> Result<Vec<String>, ParseError> {
    let items = split_top_level_items(input, ',')?;
    if items.len() == 1 && items[0].trim().is_empty() {
        return Ok(Vec::new());
    }
    items
        .into_iter()
        .filter(|item| !item.trim().is_empty())
        .map(|item| {
            let trimmed = item.trim();
            if let Some(token_len) = scan_string_literal_token_len(trimmed) {
                if token_len == trimmed.len() {
                    return decode_string_literal(trimmed);
                }
            }
            if let Ok((ident, rest)) = parse_sql_identifier(trimmed)
                && rest.trim().is_empty()
            {
                return Ok(ident);
            }
            Ok(trimmed.to_string())
        })
        .collect()
}

fn build_drop_trigger_statement(sql: &str) -> Result<DropTriggerStatement, ParseError> {
    let prefix = "drop trigger";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP TRIGGER [IF EXISTS] name ON table",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        rest = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(rest, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF EXISTS",
                actual: sql.into(),
            });
        }
        rest = consume_keyword(rest, "exists").trim_start();
        if_exists = true;
    }
    let (trigger_name, rest_after_name) = parse_sql_identifier(rest)?;
    let mut rest = rest_after_name.trim_start();
    if !keyword_at_start(rest, "on") {
        return Err(ParseError::UnexpectedToken {
            expected: "ON",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "on").trim_start();
    let ((schema_name, table_name), rest) = parse_schema_qualified_name(rest)?;
    let rest = rest.trim_start();
    let cascade = if rest.is_empty() {
        false
    } else if keyword_at_start(rest, "cascade") {
        if !consume_keyword(rest, "cascade").trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: rest.into(),
            });
        }
        true
    } else if keyword_at_start(rest, "restrict") {
        if !consume_keyword(rest, "restrict").trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: rest.into(),
            });
        }
        false
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "CASCADE, RESTRICT, or end of statement",
            actual: rest.into(),
        });
    };
    Ok(DropTriggerStatement {
        if_exists,
        trigger_name,
        schema_name,
        table_name,
        cascade,
    })
}

fn build_create_policy_statement(sql: &str) -> Result<CreatePolicyStatement, ParseError> {
    let prefix = "create policy";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE POLICY name ON table",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let (policy_name, after_name) = parse_sql_identifier(rest)?;
    rest = after_name.trim_start();
    if !keyword_at_start(rest, "on") {
        return Err(ParseError::UnexpectedToken {
            expected: "ON",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "on").trim_start();
    let ((schema_name, table_name), after_table) = parse_schema_qualified_name(rest)?;
    let table_name = qualified_policy_table_name(schema_name, table_name);
    rest = after_table.trim_start();

    let mut permissive = true;
    let mut command = PolicyCommand::All;
    let mut role_names = vec!["public".to_string()];
    let mut using_expr = None;
    let mut using_sql = None;
    let mut with_check_expr = None;
    let mut with_check_sql = None;

    while !rest.is_empty() {
        if keyword_at_start(rest, "as") {
            rest = consume_keyword(rest, "as").trim_start();
            if keyword_at_start(rest, "permissive") {
                permissive = true;
                rest = consume_keyword(rest, "permissive").trim_start();
                continue;
            }
            if keyword_at_start(rest, "restrictive") {
                permissive = false;
                rest = consume_keyword(rest, "restrictive").trim_start();
                continue;
            }
            if let Ok((policy_option, _)) = parse_sql_identifier(rest) {
                return Err(ParseError::DetailedError {
                    message: format!("unrecognized row security option \"{policy_option}\""),
                    detail: None,
                    hint: Some(
                        "Only PERMISSIVE or RESTRICTIVE policies are supported currently.".into(),
                    ),
                    sqlstate: "42601",
                }
                .with_position(sql_position_from_byte_offset(
                    sql,
                    slice_byte_offset(sql, rest),
                )));
            }
            return Err(ParseError::UnexpectedToken {
                expected: "PERMISSIVE or RESTRICTIVE",
                actual: rest.into(),
            });
        }
        if keyword_at_start(rest, "for") {
            rest = consume_keyword(rest, "for").trim_start();
            let (parsed_command, next_rest) = parse_policy_command(rest)?;
            command = parsed_command;
            rest = next_rest.trim_start();
            continue;
        }
        if keyword_at_start(rest, "to") {
            rest = consume_keyword(rest, "to").trim_start();
            let boundary =
                find_next_top_level_keyword(rest, &["using", "with"]).unwrap_or(rest.len());
            role_names = parse_policy_role_list(&rest[..boundary])?;
            rest = rest[boundary..].trim_start();
            continue;
        }
        if keyword_at_start(rest, "using") {
            rest = consume_keyword(rest, "using");
            let (sql, next_rest) = take_parenthesized_segment(rest)?;
            using_expr = Some(parse_expr(&sql)?);
            using_sql = Some(sql.trim().to_string());
            rest = next_rest.trim_start();
            continue;
        }
        if keyword_at_start(rest, "with") {
            rest = consume_keyword(rest, "with").trim_start();
            if !keyword_at_start(rest, "check") {
                return Err(ParseError::UnexpectedToken {
                    expected: "CHECK",
                    actual: rest.into(),
                });
            }
            rest = consume_keyword(rest, "check");
            let (sql, next_rest) = take_parenthesized_segment(rest)?;
            with_check_expr = Some(parse_expr(&sql)?);
            with_check_sql = Some(sql.trim().to_string());
            rest = next_rest.trim_start();
            continue;
        }
        return Err(ParseError::UnexpectedToken {
            expected: "AS, FOR, TO, USING, or WITH CHECK",
            actual: rest.into(),
        });
    }

    Ok(CreatePolicyStatement {
        policy_name,
        table_name,
        permissive,
        command,
        role_names,
        using_expr,
        using_sql,
        with_check_expr,
        with_check_sql,
    })
}

fn build_alter_policy_statement(sql: &str) -> Result<AlterPolicyStatement, ParseError> {
    let prefix = "alter policy";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "ALTER POLICY name ON table",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let (policy_name, after_name) = parse_sql_identifier(rest)?;
    rest = after_name.trim_start();
    if !keyword_at_start(rest, "on") {
        return Err(ParseError::UnexpectedToken {
            expected: "ON",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "on").trim_start();
    let ((schema_name, table_name), after_table) = parse_schema_qualified_name(rest)?;
    let table_name = qualified_policy_table_name(schema_name, table_name);
    rest = after_table.trim_start();

    if keyword_at_start(rest, "rename") {
        rest = consume_keyword(rest, "rename").trim_start();
        if !keyword_at_start(rest, "to") {
            return Err(ParseError::UnexpectedToken {
                expected: "TO",
                actual: rest.into(),
            });
        }
        rest = consume_keyword(rest, "to").trim_start();
        let (new_name, remainder) = parse_sql_identifier(rest)?;
        if !remainder.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: remainder.trim().into(),
            });
        }
        return Ok(AlterPolicyStatement {
            policy_name,
            table_name,
            action: AlterPolicyAction::Rename { new_name },
        });
    }

    let mut role_names = None;
    let mut using_expr = None;
    let mut using_sql = None;
    let mut with_check_expr = None;
    let mut with_check_sql = None;
    let mut saw_clause = false;

    while !rest.is_empty() {
        if keyword_at_start(rest, "to") {
            rest = consume_keyword(rest, "to").trim_start();
            let boundary =
                find_next_top_level_keyword(rest, &["using", "with"]).unwrap_or(rest.len());
            role_names = Some(parse_policy_role_list(&rest[..boundary])?);
            rest = rest[boundary..].trim_start();
            saw_clause = true;
            continue;
        }
        if keyword_at_start(rest, "using") {
            rest = consume_keyword(rest, "using");
            let (sql, next_rest) = take_parenthesized_segment(rest)?;
            using_expr = Some(parse_expr(&sql)?);
            using_sql = Some(sql.trim().to_string());
            rest = next_rest.trim_start();
            saw_clause = true;
            continue;
        }
        if keyword_at_start(rest, "with") {
            rest = consume_keyword(rest, "with").trim_start();
            if !keyword_at_start(rest, "check") {
                return Err(ParseError::UnexpectedToken {
                    expected: "CHECK",
                    actual: rest.into(),
                });
            }
            rest = consume_keyword(rest, "check");
            let (sql, next_rest) = take_parenthesized_segment(rest)?;
            with_check_expr = Some(parse_expr(&sql)?);
            with_check_sql = Some(sql.trim().to_string());
            rest = next_rest.trim_start();
            saw_clause = true;
            continue;
        }
        return Err(ParseError::UnexpectedToken {
            expected: "RENAME, TO, USING, or WITH CHECK",
            actual: rest.into(),
        });
    }

    if !saw_clause {
        return Err(ParseError::UnexpectedToken {
            expected: "policy alteration clause",
            actual: sql.into(),
        });
    }

    Ok(AlterPolicyStatement {
        policy_name,
        table_name,
        action: AlterPolicyAction::Update {
            role_names,
            using_expr,
            using_sql,
            with_check_expr,
            with_check_sql,
        },
    })
}

fn build_drop_policy_statement(sql: &str) -> Result<DropPolicyStatement, ParseError> {
    let prefix = "drop policy";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP POLICY [IF EXISTS] name ON table",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if keyword_at_start(rest, "if") {
        rest = consume_keyword(rest, "if").trim_start();
        if !keyword_at_start(rest, "exists") {
            return Err(ParseError::UnexpectedToken {
                expected: "IF EXISTS",
                actual: sql.into(),
            });
        }
        rest = consume_keyword(rest, "exists").trim_start();
        if_exists = true;
    }
    let (policy_name, after_name) = parse_sql_identifier(rest)?;
    rest = after_name.trim_start();
    if !keyword_at_start(rest, "on") {
        return Err(ParseError::UnexpectedToken {
            expected: "ON",
            actual: rest.into(),
        });
    }
    rest = consume_keyword(rest, "on").trim_start();
    let ((schema_name, table_name), remainder) = parse_schema_qualified_name(rest)?;
    let table_name = qualified_policy_table_name(schema_name, table_name);
    if !remainder.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of statement",
            actual: remainder.trim().into(),
        });
    }
    Ok(DropPolicyStatement {
        if_exists,
        policy_name,
        table_name,
    })
}

fn qualified_policy_table_name(schema_name: Option<String>, table_name: String) -> String {
    schema_name
        .map(|schema| format!("{schema}.{table_name}"))
        .unwrap_or(table_name)
}

fn parse_policy_command(input: &str) -> Result<(PolicyCommand, &str), ParseError> {
    if keyword_at_start(input, "all") {
        return Ok((PolicyCommand::All, consume_keyword(input, "all")));
    }
    if keyword_at_start(input, "select") {
        return Ok((PolicyCommand::Select, consume_keyword(input, "select")));
    }
    if keyword_at_start(input, "insert") {
        return Ok((PolicyCommand::Insert, consume_keyword(input, "insert")));
    }
    if keyword_at_start(input, "update") {
        return Ok((PolicyCommand::Update, consume_keyword(input, "update")));
    }
    if keyword_at_start(input, "delete") {
        return Ok((PolicyCommand::Delete, consume_keyword(input, "delete")));
    }
    Err(ParseError::UnexpectedToken {
        expected: "ALL, SELECT, INSERT, UPDATE, or DELETE",
        actual: input.into(),
    })
}

fn parse_policy_role_list(input: &str) -> Result<Vec<String>, ParseError> {
    let items = split_top_level_items(input.trim(), ',')?;
    let mut out = Vec::new();
    for item in items {
        let trimmed = item.trim();
        if trimmed.is_empty() {
            continue;
        }
        let (role_name, rest) = parse_sql_identifier(trimmed)?;
        if !rest.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "role name",
                actual: trimmed.into(),
            });
        }
        out.push(role_name);
    }
    if out.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "role name",
            actual: input.into(),
        });
    }
    Ok(out)
}

fn parse_qualified_sql_name(input: &str) -> Result<((Option<String>, String), &str), ParseError> {
    let (first, mut rest) = parse_sql_identifier(input)?;
    rest = rest.trim_start();
    if let Some(after_dot) = rest.strip_prefix('.') {
        let (second, rest) = parse_sql_identifier(after_dot.trim_start())?;
        return Ok(((Some(first), second), rest));
    }
    Ok(((None, first), rest))
}

fn build_create_type_statement(sql: &str) -> Result<CreateTypeStatement, ParseError> {
    let prefix = "create type";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE TYPE name AS (...)",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, type_name), rest) = parse_qualified_sql_name(rest)?;
    let rest = rest.trim_start();
    if rest.is_empty() {
        return Ok(CreateTypeStatement::Shell(CreateShellTypeStatement {
            schema_name,
            type_name,
        }));
    }
    if rest.starts_with('(') {
        let (option_list, rest) = take_parenthesized_segment(rest)?;
        if !rest.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: rest.trim().into(),
            });
        }
        return Ok(CreateTypeStatement::Base(CreateBaseTypeStatement {
            schema_name,
            type_name,
            options: parse_create_base_type_options(&option_list)?,
        }));
    }
    if !keyword_at_start(rest, "as") {
        return Err(ParseError::FeatureNotSupported(
            "unsupported CREATE TYPE form".into(),
        ));
    }
    let rest = consume_keyword(rest, "as").trim_start();
    if keyword_at_start(rest, "enum") {
        let rest = consume_keyword(rest, "enum").trim_start();
        let (label_list, rest) = take_parenthesized_segment(rest)?;
        if !rest.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: rest.trim().into(),
            });
        }
        return Ok(CreateTypeStatement::Enum(CreateEnumTypeStatement {
            schema_name,
            type_name,
            labels: parse_create_enum_labels(&label_list)?,
        }));
    }
    if keyword_at_start(rest, "range") {
        let rest = consume_keyword(rest, "range").trim_start();
        let (option_list, rest) = take_parenthesized_segment(rest)?;
        if !rest.trim().is_empty() {
            return Err(ParseError::UnexpectedToken {
                expected: "end of statement",
                actual: rest.trim().into(),
            });
        }
        return Ok(CreateTypeStatement::Range(
            parse_create_range_type_statement(schema_name, type_name, &option_list)?,
        ));
    }
    let (attr_list, rest) = take_parenthesized_segment(rest)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of statement",
            actual: rest.trim().into(),
        });
    }
    let attributes = parse_create_type_attributes(&attr_list)?;
    Ok(CreateTypeStatement::Composite(
        CreateCompositeTypeStatement {
            schema_name,
            type_name,
            attributes,
        },
    ))
}

fn build_create_cast_statement(sql: &str) -> Result<CreateCastStatement, ParseError> {
    let prefix = "create cast";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE CAST (source AS target)",
            actual: sql.into(),
        });
    };
    let (type_pair, rest) = take_parenthesized_segment(rest.trim_start())?;
    let (source_type, target_type) = parse_cast_type_pair(&type_pair)?;
    let rest = rest.trim_start();
    let (method, rest) = if keyword_at_start(rest, "with") {
        let rest = consume_keyword(rest, "with").trim_start();
        if keyword_at_start(rest, "function") {
            let rest = consume_keyword(rest, "function").trim_start();
            let ((schema_name, function_name), rest) = parse_qualified_sql_name(rest)?;
            let (args_sql, rest) = take_parenthesized_segment(rest.trim_start())?;
            let arg_types = parse_cast_function_arg_types(&args_sql)?;
            (
                CreateCastMethod::Function {
                    schema_name,
                    function_name,
                    arg_types,
                },
                rest,
            )
        } else if keyword_at_start(rest, "inout") {
            (CreateCastMethod::InOut, consume_keyword(rest, "inout"))
        } else {
            return Err(ParseError::UnexpectedToken {
                expected: "FUNCTION or INOUT",
                actual: rest.into(),
            });
        }
    } else if let Some(rest) = consume_keywords(rest, &["without", "function"]) {
        (CreateCastMethod::WithoutFunction, rest)
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "WITH FUNCTION, WITHOUT FUNCTION, or WITH INOUT",
            actual: rest.into(),
        });
    };
    let (context, rest) = parse_cast_context(rest)?;
    if !rest.trim().is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "end of CREATE CAST statement",
            actual: rest.trim().into(),
        });
    }
    Ok(CreateCastStatement {
        source_type,
        target_type,
        method,
        context,
    })
}

fn build_drop_cast_statement(sql: &str) -> Result<DropCastStatement, ParseError> {
    let prefix = "drop cast";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "DROP CAST (source AS target)",
            actual: sql.into(),
        });
    };
    let mut rest = rest.trim_start();
    let mut if_exists = false;
    if let Some(next) = consume_keywords(rest, &["if", "exists"]) {
        if_exists = true;
        rest = next.trim_start();
    }
    let (type_pair, rest) = take_parenthesized_segment(rest)?;
    let (source_type, target_type) = parse_cast_type_pair(&type_pair)?;
    let suffix = rest.trim();
    let cascade = if suffix.is_empty() || keyword_at_start(suffix, "restrict") {
        false
    } else if keyword_at_start(suffix, "cascade") {
        true
    } else {
        return Err(ParseError::UnexpectedToken {
            expected: "CASCADE, RESTRICT, or end of statement",
            actual: suffix.into(),
        });
    };
    Ok(DropCastStatement {
        if_exists,
        source_type,
        target_type,
        cascade,
    })
}

fn parse_cast_type_pair(input: &str) -> Result<(RawTypeName, RawTypeName), ParseError> {
    let as_index =
        find_next_top_level_keyword(input, &["as"]).ok_or(ParseError::UnexpectedToken {
            expected: "source type AS target type",
            actual: input.into(),
        })?;
    let source_sql = input[..as_index].trim();
    let target_sql = input[as_index + "as".len()..].trim();
    if source_sql.is_empty() || target_sql.is_empty() {
        return Err(ParseError::UnexpectedToken {
            expected: "source type AS target type",
            actual: input.into(),
        });
    }
    Ok((parse_type_name(source_sql)?, parse_type_name(target_sql)?))
}

fn parse_cast_function_arg_types(input: &str) -> Result<Vec<RawTypeName>, ParseError> {
    split_top_level_items(input, ',')?
        .into_iter()
        .filter(|item| !item.trim().is_empty())
        .map(|item| parse_type_name(item.trim()))
        .collect()
}

fn parse_cast_context(input: &str) -> Result<(CastContext, &str), ParseError> {
    let rest = input.trim_start();
    if let Some(rest) = consume_keywords(rest, &["as", "implicit"]) {
        return Ok((CastContext::Implicit, rest));
    }
    if let Some(rest) = consume_keywords(rest, &["as", "assignment"]) {
        return Ok((CastContext::Assignment, rest));
    }
    Ok((CastContext::Explicit, rest))
}

fn build_create_operator_class_statement(
    sql: &str,
) -> Result<CreateOperatorClassStatement, ParseError> {
    let prefix = "create operator class";
    let Some(rest) = sql.get(prefix.len()..) else {
        return Err(ParseError::UnexpectedToken {
            expected: "CREATE OPERATOR CLASS name FOR TYPE ... USING ... AS ...",
            actual: sql.into(),
        });
    };
    let rest = rest.trim_start();
    let ((schema_name, opclass_name), rest) = parse_qualified_sql_name(rest)?;
    let rest = rest.trim_start();
    if !keyword_at_start(rest, "for") {
        return Err(ParseError::UnexpectedToken {
            expected: "FOR TYPE",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "for").trim_start();
    if !keyword_at_start(rest, "type") {
        return Err(ParseError::UnexpectedToken {
            expected: "TYPE",
            actual: rest.into(),
        });
    }
    let rest = consume_keyword(rest, "type").trim_start();
    let data_type_end = keyword_boundary(rest, "using").ok_or(ParseError::UnexpectedToken {
        expected: "USING access method",
        actual: rest.into(),
    })?;
    let data_type = parse_type_name(rest[..data_type_end].trim())?;
    let rest = rest[data_type_end..].trim_start();
    let rest = consume_keyword(rest, "using").trim_start();
    let (access_method, rest) = parse_sql_identifier(rest)?;
    let rest = rest.trim_start();
    let mut is_default = false;
    let rest = if keyword_at_start(rest, "default") {
        is_default = true;
        consume_keyword(rest, "default").trim_start()
    } else {
        rest
    };
    if !keyword_at_start(rest, "as") {
        return Err(ParseError::UnexpectedToken {
            expected: "AS",
            actual: rest.into(),
        });
    }
    let items = parse_create_operator_class_items(consume_keyword(rest, "as").trim_start())?;
    Ok(CreateOperatorClassStatement {
        schema_name,
        opclass_name,
        data_type,
        access_method,
        is_default,
        items,
    })
}

