fn build_qualified_identifier_string(pair: Pair<'_, Rule>) -> String {
    let (schema, name) = build_relation_name(pair);
    schema
        .map(|schema| format!("{schema}.{name}"))
        .unwrap_or(name)
}

fn build_qualified_identifier_list(pair: Pair<'_, Rule>) -> Vec<String> {
    pair.into_inner()
        .filter(|part| part.as_rule() == Rule::qualified_identifier)
        .map(build_qualified_identifier_string)
        .collect()
}

fn build_lock_table(pair: Pair<'_, Rule>) -> Result<LockTableStatement, ParseError> {
    let mut table_names = Vec::new();
    let mut mode = LockTableMode::AccessExclusive;
    let mut nowait = false;

    // :HACK: PostgreSQL's LockStmt carries RangeVar details for ONLY,
    // inheritance recursion, trailing '*', and view recursion. This raw node
    // keeps just direct relation names until those semantics are modeled.
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::qualified_ident_list => {
                table_names.extend(build_qualified_identifier_list(part));
            }
            Rule::lock_table_mode_clause => mode = build_lock_table_mode_clause(part)?,
            Rule::lock_nowait_clause => nowait = true,
            _ => {}
        }
    }
    if table_names.is_empty() {
        return Err(ParseError::UnexpectedEof);
    }
    Ok(LockTableStatement {
        table_names,
        mode,
        nowait,
    })
}

fn build_lock_table_mode_clause(pair: Pair<'_, Rule>) -> Result<LockTableMode, ParseError> {
    let mode = pair
        .into_inner()
        .find(|part| part.as_rule() == Rule::lock_table_mode)
        .ok_or(ParseError::UnexpectedEof)?;
    build_lock_table_mode(mode.as_str())
}

fn build_lock_table_mode(mode_sql: &str) -> Result<LockTableMode, ParseError> {
    let normalized = mode_sql
        .split_ascii_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .to_ascii_lowercase();
    match normalized.as_str() {
        "access share" => Ok(LockTableMode::AccessShare),
        "row share" => Ok(LockTableMode::RowShare),
        "row exclusive" => Ok(LockTableMode::RowExclusive),
        "share update exclusive" => Ok(LockTableMode::ShareUpdateExclusive),
        "share" => Ok(LockTableMode::Share),
        "share row exclusive" => Ok(LockTableMode::ShareRowExclusive),
        "exclusive" => Ok(LockTableMode::Exclusive),
        "access exclusive" => Ok(LockTableMode::AccessExclusive),
        _ => Err(ParseError::UnexpectedToken {
            expected: "LOCK TABLE mode",
            actual: mode_sql.into(),
        }),
    }
}

fn build_truncate_table(pair: Pair<'_, Rule>) -> Result<TruncateTableStatement, ParseError> {
    let table_names = pair
        .into_inner()
        .find(|part| part.as_rule() == Rule::ident_list)
        .map(|part| part.into_inner().map(build_identifier).collect::<Vec<_>>())
        .ok_or(ParseError::UnexpectedEof)?;
    Ok(TruncateTableStatement { table_names })
}

fn build_refresh_materialized_view(
    pair: Pair<'_, Rule>,
) -> Result<RefreshMaterializedViewStatement, ParseError> {
    let raw = pair.as_str().to_ascii_lowercase();
    let concurrently = raw
        .split_ascii_whitespace()
        .any(|word| word == "concurrently");
    let mut relation_name = None;
    let mut skip_data = false;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::identifier => relation_name = Some(build_identifier(part)),
            Rule::matview_data_clause => {
                skip_data = part.as_str().to_ascii_lowercase().contains("no");
            }
            _ => {}
        }
    }
    Ok(RefreshMaterializedViewStatement {
        relation_name: relation_name.ok_or(ParseError::UnexpectedEof)?,
        concurrently,
        skip_data,
    })
}

fn build_vacuum(pair: Pair<'_, Rule>) -> Result<VacuumStatement, ParseError> {
    let mut targets = Vec::new();
    let mut analyze = false;
    let mut full = false;
    let mut freeze = false;
    let mut verbose = false;
    let mut skip_locked = false;
    let mut buffer_usage_limit = None;
    let mut disable_page_skipping = false;
    let mut index_cleanup = None;
    let mut truncate = None;
    let mut parallel = None;
    let mut parallel_specified = false;
    let mut process_main = None;
    let mut process_toast = None;
    let mut skip_database_stats = false;
    let mut only_database_stats = false;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::kw_analyze => analyze = true,
            Rule::vacuum_legacy_option => {
                let opt = part.into_inner().next().ok_or(ParseError::UnexpectedEof)?;
                match opt.as_rule() {
                    Rule::vacuum_legacy_analyze_option => analyze = true,
                    Rule::vacuum_legacy_full_option => full = true,
                    Rule::vacuum_legacy_freeze_option => freeze = true,
                    Rule::vacuum_legacy_verbose_option => verbose = true,
                    _ => {}
                }
            }
            Rule::vacuum_option_block => {
                for opt in part.into_inner() {
                    let opt = if opt.as_rule() == Rule::vacuum_option {
                        opt.into_inner().next().ok_or(ParseError::UnexpectedEof)?
                    } else {
                        opt
                    };
                    match opt.as_rule() {
                        Rule::vacuum_analyze_option => analyze = parse_option_bool(opt)?,
                        Rule::vacuum_full_option => full = parse_option_bool(opt)?,
                        Rule::vacuum_freeze_option => freeze = parse_option_bool(opt)?,
                        Rule::vacuum_disable_page_skipping_option => {
                            disable_page_skipping = parse_option_bool(opt)?
                        }
                        Rule::vacuum_index_cleanup_option => {
                            index_cleanup = parse_optional_option_scalar(opt)?
                        }
                        Rule::vacuum_truncate_option => truncate = Some(parse_option_bool(opt)?),
                        Rule::vacuum_parallel_option => {
                            parallel_specified = true;
                            parallel = parse_optional_option_scalar(opt)?
                        }
                        Rule::vacuum_process_main_option => {
                            process_main = Some(parse_option_bool(opt)?)
                        }
                        Rule::vacuum_process_toast_option => {
                            process_toast = Some(parse_option_bool(opt)?)
                        }
                        Rule::vacuum_skip_database_stats_option => {
                            skip_database_stats = parse_option_bool(opt)?
                        }
                        Rule::vacuum_only_database_stats_option => {
                            only_database_stats = parse_option_bool(opt)?
                        }
                        Rule::analyze_verbose_option => verbose = parse_option_bool(opt)?,
                        Rule::analyze_skip_locked_option => skip_locked = parse_option_bool(opt)?,
                        Rule::analyze_buffer_usage_limit_option => {
                            buffer_usage_limit = Some(parse_option_scalar(opt)?)
                        }
                        _ => {}
                    }
                }
            }
            Rule::vacuum_bare_option_list => {
                for opt in part.into_inner() {
                    let text = opt.as_str().to_ascii_lowercase();
                    match text.as_str() {
                        "analyze" => analyze = true,
                        "full" => full = true,
                        "verbose" => verbose = true,
                        _ => {}
                    }
                }
            }
            Rule::maintenance_target_list => targets = build_maintenance_target_list(part)?,
            _ => {}
        }
    }
    Ok(VacuumStatement {
        targets,
        analyze,
        full,
        freeze,
        verbose,
        skip_locked,
        buffer_usage_limit,
        disable_page_skipping,
        index_cleanup,
        truncate,
        parallel,
        parallel_specified,
        process_main,
        process_toast,
        skip_database_stats,
        only_database_stats,
    })
}

fn parse_optional_option_scalar(pair: Pair<'_, Rule>) -> Result<Option<String>, ParseError> {
    match pair
        .into_inner()
        .find(|part| part.as_rule() == Rule::option_scalar_value)
    {
        Some(scalar) => build_option_scalar_value(scalar).map(Some),
        None => Ok(None),
    }
}

fn build_maintenance_target_list(
    pair: Pair<'_, Rule>,
) -> Result<Vec<MaintenanceTarget>, ParseError> {
    pair.into_inner()
        .filter(|part| part.as_rule() == Rule::maintenance_target)
        .map(build_maintenance_target)
        .collect()
}

fn build_maintenance_target(pair: Pair<'_, Rule>) -> Result<MaintenanceTarget, ParseError> {
    let mut only = false;
    let mut table_name = None;
    let mut columns = Vec::new();
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::only_clause => only = true,
            Rule::identifier if table_name.is_none() => table_name = Some(build_identifier(part)),
            Rule::maintenance_column_list => {
                columns = part
                    .into_inner()
                    .find(|p| p.as_rule() == Rule::ident_list)
                    .map(|p| p.into_inner().map(build_identifier).collect())
                    .unwrap_or_default();
            }
            _ => {}
        }
    }
    Ok(MaintenanceTarget {
        table_name: table_name.ok_or(ParseError::UnexpectedEof)?,
        columns,
        only,
    })
}

fn build_update(pair: Pair<'_, Rule>) -> Result<UpdateStatement, ParseError> {
    let mut with_recursive = false;
    let mut with = Vec::new();
    let mut table_name = None;
    let mut target_alias = None;
    let mut only = false;
    let mut assignments = Vec::new();
    let mut from = None;
    let mut where_clause = None;
    let mut current_of = None;
    let mut returning = Vec::new();
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::cte_clause => {
                let (recursive, ctes) = build_cte_clause(part)?;
                with_recursive = recursive;
                with = ctes;
            }
            Rule::update_target => {
                let (parsed_table_name, parsed_alias, parsed_only) = build_update_target(part)?;
                table_name = Some(parsed_table_name);
                target_alias = parsed_alias;
                only = parsed_only;
            }
            Rule::from_item => from = Some(build_from_item(part)?),
            Rule::assignment_item => assignments.extend(build_assignment_item(part)?),
            Rule::update_where_clause => match build_update_where_clause(part)? {
                UpdateWhereClause::Expr(expr) => where_clause = Some(expr),
                UpdateWhereClause::CurrentOf(cursor_name) => current_of = Some(cursor_name),
            },
            Rule::returning_clause => returning = build_returning_clause(part)?,
            _ => {}
        }
    }
    Ok(UpdateStatement {
        with_recursive,
        with,
        table_name: table_name.ok_or(ParseError::UnexpectedEof)?,
        target_alias,
        only,
        assignments,
        from,
        where_clause,
        current_of,
        returning,
    })
}

fn build_update_target(pair: Pair<'_, Rule>) -> Result<(String, Option<String>, bool), ParseError> {
    let mut table_name = None;
    let mut alias = None;
    let mut only = false;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::only_clause => only = true,
            Rule::identifier if table_name.is_none() => table_name = Some(build_identifier(part)),
            Rule::update_target_alias => {
                let alias_pair = part.into_inner().find(|inner| {
                    matches!(
                        inner.as_rule(),
                        Rule::update_alias_identifier | Rule::identifier
                    )
                });
                if let Some(alias_pair) = alias_pair {
                    alias = Some(build_identifier(alias_pair));
                }
            }
            _ => {}
        }
    }
    Ok((table_name.ok_or(ParseError::UnexpectedEof)?, alias, only))
}

fn build_delete(pair: Pair<'_, Rule>) -> Result<DeleteStatement, ParseError> {
    let mut with_recursive = false;
    let mut with = Vec::new();
    let mut table_name = None;
    let mut only = false;
    let mut using = None;
    let mut where_clause = None;
    let mut current_of = None;
    let mut returning = Vec::new();
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::cte_clause => {
                let (recursive, ctes) = build_cte_clause(part)?;
                with_recursive = recursive;
                with = ctes;
            }
            Rule::only_clause => only = true,
            Rule::identifier if table_name.is_none() => table_name = Some(build_identifier(part)),
            Rule::from_item => using = Some(build_from_item(part)?),
            Rule::update_where_clause => match build_update_where_clause(part)? {
                UpdateWhereClause::Expr(expr) => where_clause = Some(expr),
                UpdateWhereClause::CurrentOf(cursor_name) => current_of = Some(cursor_name),
            },
            Rule::returning_clause => returning = build_returning_clause(part)?,
            _ => {}
        }
    }
    Ok(DeleteStatement {
        with_recursive,
        with,
        table_name: table_name.ok_or(ParseError::UnexpectedEof)?,
        only,
        using,
        where_clause,
        current_of,
        returning,
    })
}

enum UpdateWhereClause {
    Expr(SqlExpr),
    CurrentOf(String),
}

fn build_update_where_clause(pair: Pair<'_, Rule>) -> Result<UpdateWhereClause, ParseError> {
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::expr => return build_expr(part).map(UpdateWhereClause::Expr),
            Rule::current_of_clause => {
                let cursor_name = part
                    .into_inner()
                    .find(|inner| inner.as_rule() == Rule::identifier)
                    .map(build_identifier)
                    .ok_or(ParseError::UnexpectedEof)?;
                return Ok(UpdateWhereClause::CurrentOf(cursor_name));
            }
            _ => {}
        }
    }
    Err(ParseError::UnexpectedEof)
}

fn build_select_list(pair: Pair<'_, Rule>) -> Result<Vec<SelectItem>, ParseError> {
    let mut inner = pair.into_inner();
    let Some(first) = inner.next() else {
        return Ok(Vec::new());
    };
    if first.as_rule() == Rule::star {
        return Ok(vec![SelectItem {
            output_name: "*".into(),
            expr: SqlExpr::Column("*".into()),
        }]);
    }

    let mut items = Vec::new();
    for (index, item_pair) in std::iter::once(first).chain(inner).enumerate() {
        let mut preview_inner = item_pair.clone().into_inner();
        if let Some(first_part) = preview_inner.next() {
            if first_part.as_rule() == Rule::star {
                items.push(SelectItem {
                    output_name: "*".into(),
                    expr: SqlExpr::Column("*".into()),
                });
                continue;
            }
            if first_part.as_rule() == Rule::qualified_star {
                let relation = first_part
                    .as_str()
                    .strip_suffix(".*")
                    .ok_or(ParseError::UnexpectedEof)?
                    .to_string();
                items.push(SelectItem {
                    output_name: "*".into(),
                    expr: SqlExpr::Column(format!("{relation}.*")),
                });
                continue;
            }
        }

        let mut item_inner = item_pair.into_inner();
        let expr_pair = item_inner.next().ok_or(ParseError::UnexpectedEof)?;
        let expr_is_extract = top_level_extract_expr(expr_pair.clone());
        let expr_is_power_operator = top_level_power_operator_expr(expr_pair.clone());
        let expr = build_expr(expr_pair)?;
        let output_name = if let Some(alias_pair) = item_inner.next() {
            let alias = alias_pair
                .into_inner()
                .last()
                .ok_or(ParseError::UnexpectedEof)?;
            build_identifier(alias)
        } else if expr_is_extract {
            "extract".into()
        } else if expr_is_power_operator {
            "?column?".into()
        } else {
            select_item_name(&expr, index)
        };
        items.push(SelectItem { output_name, expr });
    }

    Ok(items)
}

fn build_returning_clause(pair: Pair<'_, Rule>) -> Result<Vec<SelectItem>, ParseError> {
    let select_list = pair
        .into_inner()
        .find(|part| part.as_rule() == Rule::select_list)
        .ok_or(ParseError::UnexpectedEof)?;
    build_select_list(select_list)
}

fn top_level_extract_expr(pair: Pair<'_, Rule>) -> bool {
    match pair.as_rule() {
        Rule::extract_expr => true,
        Rule::expr
        | Rule::or_expr
        | Rule::and_expr
        | Rule::not_expr
        | Rule::cmp_expr
        | Rule::json_access_expr
        | Rule::concat_expr
        | Rule::add_expr
        | Rule::bit_expr
        | Rule::shift_expr
        | Rule::pow_expr
        | Rule::mul_expr
        | Rule::unary_expr
        | Rule::positive_expr
        | Rule::negated_expr
        | Rule::postfix_expr
        | Rule::primary_expr => {
            let mut inner = pair.into_inner();
            let Some(first) = inner.next() else {
                return false;
            };
            if inner.next().is_some() {
                return false;
            }
            top_level_extract_expr(first)
        }
        _ => false,
    }
}

fn top_level_power_operator_expr(pair: Pair<'_, Rule>) -> bool {
    match pair.as_rule() {
        Rule::pow_expr => pair.into_inner().any(|part| part.as_rule() == Rule::pow_op),
        Rule::expr
        | Rule::or_expr
        | Rule::and_expr
        | Rule::not_expr
        | Rule::cmp_expr
        | Rule::json_access_expr
        | Rule::concat_expr
        | Rule::add_expr
        | Rule::bit_expr
        | Rule::shift_expr
        | Rule::mul_expr
        | Rule::unary_expr
        | Rule::positive_expr
        | Rule::negated_expr
        | Rule::postfix_expr
        | Rule::primary_expr => {
            let mut inner = pair.into_inner();
            let Some(first) = inner.next() else {
                return false;
            };
            if inner.next().is_some() {
                return false;
            }
            top_level_power_operator_expr(first)
        }
        _ => false,
    }
}

fn select_item_name(expr: &SqlExpr, index: usize) -> String {
    let _ = index;
    match expr {
        SqlExpr::Column(name) => name.rsplit('.').next().unwrap_or(name).to_string(),
        SqlExpr::ArrayLiteral(_) | SqlExpr::ArraySubquery(_) => "array".to_string(),
        SqlExpr::ArraySubscript { array, .. } => select_item_name(array, index),
        SqlExpr::FieldSelect { field, .. } => field.clone(),
        SqlExpr::Cast(inner, ty) => match inner.as_ref() {
            SqlExpr::ArrayLiteral(_) | SqlExpr::ArraySubquery(_) => select_item_name(inner, index),
            SqlExpr::ArraySubscript { .. }
            | SqlExpr::Column(_)
            | SqlExpr::FieldSelect { .. }
            | SqlExpr::FuncCall { .. }
            | SqlExpr::Row(_) => select_item_name(inner, index),
            SqlExpr::Cast(grand_inner, _) if matches!(grand_inner.as_ref(), SqlExpr::Column(_)) => {
                select_item_name(inner, index)
            }
            _ => raw_type_output_name(ty).to_string(),
        },
        SqlExpr::Collate { expr, .. } => select_item_name(expr, index),
        SqlExpr::Case { defresult, .. } => defresult
            .as_deref()
            .map(|expr| select_item_name(expr, index))
            .filter(|name| name != "?column?" && name != "case")
            .unwrap_or_else(|| "case".to_string()),
        SqlExpr::Row(_) => "row".to_string(),
        SqlExpr::Random => "random".to_string(),
        SqlExpr::CurrentCatalog => "current_catalog".to_string(),
        SqlExpr::CurrentSchema => "current_schema".to_string(),
        SqlExpr::CurrentUser => "current_user".to_string(),
        SqlExpr::SessionUser => "session_user".to_string(),
        SqlExpr::CurrentRole => "current_role".to_string(),
        SqlExpr::AtTimeZone { .. } => "timezone".to_string(),
        SqlExpr::JsonQueryFunction(func) => match func.kind {
            JsonQueryFunctionKind::Exists => "json_exists",
            JsonQueryFunctionKind::Value => "json_value",
            JsonQueryFunctionKind::Query => "json_query",
        }
        .to_string(),
        SqlExpr::FuncCall { name, .. } => sql_json_public_func_name(name)
            .unwrap_or_else(|| name.rsplit('.').next().unwrap_or(name))
            .to_string(),
        SqlExpr::Xml(xml) => match xml.op {
            RawXmlExprOp::Concat => "xmlconcat",
            RawXmlExprOp::Element => "xmlelement",
            RawXmlExprOp::Forest => "xmlforest",
            RawXmlExprOp::Parse => "xmlparse",
            RawXmlExprOp::Pi => "xmlpi",
            RawXmlExprOp::Root => "xmlroot",
            RawXmlExprOp::Serialize => "xmlserialize",
            RawXmlExprOp::IsDocument => "?column?",
        }
        .to_string(),
        _ => "?column?".to_string(),
    }
}

fn sql_json_public_func_name(name: &str) -> Option<&'static str> {
    match name {
        SQL_JSON_FUNC => Some("json"),
        SQL_JSON_SCALAR_FUNC => Some("json_scalar"),
        SQL_JSON_SERIALIZE_FUNC => Some("json_serialize"),
        SQL_JSON_OBJECT_FUNC => Some("json_object"),
        SQL_JSON_ARRAY_FUNC => Some("json_array"),
        SQL_JSON_ARRAYAGG_FUNC => Some("json_arrayagg"),
        SQL_JSON_OBJECTAGG_FUNC => Some("json_objectagg"),
        SQL_JSON_IS_JSON_FUNC => Some("?column?"),
        _ => None,
    }
}

fn simple_func_call(name: impl Into<String>, args: Vec<SqlFunctionArg>) -> SqlExpr {
    SqlExpr::FuncCall {
        name: name.into(),
        args: SqlCallArgs::Args(args),
        order_by: Vec::new(),
        within_group: None,
        distinct: false,
        func_variadic: false,
        filter: None,
        null_treatment: None,
        over: None,
    }
}

fn internal_sql_json_func_call(name: &'static str, args: Vec<SqlFunctionArg>) -> SqlExpr {
    simple_func_call(name, args)
}

fn hidden_bool_arg(value: bool) -> SqlFunctionArg {
    SqlFunctionArg::positional(SqlExpr::Const(Value::Bool(value)))
}

fn hidden_text_arg(value: impl Into<String>) -> SqlFunctionArg {
    SqlFunctionArg::positional(SqlExpr::Const(Value::Text(value.into().into())))
}

fn cast_json_returning(expr: SqlExpr, returning: Option<RawTypeName>) -> SqlExpr {
    returning
        .map(|ty| SqlExpr::Cast(Box::new(expr.clone()), ty))
        .unwrap_or(expr)
}

fn build_json_value_expr(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut value = None;
    let mut format_json = false;
    let mut encoding = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::expr => value = Some(build_expr(part)?),
            Rule::json_format_clause => {
                format_json = true;
                encoding = json_format_clause_encoding(part);
            }
            _ => {}
        }
    }
    let value = value.ok_or(ParseError::UnexpectedEof)?;
    if format_json {
        Ok(internal_sql_json_func_call(
            SQL_JSON_FUNC,
            vec![
                SqlFunctionArg::positional(value),
                hidden_text_arg(encoding.unwrap_or_default()),
            ],
        ))
    } else {
        Ok(value)
    }
}

fn build_json_returning_clause_with_format(
    pair: Pair<'_, Rule>,
) -> Result<JsonQueryReturning, ParseError> {
    let mut ty = None;
    let mut format_json = false;
    let mut encoding = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::type_name => ty = Some(build_type_name(part)),
            Rule::json_format_clause => {
                format_json = true;
                encoding = json_format_clause_encoding(part);
            }
            _ => {}
        }
    }
    let ty = ty.ok_or(ParseError::UnexpectedEof)?;
    validate_json_returning_encoding(&ty, encoding.as_deref())?;
    Ok(JsonQueryReturning {
        type_name: ty,
        format_json,
    })
}

fn build_json_returning_clause(pair: Pair<'_, Rule>) -> Result<RawTypeName, ParseError> {
    build_json_returning_clause_with_format(pair).map(|returning| returning.type_name)
}

fn json_format_clause_encoding(pair: Pair<'_, Rule>) -> Option<String> {
    pair.into_inner()
        .find(|part| part.as_rule() == Rule::json_encoding_clause)
        .and_then(|part| {
            part.into_inner()
                .find(|part| part.as_rule() == Rule::identifier)
                .map(build_identifier)
        })
}

fn validate_json_encoding_name(encoding: &str) -> Result<(), ParseError> {
    match encoding.to_ascii_lowercase().as_str() {
        "" | "utf8" => Ok(()),
        "utf16" | "utf32" => Err(ParseError::DetailedError {
            message: "unsupported JSON encoding".into(),
            detail: None,
            hint: Some("Only UTF8 JSON encoding is supported.".into()),
            sqlstate: "0A000",
        }),
        other => Err(ParseError::DetailedError {
            message: format!("unrecognized JSON encoding: {other}"),
            detail: None,
            hint: None,
            sqlstate: "22023",
        }),
    }
}

fn validate_json_returning_encoding(
    ty: &RawTypeName,
    encoding: Option<&str>,
) -> Result<(), ParseError> {
    let Some(encoding) = encoding else {
        return Ok(());
    };
    validate_json_encoding_name(encoding)?;
    if !ty
        .as_builtin()
        .is_some_and(|ty| ty.kind == SqlTypeKind::Bytea)
    {
        return Err(ParseError::DetailedError {
            message: "cannot set JSON encoding for non-bytea output types".into(),
            detail: None,
            hint: None,
            sqlstate: "22023",
        });
    }
    Ok(())
}

fn json_null_clause_is_null_on_null(pair: Pair<'_, Rule>) -> bool {
    pair.as_str()
        .trim_start()
        .to_ascii_lowercase()
        .starts_with("null")
}

fn json_key_uniqueness_constraint_is_with_unique(pair: Pair<'_, Rule>) -> bool {
    pair.as_str()
        .trim_start()
        .to_ascii_lowercase()
        .starts_with("with")
}

fn build_json_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let value = pair
        .into_inner()
        .find(|part| part.as_rule() == Rule::json_value_expr)
        .ok_or(ParseError::UnexpectedEof)
        .and_then(build_json_value_expr)?;
    Ok(internal_sql_json_func_call(
        SQL_JSON_FUNC,
        vec![SqlFunctionArg::positional(value)],
    ))
}

fn build_json_scalar_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let value = pair
        .into_inner()
        .find(|part| part.as_rule() == Rule::expr)
        .ok_or(ParseError::UnexpectedEof)
        .and_then(build_expr)?;
    Ok(internal_sql_json_func_call(
        SQL_JSON_SCALAR_FUNC,
        vec![SqlFunctionArg::positional(value)],
    ))
}

fn build_json_serialize_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut value = None;
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_value_expr => value = Some(build_json_value_expr(part)?),
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    let expr = internal_sql_json_func_call(
        SQL_JSON_SERIALIZE_FUNC,
        vec![SqlFunctionArg::positional(
            value.ok_or(ParseError::UnexpectedEof)?,
        )],
    );
    Ok(cast_json_returning(expr, returning))
}

fn build_json_object_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut args = vec![hidden_bool_arg(false), hidden_bool_arg(false)];
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_object_value_constructor => {
                let (mut parsed_args, absent_on_null, unique_keys, parsed_returning) =
                    build_json_object_value_constructor(part)?;
                args[0] = hidden_bool_arg(absent_on_null);
                args[1] = hidden_bool_arg(unique_keys);
                args.append(&mut parsed_args);
                returning = parsed_returning;
            }
            Rule::json_object_option_constructor => {
                let (absent_on_null, unique_keys, parsed_returning) =
                    build_json_object_option_constructor(part)?;
                args[0] = hidden_bool_arg(absent_on_null);
                args[1] = hidden_bool_arg(unique_keys);
                returning = parsed_returning;
            }
            _ => {}
        }
    }
    Ok(cast_json_returning(
        internal_sql_json_func_call(SQL_JSON_OBJECT_FUNC, args),
        returning,
    ))
}

fn build_json_object_value_constructor(
    pair: Pair<'_, Rule>,
) -> Result<(Vec<SqlFunctionArg>, bool, bool, Option<RawTypeName>), ParseError> {
    let mut args = Vec::new();
    let mut absent_on_null = false;
    let mut unique_keys = false;
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_object_arg_list => args = build_json_object_arg_list(part)?,
            Rule::json_object_constructor_null_clause => {
                absent_on_null = !json_null_clause_is_null_on_null(part);
            }
            Rule::json_key_uniqueness_constraint => {
                unique_keys = json_key_uniqueness_constraint_is_with_unique(part);
            }
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    Ok((args, absent_on_null, unique_keys, returning))
}

fn build_json_object_option_constructor(
    pair: Pair<'_, Rule>,
) -> Result<(bool, bool, Option<RawTypeName>), ParseError> {
    let mut absent_on_null = false;
    let mut unique_keys = false;
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_object_constructor_null_clause => {
                absent_on_null = !json_null_clause_is_null_on_null(part);
            }
            Rule::json_key_uniqueness_constraint => {
                unique_keys = json_key_uniqueness_constraint_is_with_unique(part);
            }
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    Ok((absent_on_null, unique_keys, returning))
}

fn build_json_object_arg_list(pair: Pair<'_, Rule>) -> Result<Vec<SqlFunctionArg>, ParseError> {
    let mut args = Vec::new();
    for part in pair.into_inner() {
        if part.as_rule() == Rule::json_object_arg {
            let (key, value) = build_json_object_arg(part)?;
            args.push(SqlFunctionArg::positional(key));
            args.push(SqlFunctionArg::positional(value));
        }
    }
    Ok(args)
}

fn build_json_object_arg(pair: Pair<'_, Rule>) -> Result<(SqlExpr, SqlExpr), ParseError> {
    let mut key = None;
    let mut value = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::expr if key.is_none() => key = Some(build_expr(part)?),
            Rule::json_value_expr => value = Some(build_json_value_expr(part)?),
            _ => {}
        }
    }
    Ok((
        key.ok_or(ParseError::UnexpectedEof)?,
        value.ok_or(ParseError::UnexpectedEof)?,
    ))
}

fn build_json_array_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut args = vec![hidden_bool_arg(false), hidden_bool_arg(false)];
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_array_query_constructor => {
                let (query_expr, parsed_returning) = build_json_array_query_constructor(part)?;
                args[1] = hidden_bool_arg(true);
                args.push(SqlFunctionArg::positional(query_expr));
                returning = parsed_returning;
            }
            Rule::json_array_empty_returning_constructor => {
                returning = part
                    .into_inner()
                    .find(|part| part.as_rule() == Rule::json_returning_clause)
                    .map(build_json_returning_clause)
                    .transpose()?;
            }
            Rule::json_array_value_constructor => {
                let (mut values, null_on_null, parsed_returning) =
                    build_json_array_value_constructor(part)?;
                args[0] = hidden_bool_arg(null_on_null);
                args.append(&mut values);
                returning = parsed_returning;
            }
            _ => {}
        }
    }
    Ok(cast_json_returning(
        internal_sql_json_func_call(SQL_JSON_ARRAY_FUNC, args),
        returning,
    ))
}

fn build_json_array_query_constructor(
    pair: Pair<'_, Rule>,
) -> Result<(SqlExpr, Option<RawTypeName>), ParseError> {
    let mut query = None;
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::select_stmt => {
                query = Some(SqlExpr::ArraySubquery(Box::new(build_select(part)?)))
            }
            Rule::values_stmt => {
                query = Some(SqlExpr::ArraySubquery(Box::new(wrap_values_as_select(
                    build_values_statement(part)?,
                ))))
            }
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    Ok((query.ok_or(ParseError::UnexpectedEof)?, returning))
}

fn build_json_array_value_constructor(
    pair: Pair<'_, Rule>,
) -> Result<(Vec<SqlFunctionArg>, bool, Option<RawTypeName>), ParseError> {
    let mut args = Vec::new();
    let mut null_on_null = false;
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_array_element_list => {
                args = part
                    .into_inner()
                    .filter(|part| part.as_rule() == Rule::json_value_expr)
                    .map(|part| build_json_value_expr(part).map(SqlFunctionArg::positional))
                    .collect::<Result<Vec<_>, _>>()?;
            }
            Rule::json_array_constructor_null_clause => {
                null_on_null = json_null_clause_is_null_on_null(part);
            }
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    Ok((args, null_on_null, returning))
}

fn build_json_arrayagg_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut value = None;
    let mut order_by = Vec::new();
    let mut returning = None;
    let mut filter = None;
    let mut over = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_arrayagg_arg => {
                let (parsed_value, parsed_order_by, parsed_returning) =
                    build_json_arrayagg_arg(part)?;
                value = Some(parsed_value);
                order_by = parsed_order_by;
                returning = parsed_returning;
            }
            Rule::agg_filter_clause => filter = Some(build_agg_filter_clause(part)?),
            Rule::over_clause => over = Some(build_over_clause(part)?),
            _ => {}
        }
    }
    let expr = SqlExpr::FuncCall {
        name: SQL_JSON_ARRAYAGG_FUNC.into(),
        args: SqlCallArgs::Args(vec![SqlFunctionArg::positional(
            value.ok_or(ParseError::UnexpectedEof)?,
        )]),
        order_by,
        within_group: None,
        distinct: false,
        func_variadic: false,
        filter: filter.map(Box::new),
        null_treatment: None,
        over,
    };
    Ok(cast_json_returning(expr, returning))
}

fn build_json_arrayagg_arg(
    pair: Pair<'_, Rule>,
) -> Result<(SqlExpr, Vec<OrderByItem>, Option<RawTypeName>), ParseError> {
    let mut value = None;
    let mut order_by = Vec::new();
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_value_expr => value = Some(build_json_value_expr(part)?),
            Rule::agg_order_by_clause => {
                order_by = part
                    .into_inner()
                    .filter(|inner| inner.as_rule() == Rule::order_by_item)
                    .map(build_order_by_item)
                    .collect::<Result<Vec<_>, _>>()?;
            }
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    Ok((value.ok_or(ParseError::UnexpectedEof)?, order_by, returning))
}

fn build_json_objectagg_constructor(pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut key = None;
    let mut value = None;
    let mut order_by = Vec::new();
    let mut returning = None;
    let mut filter = None;
    let mut over = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_objectagg_arg => {
                let (parsed_key, parsed_value, parsed_order_by, parsed_returning) =
                    build_json_objectagg_arg(part)?;
                key = Some(parsed_key);
                value = Some(parsed_value);
                order_by = parsed_order_by;
                returning = parsed_returning;
            }
            Rule::agg_filter_clause => filter = Some(build_agg_filter_clause(part)?),
            Rule::over_clause => over = Some(build_over_clause(part)?),
            _ => {}
        }
    }
    let expr = SqlExpr::FuncCall {
        name: SQL_JSON_OBJECTAGG_FUNC.into(),
        args: SqlCallArgs::Args(vec![
            SqlFunctionArg::positional(key.ok_or(ParseError::UnexpectedEof)?),
            SqlFunctionArg::positional(value.ok_or(ParseError::UnexpectedEof)?),
        ]),
        order_by,
        within_group: None,
        distinct: false,
        func_variadic: false,
        filter: filter.map(Box::new),
        null_treatment: None,
        over,
    };
    Ok(cast_json_returning(expr, returning))
}

fn build_json_objectagg_arg(
    pair: Pair<'_, Rule>,
) -> Result<(SqlExpr, SqlExpr, Vec<OrderByItem>, Option<RawTypeName>), ParseError> {
    let mut key = None;
    let mut value = None;
    let mut order_by = Vec::new();
    let mut returning = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::json_object_arg => {
                let (parsed_key, parsed_value) = build_json_object_arg(part)?;
                key = Some(parsed_key);
                value = Some(parsed_value);
            }
            Rule::agg_order_by_clause => {
                order_by = part
                    .into_inner()
                    .filter(|inner| inner.as_rule() == Rule::order_by_item)
                    .map(build_order_by_item)
                    .collect::<Result<Vec<_>, _>>()?;
            }
            Rule::json_returning_clause => returning = Some(build_json_returning_clause(part)?),
            _ => {}
        }
    }
    Ok((
        key.ok_or(ParseError::UnexpectedEof)?,
        value.ok_or(ParseError::UnexpectedEof)?,
        order_by,
        returning,
    ))
}

fn build_json_predicate(left: SqlExpr, pair: Pair<'_, Rule>) -> Result<SqlExpr, ParseError> {
    let mut negated = false;
    let mut predicate_type = "value";
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::kw_not => negated = true,
            Rule::json_predicate_type => {
                predicate_type = match part.as_str().trim().to_ascii_lowercase().as_str() {
                    "scalar" => "scalar",
                    "array" => "array",
                    "object" => "object",
                    _ => "value",
                };
            }
            _ => {}
        }
    }
    let expr = internal_sql_json_func_call(
        SQL_JSON_IS_JSON_FUNC,
        vec![
            SqlFunctionArg::positional(left),
            SqlFunctionArg::positional(SqlExpr::Const(Value::Text(predicate_type.into()))),
        ],
    );
    Ok(if negated {
        SqlExpr::Not(Box::new(expr))
    } else {
        expr
    })
}

fn sql_type_output_name(ty: SqlType) -> &'static str {
    if ty.type_oid == crate::include::catalog::REFCURSOR_TYPE_OID {
        return "refcursor";
    }
    match ty.kind {
        SqlTypeKind::AnyElement => "anyelement",
        SqlTypeKind::AnyRange => "anyrange",
        SqlTypeKind::AnyMultirange => "anymultirange",
        SqlTypeKind::AnyCompatible => "anycompatible",
        SqlTypeKind::AnyCompatibleArray => "anycompatiblearray",
        SqlTypeKind::AnyCompatibleRange => "anycompatiblerange",
        SqlTypeKind::AnyCompatibleMultirange => "anycompatiblemultirange",
        SqlTypeKind::AnyEnum => "anyenum",
        SqlTypeKind::Enum => "enum",
        SqlTypeKind::Record => "record",
        SqlTypeKind::Composite => "record",
        SqlTypeKind::Shell => "shell",
        SqlTypeKind::Trigger => "trigger",
        SqlTypeKind::EventTrigger => "event_trigger",
        SqlTypeKind::Void => "void",
        SqlTypeKind::Cstring => "cstring",
        SqlTypeKind::FdwHandler => "fdw_handler",
        SqlTypeKind::Int2 => "int2",
        SqlTypeKind::Int2Vector => "int2vector",
        SqlTypeKind::Int4 => "int4",
        SqlTypeKind::Range => "range",
        SqlTypeKind::Int4Range => "int4range",
        SqlTypeKind::Int8 => "int8",
        SqlTypeKind::Int8Range => "int8range",
        SqlTypeKind::Name => "name",
        SqlTypeKind::Oid => "oid",
        SqlTypeKind::RegProc => "regproc",
        SqlTypeKind::RegClass => "regclass",
        SqlTypeKind::RegType => "regtype",
        SqlTypeKind::RegRole => "regrole",
        SqlTypeKind::RegNamespace => "regnamespace",
        SqlTypeKind::RegOper => "regoper",
        SqlTypeKind::RegOperator => "regoperator",
        SqlTypeKind::RegProcedure => "regprocedure",
        SqlTypeKind::RegCollation => "regcollation",
        SqlTypeKind::Tid => "tid",
        SqlTypeKind::Xid => "xid",
        SqlTypeKind::OidVector => "oidvector",
        SqlTypeKind::Bit => "bit",
        SqlTypeKind::VarBit => "varbit",
        SqlTypeKind::Float4 => "float4",
        SqlTypeKind::Float8 => "float8",
        SqlTypeKind::Money => "money",
        SqlTypeKind::Numeric => "numeric",
        SqlTypeKind::NumericRange => "numrange",
        SqlTypeKind::Json => "json",
        SqlTypeKind::Jsonb => "jsonb",
        SqlTypeKind::JsonPath => "jsonpath",
        SqlTypeKind::Xml => "xml",
        SqlTypeKind::Inet => "inet",
        SqlTypeKind::Cidr => "cidr",
        SqlTypeKind::MacAddr => "macaddr",
        SqlTypeKind::MacAddr8 => "macaddr8",
        SqlTypeKind::Date => "date",
        SqlTypeKind::DateRange => "daterange",
        SqlTypeKind::Time => "time",
        SqlTypeKind::TimeTz => "timetz",
        SqlTypeKind::Interval => "interval",
        SqlTypeKind::TsVector => "tsvector",
        SqlTypeKind::TsQuery => "tsquery",
        SqlTypeKind::PgLsn => "pg_lsn",
        SqlTypeKind::RegConfig => "regconfig",
        SqlTypeKind::RegDictionary => "regdictionary",
        SqlTypeKind::AnyArray => "anyarray",
        SqlTypeKind::Multirange => "multirange",
        SqlTypeKind::Text => "text",
        SqlTypeKind::Bytea => "bytea",
        SqlTypeKind::Uuid => "uuid",
        SqlTypeKind::Bool => "bool",
        SqlTypeKind::Point => "point",
        SqlTypeKind::Lseg => "lseg",
        SqlTypeKind::Path => "path",
        SqlTypeKind::Box => "box",
        SqlTypeKind::Polygon => "polygon",
        SqlTypeKind::Line => "line",
        SqlTypeKind::Circle => "circle",
        SqlTypeKind::Timestamp => "timestamp",
        SqlTypeKind::TimestampRange => "tsrange",
        SqlTypeKind::TimestampTz => "timestamptz",
        SqlTypeKind::TimestampTzRange => "tstzrange",
        SqlTypeKind::PgNodeTree => "pg_node_tree",
        SqlTypeKind::Internal => "internal",
        SqlTypeKind::InternalChar => "char",
        SqlTypeKind::Char => "bpchar",
        SqlTypeKind::Varchar => "varchar",
    }
}

fn raw_type_output_name(ty: &RawTypeName) -> &str {
    match ty {
        RawTypeName::Builtin(sql_type) => match sql_type.kind {
            SqlTypeKind::Time => "time",
            SqlTypeKind::TimeTz => "timetz",
            SqlTypeKind::Timestamp => "timestamp",
            SqlTypeKind::TimestampTz => "timestamptz",
            _ => sql_type_output_name(*sql_type),
        },
        RawTypeName::Serial(SerialKind::Small) => "smallserial",
        RawTypeName::Serial(SerialKind::Regular) => "serial",
        RawTypeName::Serial(SerialKind::Big) => "bigserial",
        RawTypeName::Named { name, .. } if name.eq_ignore_ascii_case("float") => "float8",
        RawTypeName::Named { name, .. } => name.as_str(),
        RawTypeName::Record => "record",
    }
}

fn build_values_row(pair: Pair<'_, Rule>) -> Result<Vec<SqlExpr>, ParseError> {
    pair.into_inner()
        .next()
        .ok_or(ParseError::UnexpectedEof)?
        .into_inner()
        .map(build_expr)
        .collect()
}

fn build_assignment(pair: Pair<'_, Rule>) -> Result<Assignment, ParseError> {
    let mut inner = pair.into_inner();
    Ok(Assignment {
        target: build_assignment_target(inner.next().ok_or(ParseError::UnexpectedEof)?)?,
        expr: build_expr(inner.next().ok_or(ParseError::UnexpectedEof)?)?,
    })
}

fn build_assignment_item(pair: Pair<'_, Rule>) -> Result<Vec<Assignment>, ParseError> {
    match pair.as_rule() {
        Rule::assignment_item => {
            let inner = pair.into_inner().next().ok_or(ParseError::UnexpectedEof)?;
            build_assignment_item(inner)
        }
        Rule::assignment => Ok(vec![build_assignment(pair)?]),
        Rule::row_assignment => build_row_assignment(pair),
        _ => Err(ParseError::UnexpectedToken {
            expected: "assignment",
            actual: pair.as_str().to_string(),
        }),
    }
}

fn build_row_assignment(pair: Pair<'_, Rule>) -> Result<Vec<Assignment>, ParseError> {
    let mut targets = None;
    let mut expr = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::assignment_target_list => targets = Some(build_assignment_target_list(part)?),
            Rule::expr => expr = Some(build_expr(part)?),
            _ => {}
        }
    }
    let targets = targets.ok_or(ParseError::UnexpectedEof)?;
    let exprs = split_row_assignment_expr(expr.ok_or(ParseError::UnexpectedEof)?, &targets)?;
    Ok(targets
        .into_iter()
        .zip(exprs)
        .map(|(target, expr)| Assignment { target, expr })
        .collect())
}

fn split_row_assignment_expr(
    expr: SqlExpr,
    targets: &[AssignmentTarget],
) -> Result<Vec<SqlExpr>, ParseError> {
    let arity = targets.len();
    match expr {
        SqlExpr::Row(items) if items.len() == arity => Ok(items),
        SqlExpr::Row(items) if items.len() == 1 && arity > 1 => {
            if let SqlExpr::Column(name) = &items[0]
                && let Some(relation) = name.strip_suffix(".*")
            {
                return Ok(targets
                    .iter()
                    .map(|target| SqlExpr::FieldSelect {
                        expr: Box::new(SqlExpr::Column(relation.to_string())),
                        field: target.column.clone(),
                    })
                    .collect());
            }
            Err(ParseError::UnexpectedToken {
                expected: "matching row assignment values",
                actual: "1 values".into(),
            })
        }
        SqlExpr::Row(items) => Err(ParseError::UnexpectedToken {
            expected: "matching row assignment values",
            actual: format!("{} values", items.len()),
        }),
        SqlExpr::ScalarSubquery(select) => {
            if select.set_operation.is_some() || select.targets.len() != arity {
                return Err(ParseError::UnexpectedToken {
                    expected: "matching row assignment columns",
                    actual: format!("{} columns", select.targets.len()),
                });
            }
            let select = *select;
            Ok(select
                .targets
                .iter()
                .map(|target| {
                    let mut projected = select.clone();
                    projected.targets = vec![target.clone()];
                    SqlExpr::ScalarSubquery(Box::new(projected))
                })
                .collect())
        }
        other if arity == 1 => Ok(vec![other]),
        other => Err(ParseError::UnexpectedToken {
            expected: "row assignment source",
            actual: format!("{other:?}"),
        }),
    }
}

fn build_assignment_target_list(pair: Pair<'_, Rule>) -> Result<Vec<AssignmentTarget>, ParseError> {
    pair.into_inner()
        .filter(|part| part.as_rule() == Rule::assignment_target)
        .map(build_assignment_target)
        .collect()
}

fn build_assignment_target(pair: Pair<'_, Rule>) -> Result<AssignmentTarget, ParseError> {
    let mut inner = pair.into_inner();
    let column = build_identifier(inner.next().ok_or(ParseError::UnexpectedEof)?);
    let mut subscripts = Vec::new();
    let mut field_path = Vec::new();
    let mut indirection = Vec::new();
    for part in inner {
        match part.as_rule() {
            Rule::assignment_target_suffix => {
                let suffix = part.into_inner().next().ok_or(ParseError::UnexpectedEof)?;
                match suffix.as_rule() {
                    Rule::subscript_suffix => {
                        let subscript = build_array_subscript(suffix)?;
                        subscripts.push(subscript.clone());
                        indirection.push(AssignmentTargetIndirection::Subscript(subscript));
                    }
                    Rule::field_select_suffix => {
                        let field = suffix
                            .into_inner()
                            .find(|part| part.as_rule() == Rule::identifier)
                            .map(build_identifier)
                            .ok_or(ParseError::UnexpectedEof)?;
                        field_path.push(field.clone());
                        indirection.push(AssignmentTargetIndirection::Field(field));
                    }
                    _ => {}
                }
            }
            Rule::subscript_suffix => {
                let subscript = build_array_subscript(part)?;
                subscripts.push(subscript.clone());
                indirection.push(AssignmentTargetIndirection::Subscript(subscript));
            }
            Rule::field_select_suffix => {
                let field = part
                    .into_inner()
                    .find(|inner| inner.as_rule() == Rule::identifier)
                    .map(build_identifier)
                    .ok_or(ParseError::UnexpectedEof)?;
                field_path.push(field.clone());
                indirection.push(AssignmentTargetIndirection::Field(field));
            }
            _ => {}
        }
    }
    Ok(AssignmentTarget {
        column,
        subscripts,
        field_path,
        indirection,
    })
}

fn build_array_subscript(pair: Pair<'_, Rule>) -> Result<ArraySubscript, ParseError> {
    let raw = pair.as_str().to_string();
    let raw_inner = raw
        .strip_prefix('[')
        .and_then(|value| value.strip_suffix(']'))
        .unwrap_or(raw.as_str());
    let mut bounds = pair
        .into_inner()
        .filter(|part| part.as_rule() == Rule::subscript_bound)
        .map(|bound| {
            let expr = bound.into_inner().next().ok_or(ParseError::UnexpectedEof)?;
            build_expr(expr).map(Box::new)
        });
    let has_slice = raw.contains(':');
    let lower = if has_slice && raw_inner.starts_with(':') {
        None
    } else {
        bounds.next().transpose()?
    };
    let upper = if has_slice {
        bounds.next().transpose()?
    } else {
        None
    };
    Ok(ArraySubscript {
        is_slice: has_slice,
        lower,
        upper,
    })
}

fn build_column_def(pair: Pair<'_, Rule>) -> Result<ColumnDef, ParseError> {
    let mut inner = pair.into_inner();
    let name = build_identifier(inner.next().ok_or(ParseError::UnexpectedEof)?);
    let ty = canonicalize_column_type_name(build_type_name(
        inner.next().ok_or(ParseError::UnexpectedEof)?,
    ))?;
    let mut default_expr = None;
    let mut collation = None;
    let mut generated = None;
    let mut identity = None;
    let mut storage = None;
    let mut compression = None;
    let mut constraints = Vec::new();
    for flag in inner {
        let Some(flag) = (match flag.as_rule() {
            Rule::column_modifier => flag.into_inner().next(),
            _ => Some(flag),
        }) else {
            continue;
        };
        match flag.as_rule() {
            Rule::column_collation => {
                collation = Some(build_collation_name(
                    flag.into_inner()
                        .find(|part| part.as_rule() == Rule::collation_name)
                        .ok_or(ParseError::UnexpectedEof)?,
                )?);
            }
            Rule::column_default => {
                default_expr = flag
                    .into_inner()
                    .find(|part| matches!(part.as_rule(), Rule::expr | Rule::b_expr))
                    .map(|expr| expr.as_str().trim().to_string());
            }
            Rule::column_generated => {
                set_column_generated(&mut generated, build_column_generated(flag)?, &name)?;
            }
            Rule::column_identity => {
                set_column_identity(&mut identity, build_column_identity(flag)?, &name)?;
            }
            Rule::column_compression => {
                compression = Some(build_column_compression(flag)?);
            }
            Rule::column_storage => {
                storage = Some(build_column_storage(flag)?);
            }
            Rule::nullable => {}
            Rule::named_column_constraint => {
                let generated_part = flag
                    .clone()
                    .into_inner()
                    .find(|part| part.as_rule() == Rule::column_generated);
                if let Some(generated_part) = generated_part {
                    set_column_generated(
                        &mut generated,
                        build_column_generated(generated_part)?,
                        &name,
                    )?;
                } else if let Some(identity_part) = flag
                    .clone()
                    .into_inner()
                    .find(|part| part.as_rule() == Rule::column_identity)
                {
                    set_column_identity(
                        &mut identity,
                        build_column_identity(identity_part)?,
                        &name,
                    )?;
                } else {
                    constraints.push(build_column_constraint(flag)?)
                }
            }
            Rule::not_null_column_constraint
            | Rule::check_column_constraint
            | Rule::primary_key_column_constraint
            | Rule::unique_column_constraint
            | Rule::references_column_constraint => {
                constraints.push(build_column_constraint(flag)?)
            }
            _ => {}
        }
    }
    Ok(ColumnDef {
        name,
        ty,
        collation,
        default_expr,
        generated,
        identity,
        storage,
        compression,
        constraints,
    })
}

fn set_column_generated(
    target: &mut Option<ColumnGeneratedDef>,
    value: ColumnGeneratedDef,
    column_name: &str,
) -> Result<(), ParseError> {
    if target.is_some() {
        return Err(ParseError::UnexpectedToken {
            expected: "single generation clause",
            actual: format!("multiple generation clauses specified for column \"{column_name}\""),
        });
    }
    *target = Some(value);
    Ok(())
}

fn set_column_identity(
    target: &mut Option<ColumnIdentityDef>,
    value: ColumnIdentityDef,
    column_name: &str,
) -> Result<(), ParseError> {
    if target.is_some() {
        return Err(ParseError::UnexpectedToken {
            expected: "single identity clause",
            actual: format!("multiple identity clauses specified for column \"{column_name}\""),
        });
    }
    *target = Some(value);
    Ok(())
}

fn build_column_identity(pair: Pair<'_, Rule>) -> Result<ColumnIdentityDef, ParseError> {
    let mut when = None;
    let mut options = SequenceOptionsSpec::default();
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::generated_when => when = Some(part.as_str().trim().to_ascii_lowercase()),
            Rule::column_identity_options => {
                let raw = part.as_str().trim();
                let Some(inner) = raw
                    .strip_prefix('(')
                    .and_then(|value| value.strip_suffix(')'))
                else {
                    return Err(ParseError::UnexpectedToken {
                        expected: "identity sequence options",
                        actual: raw.into(),
                    });
                };
                let (parsed, rest) = parse_sequence_option_spec(inner)?;
                if !rest.trim().is_empty() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "identity sequence options",
                        actual: rest.trim().into(),
                    });
                }
                if parsed.owned_by.is_some() {
                    return Err(ParseError::UnexpectedToken {
                        expected: "identity sequence options without OWNED BY",
                        actual: raw.into(),
                    });
                }
                options = parsed;
            }
            _ => {}
        }
    }
    let kind = match when.as_deref().ok_or(ParseError::UnexpectedEof)? {
        "always" => Ok(ColumnIdentityKind::Always),
        "by default" => Ok(ColumnIdentityKind::ByDefault),
        other => Err(ParseError::UnexpectedToken {
            expected: "GENERATED ALWAYS or GENERATED BY DEFAULT",
            actual: other.into(),
        }),
    }?;
    Ok(ColumnIdentityDef { kind, options })
}

fn build_column_compression(
    pair: Pair<'_, Rule>,
) -> Result<crate::include::access::htup::AttributeCompression, ParseError> {
    let raw = pair.as_str().trim().to_ascii_lowercase();
    if raw.ends_with("default") {
        return Ok(crate::include::access::htup::AttributeCompression::Default);
    }
    if raw.ends_with("pglz") {
        return Ok(crate::include::access::htup::AttributeCompression::Pglz);
    }
    if raw.ends_with("lz4") {
        return Ok(crate::include::access::htup::AttributeCompression::Lz4);
    }
    Err(ParseError::UnexpectedToken {
        expected: "compression method",
        actual: pair.as_str().into(),
    })
}

fn build_column_storage(
    pair: Pair<'_, Rule>,
) -> Result<crate::include::access::tupdesc::AttributeStorage, ParseError> {
    let raw = pair.as_str().trim().to_ascii_lowercase();
    if raw.ends_with("plain") {
        return Ok(crate::include::access::tupdesc::AttributeStorage::Plain);
    }
    if raw.ends_with("external") {
        return Ok(crate::include::access::tupdesc::AttributeStorage::External);
    }
    if raw.ends_with("extended") {
        return Ok(crate::include::access::tupdesc::AttributeStorage::Extended);
    }
    if raw.ends_with("main") {
        return Ok(crate::include::access::tupdesc::AttributeStorage::Main);
    }
    Err(ParseError::UnexpectedToken {
        expected: "storage method",
        actual: pair.as_str().into(),
    })
}

fn build_column_generated(pair: Pair<'_, Rule>) -> Result<ColumnGeneratedDef, ParseError> {
    let mut when = None;
    let mut expr_sql = None;
    let mut kind = ColumnGeneratedKind::Virtual;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::generated_when => when = Some(part.as_str().trim().to_ascii_lowercase()),
            Rule::expr => expr_sql = Some(part.as_str().trim().to_string()),
            Rule::generated_storage => {
                kind = match part.as_str().trim().to_ascii_lowercase().as_str() {
                    "stored" => ColumnGeneratedKind::Stored,
                    "virtual" => ColumnGeneratedKind::Virtual,
                    other => {
                        return Err(ParseError::UnexpectedToken {
                            expected: "VIRTUAL or STORED",
                            actual: other.into(),
                        });
                    }
                };
            }
            _ => {}
        }
    }
    if when.as_deref() != Some("always") {
        return Err(ParseError::UnexpectedToken {
            expected: "GENERATED ALWAYS",
            actual: "for a generated column, GENERATED ALWAYS must be specified".into(),
        });
    }
    Ok(ColumnGeneratedDef {
        expr_sql: expr_sql.ok_or(ParseError::UnexpectedEof)?,
        kind,
    })
}

fn canonicalize_column_type_name(ty: RawTypeName) -> Result<RawTypeName, ParseError> {
    match ty {
        RawTypeName::Named {
            name,
            array_bounds: 0,
        } => match name.to_ascii_lowercase().as_str() {
            "smallserial" | "serial2" => Ok(RawTypeName::Serial(SerialKind::Small)),
            "serial" | "serial4" => Ok(RawTypeName::Serial(SerialKind::Regular)),
            "bigserial" | "serial8" => Ok(RawTypeName::Serial(SerialKind::Big)),
            _ => Ok(RawTypeName::Named {
                name,
                array_bounds: 0,
            }),
        },
        RawTypeName::Named { name, array_bounds } => {
            if matches!(
                name.to_ascii_lowercase().as_str(),
                "smallserial" | "serial2" | "serial" | "serial4" | "bigserial" | "serial8"
            ) {
                return Err(ParseError::FeatureNotSupported(
                    "array of serial is not implemented".into(),
                ));
            }
            Ok(RawTypeName::Named { name, array_bounds })
        }
        other => Ok(other),
    }
}

fn build_alter_table_add_column(
    pair: Pair<'_, Rule>,
) -> Result<AlterTableAddColumnStatement, ParseError> {
    let mut if_exists = false;
    let mut missing_ok = false;
    let mut only = false;
    let mut table_name = None;
    let mut column = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::alter_table_target => {
                let (parsed_if_exists, parsed_only, parsed_table_name) =
                    build_alter_table_target(part)?;
                if_exists = parsed_if_exists;
                only = parsed_only;
                table_name = Some(parsed_table_name);
            }
            Rule::if_not_exists_clause => missing_ok = true,
            Rule::identifier if table_name.is_none() => table_name = Some(build_identifier(part)),
            Rule::column_def => column = Some(build_column_def(part)?),
            _ => {}
        }
    }
    Ok(AlterTableAddColumnStatement {
        if_exists,
        missing_ok,
        only,
        table_name: table_name.ok_or(ParseError::UnexpectedEof)?,
        column: column.ok_or(ParseError::UnexpectedEof)?,
        fdw_options: None,
    })
}

fn build_alter_table_add_constraint(
    pair: Pair<'_, Rule>,
) -> Result<AlterTableAddConstraintStatement, ParseError> {
    let mut if_exists = false;
    let mut only = false;
    let mut table_name = None;
    let mut constraint = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::alter_table_target => {
                let (parsed_if_exists, parsed_only, parsed_table_name) =
                    build_alter_table_target(part)?;
                if_exists = parsed_if_exists;
                only = parsed_only;
                table_name = Some(parsed_table_name);
            }
            Rule::identifier if table_name.is_none() => table_name = Some(build_identifier(part)),
            Rule::table_constraint => constraint = Some(build_table_constraint(part)?),
            Rule::alter_table_add_using_index_constraint => {
                constraint = Some(build_alter_table_add_using_index_constraint(part)?)
            }
            _ => {}
        }
    }
    Ok(AlterTableAddConstraintStatement {
        if_exists,
        only,
        table_name: table_name.ok_or(ParseError::UnexpectedEof)?,
        constraint: constraint.ok_or(ParseError::UnexpectedEof)?,
    })
}

fn build_alter_table_add_using_index_constraint(
    pair: Pair<'_, Rule>,
) -> Result<TableConstraint, ParseError> {
    let mut attributes = build_constraint_attributes(pair.clone())?;
    let mut identifiers = pair
        .clone()
        .into_inner()
        .filter(|part| part.as_rule() == Rule::identifier)
        .map(build_identifier)
        .collect::<Vec<_>>();
    let raw = pair.as_str().trim_start().to_ascii_lowercase();
    if raw.starts_with("constraint ") {
        attributes.name = identifiers.first().cloned();
        if !identifiers.is_empty() {
            identifiers.remove(0);
        }
    }
    let index_name = identifiers.pop().ok_or(ParseError::UnexpectedEof)?;
    if raw.contains("primary key") {
        Ok(TableConstraint::PrimaryKeyUsingIndex {
            attributes,
            index_name,
        })
    } else {
        Ok(TableConstraint::UniqueUsingIndex {
            attributes,
            index_name,
        })
    }
}

