fn build_alter_table_alter_constraint(
    pair: Pair<'_, Rule>,
) -> Result<AlterTableAlterConstraintStatement, ParseError> {
    let mut if_exists = false;
    let mut only = false;
    let mut table_name = None;
    let mut constraint_name = None;
    let mut not_valid = false;
    let mut inheritability = None;
    let mut deferrable = None;
    let mut initially_deferred = None;
    let mut enforced = None;
    for part in pair.into_inner() {
        match part.as_rule() {
            Rule::alter_table_target => {
                let (parsed_if_exists, parsed_only, parsed_table_name) =
                    build_alter_table_target(part)?;
                if_exists = parsed_if_exists;
                only = parsed_only;
                table_name = Some(parsed_table_name);
            }
            Rule::identifier if table_name.is_none() => table_name = Some(build_identifier(part)),
            Rule::identifier if constraint_name.is_none() => {
                constraint_name = Some(build_identifier(part))
            }
            Rule::alter_table_constraint_action => {
                for inner in part.into_inner() {
                    match inner.as_rule() {
                        Rule::not_valid_constraint_attribute => not_valid = true,
                        Rule::inherit_constraint_attribute => {
                            if inheritability.replace(true).is_some() {
                                return Err(ParseError::UnexpectedToken {
                                    expected: "one INHERIT/NO INHERIT constraint attribute",
                                    actual: "conflicting INHERIT declarations".into(),
                                });
                            }
                        }
                        Rule::no_inherit_constraint_attribute => {
                            if inheritability.replace(false).is_some() {
                                return Err(ParseError::UnexpectedToken {
                                    expected: "one INHERIT/NO INHERIT constraint attribute",
                                    actual: "conflicting INHERIT declarations".into(),
                                });
                            }
                        }
                        Rule::deferrable_constraint_attribute => {
                            set_deferrable_attribute(&mut deferrable, initially_deferred, true)?
                        }
                        Rule::not_deferrable_constraint_attribute => {
                            set_deferrable_attribute(&mut deferrable, initially_deferred, false)?
                        }
                        Rule::initially_deferred_constraint_attribute => {
                            set_initially_deferred_attribute(
                                &mut initially_deferred,
                                &mut deferrable,
                                true,
                            )?
                        }
                        Rule::initially_immediate_constraint_attribute => {
                            set_initially_deferred_attribute(
                                &mut initially_deferred,
                                &mut deferrable,
                                false,
                            )?
                        }
                        Rule::enforced_constraint_attribute => {
                            set_alter_constraint_enforced_attribute(&mut enforced, true)?
                        }
                        Rule::not_enforced_constraint_attribute => {
                            set_alter_constraint_enforced_attribute(&mut enforced, false)?
                        }
                        _ => {}
                    }
                }
            }
            _ => {}
        }
    }
    Ok(AlterTableAlterConstraintStatement {
        if_exists,
        only,
        table_name: table_name.ok_or(ParseError::UnexpectedEof)?,
        constraint_name: constraint_name.ok_or(ParseError::UnexpectedEof)?,
        not_valid,
        inheritability,
        deferrable,
        initially_deferred,
        enforced,
    })
}

